var ROUTER_MODEL = "cc/claude-sonnet-4-6";
var ROUTER_AUTO_MODEL = "cc/claude-haiku-4-5";
var ROUTER_PROBE_TIMEOUT_MS = 8000;
var ROUTER_AI_TIMEOUT_MS = 120000;
var ROUTER_SPEC_TIMEOUT_MS = 300000;
var _routerCallSeq = 0;
var _routerCallWaiters = {};

function normalizeRouterEndpoint(url) {
  var u = (url || DEFAULT_ROUTER_ENDPOINT).trim().replace(/\/+$/, "");
  return u || DEFAULT_ROUTER_ENDPOINT;
}

function callRouterViaUiBridge(routerEndpoint, system, user, model, maxTokens, timeoutMs) {
  return new Promise(function(resolve, reject) {
    var limit = timeoutMs || ROUTER_AI_TIMEOUT_MS;
    var id = ++_routerCallSeq;
    _routerCallWaiters[id] = { resolve: resolve, reject: reject };
    figma.ui.postMessage({
      type: "router-ai-request",
      id: id,
      endpoint: normalizeRouterEndpoint(routerEndpoint),
      model: model || ROUTER_MODEL,
      maxTokens: maxTokens || 1500,
      system: system || "",
      user: user || "",
      timeoutMs: limit,
    });
    setTimeout(function() {
      if (!_routerCallWaiters[id]) return;
      delete _routerCallWaiters[id];
      reject(new Error(
        "Timeout goi Claude Code (" + (limit / 1000) + "s). Kiem tra: npm run proxy (port 20128)."
      ));
    }, limit);
  });
}

function parseRouterCompletionRaw(raw) {
  var trimmed = String(raw || "").trim();
  if (!trimmed) throw new Error("AI tra ve rong.");
  if (trimmed.charAt(0) === "{") return JSON.parse(trimmed);
  var content = "";
  var lines = trimmed.split("\n");
  for (var i = 0; i < lines.length; i++) {
    var line = lines[i].trim();
    if (line.indexOf("data:") !== 0) continue;
    var payload = line.slice(5).trim();
    if (!payload || payload === "[DONE]") continue;
    try {
      var chunk = JSON.parse(payload);
      var delta = chunk.choices && chunk.choices[0] && chunk.choices[0].delta;
      var msg = chunk.choices && chunk.choices[0] && chunk.choices[0].message;
      if (delta && delta.content) content += delta.content;
      if (msg && msg.content) content = msg.content;
    } catch (e) {}
  }
  if (content) return { choices: [{ message: { content: content } }] };
  throw new Error("AI tra ve rong (khong parse duoc SSE/JSON).");
}

async function probeProxyHealth(routerEndpoint) {
  var base = normalizeRouterEndpoint(routerEndpoint).replace(/\/v1\/?$/, "");
  var healthUrl = base + "/health";
  var res = await Promise.race([
    fetch(healthUrl),
    new Promise(function(_, reject) {
      setTimeout(function() {
        reject(new Error(
          "Khong ket noi duoc proxy tai " + base + ". Chay: npm run proxy (port 20128)."
        ));
      }, ROUTER_PROBE_TIMEOUT_MS);
    }),
  ]);
  if (!res.ok) {
    throw new Error("Proxy khong san sang (HTTP " + res.status + "). Chay: npm run proxy.");
  }
}

async function callRouterApiDirect(routerEndpoint, system, user, model, maxTokens, timeoutMs) {
  await probeProxyHealth(routerEndpoint);

  var limit = timeoutMs || ROUTER_AI_TIMEOUT_MS;
  var endpoint = normalizeRouterEndpoint(routerEndpoint);
  var url = endpoint + "/chat/completions";
  var messages = [];
  if (system) messages.push({ role: "system", content: system });
  messages.push({ role: "user", content: user || "" });

  var fetchPromise = fetch(url, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "Authorization": "Bearer local",
    },
    body: JSON.stringify({
      model: model || ROUTER_MODEL,
      max_tokens: maxTokens || 1500,
      stream: false,
      messages: messages,
    }),
  });

  var res = await Promise.race([
    fetchPromise,
    new Promise(function(_, reject) {
      setTimeout(function() {
        reject(new Error(
          "Timeout goi Claude Code (" + (limit / 1000) + "s). Kiem tra proxy dang chay."
        ));
      }, limit);
    }),
  ]);

  var raw = await res.text();
  if (!res.ok) {
    var errText = raw;
    try {
      var errJson = JSON.parse(raw);
      errText = (errJson.error && (errJson.error.message || errJson.error)) || raw;
    } catch (e) {}
    throw new Error(typeof errText === "string" ? errText : JSON.stringify(errText));
  }

  var data = parseRouterCompletionRaw(raw);
  var text = "";
  if (data.choices && data.choices.length && data.choices[0].message) {
    text = data.choices[0].message.content || "";
  }
  if (!String(text).trim()) throw new Error("AI tra ve rong (khong co content).");
  return text.replace(/```json|```/g, "").trim();
}

// Goi proxy truc tiep tu plugin (Figma networkAccess); fallback qua UI neu can
async function callRouterApiWithModel(routerEndpoint, system, user, model, maxTokens, timeoutMs) {
  try {
    return await callRouterApiDirect(routerEndpoint, system, user, model, maxTokens, timeoutMs);
  } catch (directErr) {
    try {
      var text = await callRouterViaUiBridge(routerEndpoint, system, user, model, maxTokens, timeoutMs);
      if (!text.trim()) throw new Error("AI tra ve rong (khong co content).");
      return text.replace(/```json|```/g, "").trim();
    } catch (bridgeErr) {
      throw formatRouterError(directErr, timeoutMs);
    }
  }
}

async function callRouterApi(routerEndpoint, system, user, maxTokens, timeoutMs) {
  return callRouterApiWithModel(routerEndpoint, system, user, ROUTER_MODEL, maxTokens, timeoutMs);
}

function formatRouterError(err, timeoutMs) {
  var limit = timeoutMs || ROUTER_AI_TIMEOUT_MS;
  var msg = (err && err.message) ? String(err.message) : String(err || "Loi Claude Code proxy");
  var lower = msg.toLowerCase();
  if (
    lower.indexOf("failed to fetch") >= 0 ||
    lower.indexOf("networkerror") >= 0 ||
    lower.indexOf("econnrefused") >= 0 ||
    lower.indexOf("connection refused") >= 0 ||
    lower.indexOf("fetch failed") >= 0
  ) {
    return new Error(
      "Khong ket noi duoc proxy tai " + normalizeRouterEndpoint(DEFAULT_ROUTER_ENDPOINT) +
      ". Chay: npm run proxy (port 20128)."
    );
  }
  if (lower.indexOf("timeout") >= 0 || lower.indexOf("abort") >= 0) {
    return new Error(
      "Timeout goi Claude Code (" + (limit / 1000) + "s). Kiem tra proxy dang chay."
    );
  }
  return err instanceof Error ? err : new Error(msg);
}

function extractBalancedJsonSlice(text, openChar, closeChar) {
  var start = text.indexOf(openChar);
  if (start < 0) return null;
  var depth = 0;
  var inString = false;
  var escape = false;
  for (var i = start; i < text.length; i++) {
    var ch = text[i];
    if (escape) {
      escape = false;
      continue;
    }
    if (ch === "\\" && inString) {
      escape = true;
      continue;
    }
    if (ch === '"') {
      inString = !inString;
      continue;
    }
    if (inString) continue;
    if (ch === openChar) depth++;
    else if (ch === closeChar) {
      depth--;
      if (depth === 0) return text.slice(start, i + 1);
    }
  }
  return null;
}

function repairTruncatedJsonBrackets(text) {
  var inString = false;
  var escape = false;
  var stack = [];
  for (var i = 0; i < text.length; i++) {
    var ch = text[i];
    if (escape) {
      escape = false;
      continue;
    }
    if (ch === "\\" && inString) {
      escape = true;
      continue;
    }
    if (ch === '"') {
      inString = !inString;
      continue;
    }
    if (inString) continue;
    if (ch === "{" || ch === "[") stack.push(ch);
    else if (ch === "}" && stack.length && stack[stack.length - 1] === "{") stack.pop();
    else if (ch === "]" && stack.length && stack[stack.length - 1] === "[") stack.pop();
  }
  var suffix = "";
  for (var j = stack.length - 1; j >= 0; j--) {
    suffix += stack[j] === "{" ? "}" : "]";
  }
  return text + suffix;
}

function salvageItemsFromTruncatedJson(text) {
  var itemsKey = text.indexOf('"items"');
  if (itemsKey < 0) return null;
  var arrStart = text.indexOf("[", itemsKey);
  if (arrStart < 0) return null;

  var items = [];
  var i = arrStart + 1;
  while (i < text.length) {
    while (i < text.length && /\s/.test(text[i])) i++;
    if (i >= text.length || text[i] === "]") break;
    if (text[i] !== "{") break;

    var objStart = i;
    var depth = 0;
    var inStr = false;
    var esc = false;
    var closed = false;
    for (; i < text.length; i++) {
      var c = text[i];
      if (esc) {
        esc = false;
        continue;
      }
      if (c === "\\" && inStr) {
        esc = true;
        continue;
      }
      if (c === '"') {
        inStr = !inStr;
        continue;
      }
      if (inStr) continue;
      if (c === "{") depth++;
      else if (c === "}") {
        depth--;
        if (depth === 0) {
          try {
            items.push(JSON.parse(text.slice(objStart, i + 1)));
          } catch (parseErr) {}
          closed = true;
          i++;
          break;
        }
      }
    }
    if (!closed) break;
    while (i < text.length && (/\s/.test(text[i]) || text[i] === ",")) i++;
  }
  return items.length ? { items: items, ignored: [] } : null;
}

function parseClaudeJson(text) {
  var cleaned = String(text || "").replace(/```json|```/gi, "").trim();
  if (!cleaned) throw new Error("AI tra ve rong (khong co JSON).");

  var attempts = [
    function() { return JSON.parse(cleaned); },
    function() {
      var slice = extractBalancedJsonSlice(cleaned, "{", "}");
      if (!slice) throw new Error("no balanced object");
      return JSON.parse(slice);
    },
    function() {
      var start = cleaned.indexOf("{");
      if (start < 0) throw new Error("no object start");
      return JSON.parse(repairTruncatedJsonBrackets(cleaned.slice(start)));
    },
    function() {
      var start = cleaned.indexOf("{");
      var end = cleaned.lastIndexOf("}");
      if (start < 0 || end <= start) throw new Error("no object bounds");
      return JSON.parse(cleaned.slice(start, end + 1));
    },
  ];

  var lastErr = null;
  for (var a = 0; a < attempts.length; a++) {
    try {
      return attempts[a]();
    } catch (e) {
      lastErr = e;
    }
  }

  var salvaged = salvageItemsFromTruncatedJson(cleaned);
  if (salvaged) return salvaged;

  var detail = lastErr && lastErr.message ? lastErr.message : "unknown";
  throw new Error(
    "Khong parse duoc JSON tu AI (" + detail + "). " +
    "Phan hoi co the bi cat — thu lai hoac tang max_tokens tren proxy."
  );
}

function postProgress(step, detail) {
  figma.ui.postMessage({ type: "progress", step: step, detail: detail || "" });
}

async function callClaudeApi(routerEndpoint, system, user) {
  return callRouterApi(routerEndpoint, system, user, 1500);
}

function getParentPath(node, frame) {
  var parts = [];
  var p = node.parent;
  while (p && p.id !== frame.id) {
    parts.unshift(p.name || p.type);
    p = p.parent;
  }
  return parts.length ? parts.join(" > ") : "(root)";
}

function annotateDuplicateText(rawEls) {
  var groups = {};
  for (var i = 0; i < rawEls.length; i++) {
    var key = (rawEls[i].text || "").trim();
    if (!key) continue;
    if (!groups[key]) groups[key] = [];
    groups[key].push(i);
  }
  for (var key in groups) {
    var idxs = groups[key];
    if (idxs.length < 2) continue;
    idxs.sort(function(a, b) { return rawEls[a].x - rawEls[b].x; });
    for (var d = 0; d < idxs.length; d++) {
      rawEls[idxs[d]].dupHint = "trung text " + (d + 1) + "/" + idxs.length +
        " @x=" + Math.round(rawEls[idxs[d]].x);
    }
  }
}

function normalizeItemNumber(val) {
  if (val == null || val === "") return "";
  if (typeof val === "number" && !isNaN(val)) return String(val);
  var s = String(val).replace(/,/g, ".").trim().replace(/\.+$/, "");
  // Giu nguyen cap bac: 11.1.1 — KHONG dung parseFloat (11.1.1 -> 11.1)
  if (/^\d+(?:\.\d+)+$/.test(s)) return s;
  if (/^\d+$/.test(s)) return s;
  var oneDot = parseFloat(s);
  if (!isNaN(oneDot) && s.indexOf(".") === s.lastIndexOf(".")) return String(oneDot);
  return s;
}

function normalizeForMatch(s) {
  if (!s) return "";
  // Remove whitespace (half/full width) and unify punctuation that often differs in Figma text
  return String(s)
    .replace(/[\s\u3000]+/g, "")
    .replace(/[：:]/g, ":")
    .replace(/[（）()]/g, function(ch) { return ch === "（" ? "(" : ch === "）" ? ")" : ch; })
    .trim();
}

function numberSortKey(numStr) {
  if (!numStr) return 999999999;
  var parts = String(numStr).split(".");
  var key = 0;
  for (var i = 0; i < parts.length; i++) {
    key = key * 1000 + (parseInt(parts[i], 10) || 0);
  }
  return key;
}

function formatMarkerNumber(num) {
  if (num == null || num === "") return "?";
  return String(num);
}

function parseNumberedLinesFromPrompt(userPrompt) {
  var items = [];
  if (!userPrompt) return items;
  var lines = userPrompt.split(/\r?\n/);
  for (var i = 0; i < lines.length; i++) {
    var line = lines[i];
    // Support:
    // - 8.4: 住民税
    // - 8.4　住民税 (spaces / tabs / fullwidth spaces)
    // - 8: 税負担比較グラフ
    var m = line.match(/^\s*(\d+(?:\.\d+)*\.?)\s*(?:[:：]|\s+)\s*(.+)$/);
    if (m) {
      var num = normalizeItemNumber(m[1]);
      if (num) items.push({ number: num, hint: (m[2] || "").trim() });
    }
  }
  return items;
}

function applyPromptNumbersToMapped(userPrompt, mapped) {
  var lines = parseNumberedLinesFromPrompt(userPrompt);
  if (!lines.length) return mapped;
  var byNumber = {};
  for (var i = 0; i < lines.length; i++) byNumber[lines[i].number] = lines[i];

  for (var j = 0; j < mapped.length; j++) {
    var el = mapped[j];
    var normalized = normalizeItemNumber(el.number);
    if (normalized && byNumber[normalized]) continue;
    if (lines[j]) el.number = lines[j].number;
  }
  return mapped;
}

function buildTextMatchIndex(rawEls) {
  var byText = {};
  for (var i = 0; i < rawEls.length; i++) {
    var el = rawEls[i];
    var keys = [
      normalizeForMatch(el.text || ""),
      normalizeForMatch(el.label || ""),
      normalizeForMatch(el.name || ""),
    ];
    for (var k = 0; k < keys.length; k++) {
      var key = keys[k];
      if (!key) continue;
      if (!byText[key]) byText[key] = [];
      byText[key].push(el);
    }
  }
  return byText;
}

function findRawElementByLabel(label, rawEls, frameWidth, options) {
  options = options || {};
  var used = options.used || {};
  var want = normalizeForMatch(label || "");
  if (!want || !rawEls || !rawEls.length) return null;

  var byText = options.byText || buildTextMatchIndex(rawEls);
  var labelMaxX = (frameWidth || 1200) * 0.42;
  var lastPickY = typeof options.lastPickY === "number" ? options.lastPickY : -9999;

  function pickBest(cands) {
    if (!cands || !cands.length) return null;
    var pool = [];
    for (var m = 0; m < cands.length; m++) {
      if (!used[cands[m].id]) pool.push(cands[m]);
    }
    if (!pool.length) pool = cands.slice();

    var labels = [];
    for (var li = 0; li < pool.length; li++) {
      if (typeof pool[li].x === "number" && pool[li].x <= labelMaxX) labels.push(pool[li]);
    }
    if (labels.length) pool = labels;

    pool.sort(function(a, b) {
      var yd = a.y - b.y;
      if (Math.abs(yd) > 2) return yd;
      return a.x - b.x;
    });

    for (var j = 0; j < pool.length; j++) {
      if (pool[j].y >= lastPickY - 4) return pool[j];
    }
    return pool[0];
  }

  var cands = byText[want] || [];
  if (!cands.length && want.length >= 4) {
    for (var key in byText) {
      if (!byText.hasOwnProperty(key)) continue;
      if (key === want || key.indexOf(want) !== -1 || want.indexOf(key) !== -1) {
        cands = cands.concat(byText[key]);
      }
    }
  }

  return pickBest(cands);
}

function isManualDrawElement(el) {
  return !el.id || String(el.id).indexOf("manual-") === 0 || el.source === "MANUAL";
}

function localResolveElementsFromPrompt(userPrompt, rawEls, frameWidth) {
  var lines = parseNumberedLinesFromPrompt(userPrompt);
  if (!lines.length) return null;

  var labelMaxX = (frameWidth || 1200) * 0.42;

  // Build candidate index by normalized text/label
  var byText = {};
  for (var i = 0; i < rawEls.length; i++) {
    var el = rawEls[i];
    var t = normalizeForMatch(el.text || "");
    var l = normalizeForMatch(el.label || "");
    if (t) {
      if (!byText[t]) byText[t] = [];
      byText[t].push(el);
    }
    if (l && l !== t) {
      if (!byText[l]) byText[l] = [];
      byText[l].push(el);
    }
  }

  var lastPickY = -9999;
  var used = {};

  function pickBest(cands) {
    if (!cands || !cands.length) return null;
    var pool = [];
    for (var m = 0; m < cands.length; m++) {
      if (!used[cands[m].id]) pool.push(cands[m]);
    }
    if (!pool.length) pool = cands.slice();

    // Uu tien cot label trai (row header table)
    var labels = [];
    for (var li = 0; li < pool.length; li++) {
      if (typeof pool[li].x === "number" && pool[li].x <= labelMaxX) labels.push(pool[li]);
    }
    if (labels.length) pool = labels;

    pool.sort(function(a, b) {
      var yd = a.y - b.y;
      if (Math.abs(yd) > 2) return yd;
      return a.x - b.x;
    });

    // Chon dong ke tiep theo thu tu doc (tranh match nham len dong tren)
    for (var j = 0; j < pool.length; j++) {
      if (pool[j].y >= lastPickY - 4) {
        lastPickY = pool[j].y;
        return pool[j];
      }
    }
    lastPickY = pool[0].y;
    return pool[0];
  }

  var mapped = [];
  var miss = 0;

  for (var j = 0; j < lines.length; j++) {
    var line = lines[j];
    var want = normalizeForMatch(line.hint);
    var cands = byText[want] || [];

    // fallback: contains match for long strings
    if (!cands.length && want.length >= 8) {
      for (var key in byText) {
        if (!byText.hasOwnProperty(key)) continue;
        if (key.indexOf(want) !== -1 || want.indexOf(key) !== -1) {
          cands = cands.concat(byText[key]);
        }
      }
    }

    var filtered = [];
    for (var m2 = 0; m2 < cands.length; m2++) {
      if (!used[cands[m2].id]) filtered.push(cands[m2]);
    }
    var picked = pickBest(filtered.length ? filtered : cands);
    if (!picked) {
      miss++;
      continue;
    }
    used[picked.id] = true;
    mapped.push({
      id: picked.id,
      name: picked.name,
      type: picked.type,
      text: picked.text || "",
      label: picked.label || "",
      role: picked.role || "",
      parentPath: picked.parentPath || "",
      number: line.number,
      x: picked.x,
      y: picked.y,
      width: picked.width,
      height: picked.height,
      centerX: picked.centerX,
      centerY: picked.centerY,
    });
  }

  // Chap nhan partial match (table lon) — khong bat buoc 50%
  if (mapped.length >= 1) {
    mapped.sort(function(a, b) { return numberSortKey(a.number) - numberSortKey(b.number); });
    return { elements: mapped, miss: miss, total: lines.length, method: "Local text match" };
  }
  return null;
}

function formatElForAI(el, i) {
  var line = (i + 1) + ". nodeId=" + el.id + " [" + el.type + '] name="' + el.name + '"';
  if (el.text) line += ' text="' + el.text + '"';
  if (el.label) line += ' label="' + el.label + '"';
  if (el.role === "icon") line += " role=icon";
  if (el.toolbarIndex) line += " toolbarPos=" + el.toolbarIndex;
  if (el.dupHint) line += " " + el.dupHint;
  if (el.parentPath) line += " path=" + el.parentPath;
  line += " box=" + Math.round(el.width) + "x" + Math.round(el.height);
  line += " @(" + Math.round(el.x) + "," + Math.round(el.y) + ")";
  line += " center=(" + Math.round(el.centerX) + "," + Math.round(el.centerY) + ")";
  return line;
}

function findRawElement(rawEls, aiEl) {
  if (aiEl.nodeId) {
    for (var i = 0; i < rawEls.length; i++) {
      if (rawEls[i].id === aiEl.nodeId) return rawEls[i];
    }
  }
  return null;
}

function mapAiElements(rawEls, aiEls) {
  var mapped = [];
  for (var i = 0; i < aiEls.length; i++) {
    var aiEl = aiEls[i];
    var orig = findRawElement(rawEls, aiEl);
    if (!orig) continue;
    mapped.push({
      id: orig.id,
      name: aiEl.label || aiEl.name || orig.name,
      type: aiEl.type || orig.type,
      text: orig.text || "",
      label: orig.label || "",
      role: orig.role || "",
      parentPath: orig.parentPath || "",
      number: normalizeItemNumber(aiEl.number),
      x: orig.x,
      y: orig.y,
      width: orig.width,
      height: orig.height,
      centerX: orig.centerX,
      centerY: orig.centerY,
    });
  }
  mapped.sort(function(a, b) {
    return numberSortKey(a.number) - numberSortKey(b.number);
  });
  for (var i = 0; i < mapped.length; i++) {
    if (!mapped[i].number) mapped[i].number = String(i + 1);
  }
  return mapped;
}

function annotateActionToolbarIcons(rawEls) {
  var groups = {};
  for (var i = 0; i < rawEls.length; i++) {
    var el = rawEls[i];
    if (el.role !== "icon") continue;
    var path = (el.parentPath || "").toLowerCase();
    var key;
    if (ACTION_PATH_RE.test(path) && /table|grid/i.test(path)) {
      key = "table_action_col_" + Math.round(el.x / 24);
    } else {
      key = el.parentPath || el.name;
    }
    if (!groups[key]) groups[key] = [];
    groups[key].push(el);
  }
  for (var key in groups) {
    var g = groups[key];
    if (g.length < 2) continue;
    g.sort(function(a, b) { return a.y - b.y; });
    for (var j = 0; j < g.length; j++) {
      g[j].toolbarIndex = (j + 1) + "/" + g.length;
    }
  }
}

function sortElementsReadingOrder(elements) {
  return elements.slice().sort(function(a, b) {
    var rowDiff = a.y - b.y;
    if (Math.abs(rowDiff) > READING_ORDER_ROW_PX) return rowDiff;
    return a.x - b.x;
  });
}

function isIconLikeName(name) {
  return ICON_NAME_RE.test(name || "");
}

function isButtonLabelText(text) {
  var t = String(text || "").trim();
  if (!t) return false;
  if (BUTTON_LABEL_RE.test(t)) return true;
  if (BD_LINK_TEXT_RE.test(t)) return true;
  if (/^(適用|決済を確定|＋\s*参加者)/.test(t)) return true;
  return false;
}

function isActionIconCandidate(c) {
  if (!c) return false;
  var path = (c.path || c.parentPath || "").toLowerCase();
  var name = (c.name || "").toLowerCase();
  var label = (c.label || "").toLowerCase();
  var isIcon = c.role === "icon" || c.roleHint === "icon";
  if (!isIcon) {
    if (/^(instance|component)$/i.test(c.type || "") &&
        c.width <= 52 && c.height <= 52 && ACTION_PATH_RE.test(path)) {
      return true;
    }
    return false;
  }
  if (ACTION_PATH_RE.test(path)) return true;
  if (isIconLikeName(name) || isIconLikeName(label)) return true;
  if (/^\+$/.test(label) || /^\+$/.test(name)) return true;
  return false;
}

function supplementButtonContainers(frame, elements) {
  var ids = {};
  for (var i = 0; i < elements.length; i++) ids[elements[i].id] = true;
  var added = [];
  for (var j = 0; j < elements.length; j++) {
    var el = elements[j];
    if (el.type !== "TEXT" || !isButtonLabelText(el.text)) continue;
    var node = tryGetNodeByIdSync(el.id);
    if (!node) continue;
    var parent = node.parent;
    var depth = 0;
    while (parent && parent.id !== frame.id && depth < 6) {
      var pName = (parent.name || "").toLowerCase();
      var isBtn = parent.type === "INSTANCE" || parent.type === "COMPONENT" ||
        (parent.type === "FRAME" && /button|btn|primary|secondary/.test(pName));
      if (isBtn && parent.width >= 36 && parent.height >= 18 && !ids[parent.id]) {
        var pos = positionInFrame(parent, frame);
        if (pos && pos.width > 0 && pos.height > 0) {
          added.push({
            id: parent.id,
            name: parent.name,
            type: parent.type,
            parentPath: getParentPath(parent, frame),
            x: pos.x, y: pos.y, width: pos.width, height: pos.height,
            centerX: pos.x + pos.width / 2,
            centerY: pos.y + pos.height / 2,
            text: el.text,
            label: el.text,
            role: "button",
          });
          ids[parent.id] = true;
        }
        break;
      }
      parent = parent.parent;
      depth++;
    }
  }
  return added.length ? elements.concat(added) : elements;
}

function markActionElements(candidates) {
  for (var i = 0; i < candidates.length; i++) {
    var c = candidates[i];
    if (isActionIconCandidate(c)) {
      c.roleHint = "icon";
      c.role = c.role || "icon";
      if (c.tableRoleHint === "cell_value") c.tableRoleHint = "action";
      c.isLikelyTableCellValue = false;
      c.shouldNumberHint = true;
      c.ignoreReason = c.ignoreReason === "table_cell_value" ? "" : c.ignoreReason;
      c.score = Math.max(c.score, 88);
      c.isAction = true;
    }
    if (c.roleHint === "button" || isButtonLabelText(c.text)) {
      if (isButtonLabelText(c.text)) c.roleHint = "button";
      c.shouldNumberHint = true;
      c.score = Math.max(c.score, 85);
      c.isAction = true;
    }
    if (BD_LINK_TEXT_RE.test(c.text || "")) {
      c.roleHint = "button";
      c.isAction = true;
      c.isBdPriority = true;
      c.shouldNumberHint = true;
      c.score = Math.max(c.score, 88);
    }
  }
}

function prioritizeSelectableForAuto(selectable) {
  return sortElementsReadingOrder(selectable);
}

function pathLowerEl(el) {
  return (el.parentPath || "").toLowerCase();
}

function extractTableRegionKey(path) {
  var parts = (path || "").split(" > ");
  for (var i = 0; i < parts.length; i++) {
    if (/table|grid|datagrid|data-table|一覧|list/i.test(parts[i])) {
      return parts.slice(0, i + 1).join(" > ");
    }
  }
  return /table|grid/i.test(path || "") ? path : "";
}

function clusterElementsByY(elements, rowPx) {
  var sorted = elements.slice().sort(function(a, b) { return a.y - b.y; });
  var rows = [];
  for (var i = 0; i < sorted.length; i++) {
    var el = sorted[i];
    var placed = false;
    for (var r = 0; r < rows.length; r++) {
      if (Math.abs(el.y - rows[r][0].y) <= rowPx) {
        rows[r].push(el);
        placed = true;
        break;
      }
    }
    if (!placed) rows.push([el]);
  }
  return rows;
}

function buildTableHeaderCutoffs(elements) {
  var cutoffs = {};
  var byRegion = {};
  for (var i = 0; i < elements.length; i++) {
    var el = elements[i];
    var path = pathLowerEl(el);
    var region = extractTableRegionKey(path);
    if (!region) continue;
    if (!byRegion[region]) byRegion[region] = [];
    byRegion[region].push(el);
  }
  for (var region in byRegion) {
    var group = byRegion[region];
    var headerEls = group.filter(function(el) {
      return TABLE_HEADER_PATH_RE.test(pathLowerEl(el));
    });
    if (headerEls.length >= 1) {
      var maxY = 0;
      for (var h = 0; h < headerEls.length; h++) {
        maxY = Math.max(maxY, headerEls[h].y + headerEls[h].height);
      }
      cutoffs[region] = maxY;
      continue;
    }
    var rows = clusterElementsByY(group, 14);
    for (var r = 0; r < rows.length; r++) {
      var row = rows[r];
      var textCount = 0;
      for (var t = 0; t < row.length; t++) {
        if (row[t].type === "TEXT" && (row[t].text || "").trim()) textCount++;
      }
      if (textCount >= 3) {
        var rowBottom = 0;
        for (var b = 0; b < row.length; b++) {
          rowBottom = Math.max(rowBottom, row[b].y + row[b].height);
        }
        cutoffs[region] = rowBottom;
        break;
      }
    }
  }
  return cutoffs;
}

function isInTableRegion(path) {
  var p = (path || "").toLowerCase();
  // Form card / input layout — khong ap dung logic table (tranh loai nham label form)
  if (/form|card|field|input|textfield|panel|section|ブロック|カード|フォーム/i.test(p)) return false;
  return /data-table|datagrid|table-header|table-body|table-row|table-cell|tbody|thead|一覧表|データ一覧/i.test(p) ||
    (/\btable\b/i.test(p) && !/textfield|input-field/i.test(p));
}

function isTableHeaderElement(el, cutoffs) {
  var path = pathLowerEl(el);
  if (!isInTableRegion(path)) return false;
  if (TABLE_HEADER_PATH_RE.test(path)) return true;
  var region = extractTableRegionKey(path);
  if (!region || cutoffs[region] == null) return false;
  var cy = el.y + el.height / 2;
  return cy <= cutoffs[region] + 6;
}

function isTableBodyValue(el, cutoffs) {
  var path = pathLowerEl(el);
  if (!isInTableRegion(path)) return false;
  if (TABLE_HEADER_PATH_RE.test(path)) return false;
  if (TABLE_BODY_PATH_RE.test(path)) return true;
  var region = extractTableRegionKey(path);
  if (!region || cutoffs[region] == null) return false;
  var cy = el.y + el.height / 2;
  return cy > cutoffs[region] + 8;
}

function isInputFieldValueText(el) {
  if (el.type !== "TEXT") return false;
  var path = pathLowerEl(el);
  if (INPUT_LABEL_PATH_RE.test(path)) return false;
  if ((el.name || "").toLowerCase().indexOf("label") !== -1) return false;
  if (INPUT_VALUE_PATH_RE.test(path)) return true;
  if (/textfield|input|combobox|select|search/i.test(path) &&
      !/label|caption|title/i.test(path)) {
    return true;
  }
  return false;
}

function isDecorativeAutoElement(el) {
  var n = (el.name || "").toLowerCase();
  var path = pathLowerEl(el);
  if (el.type === "LINE") return true;
  if (el.type === "RECTANGLE" && /border|divider|separator|line|stroke/i.test(n)) return true;
  if (/border|divider|separator/.test(path) && el.type !== "TEXT" && el.role !== "icon") return true;
  return false;
}

function isPaginationValueText(el) {
  if (el.type !== "TEXT") return false;
  if (!/pagination/i.test(pathLowerEl(el))) return false;
  return /件中|[\d]+[\-–~][\d]+|^\d+件/.test((el.text || "").trim());
}

function buildRepeatTextKeys(elements, cutoffs) {
  var counts = {};
  for (var i = 0; i < elements.length; i++) {
    var el = elements[i];
    if (el.type !== "TEXT" || !(el.text || "").trim()) continue;
    if (!isInTableRegion(pathLowerEl(el))) continue;
    if (isTableHeaderElement(el, cutoffs)) continue;
    var key = normalizeForMatch(el.text);
    counts[key] = (counts[key] || 0) + 1;
  }
  return counts;
}

function isRepeatedTableCellText(el, repeatCounts, cutoffs) {
  if (el.type !== "TEXT") return false;
  if (isTableHeaderElement(el, cutoffs)) return false;
  var key = normalizeForMatch(el.text || "");
  if (!key || (repeatCounts[key] || 0) < 3) return false;
  return isInTableRegion(pathLowerEl(el));
}

function isAutoNumberable(el) {
  if (el.role === "icon") return true;
  if (el.type === "TEXT") {
    var t = (el.text || "").trim();
    if (!t) return false;
    if (isNumericOnlyText(t)) return false;
  }
  return true;
}

function filterAutoStructuralTargets(raw) {
  var basic = [];
  for (var i = 0; i < raw.length; i++) {
    if (isAutoNumberable(raw[i])) basic.push(raw[i]);
  }
  var cutoffs = buildTableHeaderCutoffs(basic);
  var repeatCounts = buildRepeatTextKeys(basic, cutoffs);
  var filtered = [];
  for (var j = 0; j < basic.length; j++) {
    var el = basic[j];
    if (isDecorativeAutoElement(el)) continue;
    if (isPaginationValueText(el)) continue;
    if (isInputFieldValueText(el)) continue;
    if (isTableBodyValue(el, cutoffs)) continue;
    if (isRepeatedTableCellText(el, repeatCounts, cutoffs)) continue;
    if (el.role === "icon" && isInTableRegion(pathLowerEl(el)) &&
        !isTableHeaderElement(el, cutoffs) &&
        !isActionIconCandidate({
          role: el.role, roleHint: "icon", path: el.parentPath,
          name: el.name, label: el.label, width: el.width, height: el.height, type: el.type,
        })) {
      continue;
    }
    filtered.push(el);
  }
  return { elements: filtered, cutoffs: cutoffs };
}

function isLikelySeparatorText(text) {
  var t = String(text || "").trim();
  if (!t) return false;
  if (/^[\/／>|｜・:：\-–—]+$/.test(t)) return true;
  if (t.length <= 2 && /^[\/／>|｜]$/.test(t)) return true;
  return false;
}

function isLikelyDateText(text) {
  var t = String(text || "").trim();
  if (!t) return false;
  if (/^[0-9０-９]{4}[-/年][0-9０-９]{1,2}[-/月][0-9０-９]{1,2}/.test(t)) return true;
  if (/^[0-9０-９]{4}\/[0-9０-９]{1,2}\/[0-9０-９]{1,2}$/.test(t)) return true;
  return false;
}

function isLikelyMoneyText(text) {
  var t = String(text || "").trim();
  return /^[¥￥]?[0-9０-９,.]+円?$/.test(t);
}

function isLikelyValueText(text) {
  var t = String(text || "").trim();
  if (!t) return false;
  if (isLikelySeparatorText(t)) return true;
  if (isLikelySampleDisplayText(t)) return true;
  if (/^[-ー－―–—]$/.test(t)) return true;
  if (/^[0-9０-９,.]+$/.test(t)) return true;
  if (isLikelyMoneyText(t)) return true;
  if (/^[0-9０-９]+(\.[0-9０-９]+)?%$/.test(t)) return true;
  if (isLikelyDateText(t)) return true;
  if (/^no\.?$/i.test(t) && t.length <= 3) return false;
  return false;
}

function isLikelySampleDisplayText(text) {
  var t = String(text || "").trim();
  if (!t) return false;
  if (/@[a-z0-9.-]+\.[a-z]{2,}/i.test(t)) return true;
  if (/yamada|example\.com|@example|tarou|taro\b|xxxx|xxx-|山田|太郎|花子|次郎|dummy/i.test(t)) return true;
  if (/^[A-E]\d{1,2}$/.test(t)) return true;
  if (/^(認証済|発行済|未発行|未割り当て|代表者|INSTANT|WITHIN|SECURE)/i.test(t)) return true;
  if (/^¥[\d,]+$/.test(t) || /^[\d,]+円$/.test(t)) return true;
  if (/^CODE\d+/i.test(t)) return true;
  if (/^\d{2}\s*\/\s*\d{2}$/.test(t)) return true;
  if (/^[\d]+枚$/.test(t)) return true;
  if (/^Every\s/i.test(t)) return true;
  return false;
}

function isLikelyDescriptionParagraph(c) {
  var t = (c.text || c.label || "").trim();
  if (c.type !== "TEXT" || !t) return false;
  if (t.length > 52) return true;
  var path = (c.path || c.parentPath || "").toLowerCase();
  if (/description|helper|hint|caption|subtitle|note|paragraph|body-text|説明|注釈|リード|lead/i.test(path)) {
    return true;
  }
  return false;
}

function isLikelySectionTitleText(text) {
  var t = String(text || "").trim();
  if (!t) return false;
  if (BD_SECTION_TITLE_RE.test(t) && t.length <= 48) return true;
  if (t.length >= 6 && t.length <= 64 && BD_SIMULATION_TITLE_RE.test(t)) return true;
  if (t.length >= 4 && t.length <= 48 && BD_CARD_SECTION_TITLE_RE.test(t)) return true;
  return false;
}

function parentPathPrefix(path, levels) {
  var parts = (path || "").split(" > ");
  return parts.slice(0, levels || 2).join(" > ");
}

function isLikelySectionCardTitle(c, enriched) {
  var text = (c.text || "").trim();
  if (!text || text.length < 2 || text.length > 30) return false;
  if (c.type !== "TEXT") return false;
  if (isLikelyValueText(text) || isLikelySampleDisplayText(text)) return false;

  var samePath = enriched.filter(function(e) {
    return e !== c && e.parentPath === c.parentPath;
  });
  if (!samePath.length) return false;

  var minY = c.y;
  for (var i = 0; i < samePath.length; i++) {
    if (samePath[i].y < minY) return false;
  }

  return samePath.length >= 3;
}

function isGenericComponentName(name) {
  var n = String(name || "").trim();
  return /^(button|icon|frame|text|instance|component|group|vector|rectangle)$/i.test(n);
}

function markSampleAndDescriptionText(candidates) {
  for (var i = 0; i < candidates.length; i++) {
    var c = candidates[i];
    var text = (c.text || c.label || "").trim();
    if (isLikelySampleDisplayText(text)) {
      c.isLikelyValue = true;
      c.shouldNumberHint = false;
      c.ignoreReason = c.ignoreReason || "sample_display_value";
      c.score = Math.min(c.score, 12);
      continue;
    }
    if (isLikelyDescriptionParagraph(c)) {
      c.shouldNumberHint = false;
      c.ignoreReason = c.ignoreReason || "description_text";
      c.score = Math.min(c.score, 15);
      continue;
    }
    if (isLikelySectionTitleText(text)) {
      c.roleHint = "section_title";
      c.shouldNumberHint = true;
      c.score = Math.max(c.score, 88);
      continue;
    }
    if (c.type !== "TEXT" && isGenericComponentName(c.name) && !c.isAction && !c.isBdPriority) {
      c.shouldNumberHint = false;
      c.ignoreReason = c.ignoreReason || "generic_component";
      c.score = Math.min(c.score, 20);
    }
  }
}

function markBdCoverageBoost(candidates, frameWidth) {
  var fw = frameWidth || 1500;
  var sidebarX = fw * 0.50;

  for (var i = 0; i < candidates.length; i++) {
    var c = candidates[i];
    var text = (c.text || c.label || "").trim();
    var path = (c.path || c.parentPath || "").toLowerCase();
    var inSidebar = c.x >= sidebarX;

    if (inSidebar && text && !isLikelySampleDisplayText(text)) {
      if (BD_OUTPUT_LABEL_RE.test(text) || isButtonLabelText(text) || BD_LINK_TEXT_RE.test(text)) {
        c.isBdPriority = true;
        c.shouldNumberHint = true;
        c.roleHint = isButtonLabelText(text) || BD_LINK_TEXT_RE.test(text) ? "button" : "label";
        c.score = Math.max(c.score, 86);
        if (c.roleHint === "button") c.isAction = true;
      }
    }

    if (isLikelySectionTitleText(text)) {
      c.roleHint = "section_title";
      c.isBdPriority = true;
      c.shouldNumberHint = true;
      c.score = Math.max(c.score, 88);
    }

    if (BD_FORM_LABEL_RE.test(text)) {
      c.roleHint = "label";
      c.isBdPriority = true;
      c.shouldNumberHint = true;
      c.score = Math.max(c.score, 80);
    }

    if (BD_REAL_ESTATE_LABEL_RE.test(text) || BD_CARD_SECTION_TITLE_RE.test(text)) {
      c.isBdPriority = true;
      c.shouldNumberHint = true;
      c.score = Math.max(c.score, 84);
      if (BD_CARD_SECTION_TITLE_RE.test(text) && text.length >= 4) {
        c.roleHint = "section_title";
      } else {
        c.roleHint = "label";
      }
    }

    if (text && text.length <= 40 && BD_RADIO_OPTION_RE.test(text)) {
      c.roleHint = /席/.test(text) ? "tab" : "radio";
      c.isBdPriority = true;
      c.shouldNumberHint = true;
      c.score = Math.max(c.score, 82);
    }

    if (isButtonLabelText(text) || BD_LINK_TEXT_RE.test(text)) {
      c.roleHint = "button";
      c.isAction = true;
      c.isBdPriority = true;
      c.shouldNumberHint = true;
      c.score = Math.max(c.score, 88);
    }

    if (BD_SIMULATION_ACTION_RE.test(text) || BD_SIMULATION_TITLE_RE.test(text)) {
      c.isBdPriority = true;
      c.shouldNumberHint = true;
      c.score = Math.max(c.score, 86);
      if (BD_SIMULATION_TITLE_RE.test(text) && text.length >= 8) {
        c.roleHint = "section_title";
      } else if (isButtonLabelText(text) || /出力|計算|戻る|保存/.test(text)) {
        c.roleHint = "button";
        c.isAction = true;
      } else {
        c.roleHint = c.roleHint || "label";
      }
    }

    if (/^[＋\+−\-]$/.test(text)) {
      c.isAction = true;
      c.isBdPriority = true;
      c.shouldNumberHint = true;
      c.roleHint = "icon";
      c.score = Math.max(c.score, 86);
    }

    if (c.y < 130 && (c.role === "icon" || c.type === "INSTANCE" || c.type === "COMPONENT") &&
        c.width <= 56 && c.height <= 56 && !isInTableRegion(path) &&
        (isIconLikeName(c.name) || /cart|menu|header|nav|icon/i.test(path))) {
      c.isAction = true;
      c.isBdPriority = true;
      c.shouldNumberHint = true;
      c.score = Math.max(c.score, 82);
    }

    if ((c.role === "icon" || c.type === "INSTANCE") && c.width <= 48 && c.height <= 48 &&
        (/edit|pencil|pen|編集/i.test(path) || /edit|pencil|pen/i.test(c.name || ""))) {
      c.isAction = true;
      c.isBdPriority = true;
      c.shouldNumberHint = true;
      c.score = Math.max(c.score, 85);
    }

    if (/seat|座席|grid|map|シート/i.test(path) &&
        (c.type === "FRAME" || c.type === "INSTANCE" || c.type === "COMPONENT") &&
        c.width >= 200 && c.height >= 120) {
      c.isBdPriority = true;
      c.shouldNumberHint = true;
      c.roleHint = "label";
      c.text = c.text || "座席マップ";
      c.score = Math.max(c.score, 80);
    }

    if (text.length >= 10 && text.length <= 52 &&
        /ワークショップ|workshop|seminar/i.test(text) &&
        !isLikelySampleDisplayText(text)) {
      c.roleHint = "label";
      c.isBdPriority = true;
      c.shouldNumberHint = true;
      c.score = Math.max(c.score, 80);
    }

    if (isLikelySectionCardTitle(c, candidates)) {
      c.roleHint = "section_title";
      c.isBdPriority = true;
      c.shouldNumberHint = true;
      c.score = Math.max(c.score, 84);
    }
  }
}

function markRadioTabOptions(candidates) {
  for (var i = 0; i < candidates.length; i++) {
    var c = candidates[i];
    if (c.type !== "TEXT") continue;
    var text = (c.text || "").trim();
    if (!text || text.length > 36) continue;
    var path = (c.path || "").toLowerCase();
    if (/radio|toggle|tab|segment|checkbox|card-select|payment|申込|支払|区分/i.test(path)) {
      c.roleHint = /tab|segment/i.test(path) ? "tab" : "radio";
      c.shouldNumberHint = true;
      c.score = Math.max(c.score, 82);
    }
  }
}

function markProductCardTitles(candidates) {
  for (var i = 0; i < candidates.length; i++) {
    var c = candidates[i];
    if (c.type !== "TEXT") continue;
    var text = (c.text || "").trim();
    if (text.length < 6 || text.length > 52) continue;
    var path = (c.path || "").toLowerCase();
    if (/card|product|workshop|seminar|ticket|course|item-row|event|申込内容/i.test(path)) {
      c.roleHint = "label";
      c.shouldNumberHint = true;
      c.score = Math.max(c.score, 80);
    }
  }
}

function isSpatiallyContained(inner, outer) {
  if (!inner || !outer || inner.id === outer.id) return false;
  var ix = inner.x != null ? inner.x : 0;
  var iy = inner.y != null ? inner.y : 0;
  var iw = inner.width || 0;
  var ih = inner.height || 0;
  var ox = outer.x != null ? outer.x : 0;
  var oy = outer.y != null ? outer.y : 0;
  var ow = outer.width || 0;
  var oh = outer.height || 0;
  return ix >= ox - 3 && iy >= oy - 3 &&
    ix + iw <= ox + ow + 3 && iy + ih <= oy + oh + 3;
}

function isBasicDesignItem(c) {
  if (!c) return false;
  if (c.shouldNumberHint === false) return false;
  if (c.isLikelySeparator || c.ignoreReason === "breadcrumb_separator" ||
      c.ignoreReason === "duplicate_child_text" || c.ignoreReason === "input_value" ||
      c.ignoreReason === "sample_display_value" || c.ignoreReason === "description_text") {
    return false;
  }

  var text = (c.text || c.label || "").trim();
  if (!text && c.type === "TEXT") return false;
  if (SEAT_CODE_RE.test(text)) return false;
  if (isLikelySampleDisplayText(text)) return false;
  if (isLikelyDescriptionParagraph(c)) return false;
  if (isInputFieldValueCandidate(c)) return false;

  if (c.isAction || c.roleHint === "button" || isButtonLabelText(text) || BD_LINK_TEXT_RE.test(text)) {
    return true;
  }
  if ((c.roleHint === "icon" || c.role === "icon") && (c.isAction || c.isBdPriority)) return true;
  if (c.roleHint === "section_title" || isLikelySectionTitleText(text)) return true;
  if (BD_OUTPUT_LABEL_RE.test(text)) return true;
  if (BD_FORM_LABEL_RE.test(text)) return true;
  if (BD_REAL_ESTATE_LABEL_RE.test(text) || BD_CARD_SECTION_TITLE_RE.test(text)) return true;
  if (text.length <= 36 && BD_RADIO_OPTION_RE.test(text)) return true;
  if (/^[＋\+−\-]$/.test(text)) return true;
  if (c.roleHint === "tab" || c.roleHint === "radio") return true;
  if (c.tableRoleHint === "column_header" || c.tableRoleHint === "row_header" ||
      c.tableRoleHint === "action") return true;

  if (c.type === "TEXT" && c.y < 140 &&
      text.length >= 4 && text.length <= 40 &&
      (text === text.toUpperCase() || /checkout|チェックアウト/i.test(text))) {
    return true;
  }

  if ((c.type === "FRAME" || c.type === "INSTANCE" || c.type === "COMPONENT") &&
      /seat|座席|grid|map/i.test((c.path || "").toLowerCase()) &&
      c.width >= 200 && c.height >= 120) {
    return true;
  }

  if (text.length >= 10 && text.length <= 52 && /ワークショップ|workshop|seminar/i.test(text)) {
    return true;
  }

  if (c.type === "TEXT" && text.length >= 2 && text.length <= 52 && c.shouldNumberHint !== false) {
    if (BD_SIMULATION_ACTION_RE.test(text) || BD_SIMULATION_TITLE_RE.test(text)) return true;
    if (c.roleHint === "label" || c.roleHint === "section_title" || c.isBdPriority) {
      if (!isLikelyValueText(text) && !isLikelySampleDisplayText(text) &&
          !isInputFieldValueCandidate(c) && !c.isLikelyTableCellValue) {
        return true;
      }
    }
  }

  if ((c.roleHint === "icon" || c.role === "icon") && c.shouldNumberHint !== false) return true;

  return false;
}

function isStructuralAutoPick(c) {
  return isBasicDesignItem(c);
}

function collapseRepeatedActionIconsMapped(mapped, selectableMap) {
  var groups = {};
  for (var i = 0; i < mapped.length; i++) {
    var m = mapped[i];
    var c = selectableMap[m.id];
    if (!c || !(c.isAction && (c.roleHint === "icon" || c.role === "icon"))) continue;
    var path = (c.path || "").toLowerCase();
    var key = "icon_" + Math.round(c.x / 28);
    if (/table|grid|seat|action|アクション/i.test(path)) {
      key = "table_icon_" + Math.round(c.x / 28) + "_" + (c.label || c.name || "x");
    }
    if (!groups[key]) groups[key] = [];
    groups[key].push(m);
  }
  var dropIds = {};
  for (var gk in groups) {
    var g = groups[gk];
    if (g.length < 2) continue;
    g.sort(function(a, b) { return a.y - b.y; });
    for (var j = 1; j < g.length; j++) dropIds[g[j].id] = true;
  }
  return mapped.filter(function(m) { return !dropIds[m.id]; });
}

function dedupeNestedAutoItems(mapped, selectableMap) {
  var kept = [];
  for (var i = 0; i < mapped.length; i++) {
    var m = mapped[i];
    var c = selectableMap[m.id];
    var skip = false;

    if (c && c.type === "TEXT") {
      for (var j = 0; j < mapped.length; j++) {
        if (i === j) continue;
        var other = mapped[j];
        var oc = selectableMap[other.id];
        if (!oc || oc.type === "TEXT") continue;
        var sameText = (m.text || "") && (m.text === other.text || m.text === oc.text);
        if (sameText && isSpatiallyContained(m, other)) {
          skip = true;
          break;
        }
        if (isSpatiallyContained(m, other) &&
            (oc.roleHint === "button" || oc.isAction || /button|btn/i.test(oc.type || ""))) {
          skip = true;
          break;
        }
      }
    }

    if (!skip && c && c.type !== "TEXT" && (c.width || 0) * (c.height || 0) >= 8000) {
      var innerCount = 0;
      for (var k = 0; k < mapped.length; k++) {
        if (k === i) continue;
        if (isSpatiallyContained(mapped[k], m)) innerCount++;
      }
      if (innerCount >= 2) skip = true;
    }

    if (!skip && c && isGenericComponentName(c.name) && c.type !== "TEXT" && !c.isAction && !c.isBdPriority) {
      skip = true;
    }

    if (!skip) kept.push(m);
  }
  return kept;
}

function dropSeatCellItems(mapped) {
  return mapped.filter(function(m) {
    return !SEAT_CODE_RE.test((m.text || "").trim());
  });
}

function dropRepeatedFieldLabels(mapped, selectableMap) {
  var seen = {};
  var out = [];
  for (var i = 0; i < mapped.length; i++) {
    var m = mapped[i];
    var key = normalizeForMatch(m.text || "");
    var c = selectableMap[m.id];
    if (c && c.roleHint === "label" && key &&
        /参加者|メール|座席|カード|名義|期限|cvv|セキュリティ/i.test(key)) {
      if (seen[key]) continue;
      seen[key] = true;
    }
    out.push(m);
  }
  return out;
}

function keepOneSeatMapRepresentative(mapped, selectableMap) {
  var best = null;
  var bestArea = 0;
  for (var i = 0; i < mapped.length; i++) {
    var m = mapped[i];
    var c = selectableMap[m.id];
    if (!c) continue;
    var path = (c.path || "").toLowerCase();
    if (!/seat|座席|grid|map/i.test(path)) continue;
    if (c.type === "TEXT" && SEAT_CODE_RE.test((m.text || "").trim())) continue;
    var area = (c.width || 0) * (c.height || 0);
    if (area > bestArea) {
      bestArea = area;
      best = m.id;
    }
  }
  if (!best) return mapped;
  return mapped.filter(function(m) {
    var c = selectableMap[m.id];
    if (!c) return true;
    var path = (c.path || "").toLowerCase();
    if (!/seat|座席|grid|map/i.test(path)) return true;
    if (c.type === "TEXT" && !SEAT_CODE_RE.test((m.text || "").trim()) &&
        (c.width || 0) < 200) return true;
    return m.id === best;
  });
}

function sortAutoReadingOrder(mapped) {
  return sortElementsReadingOrder(mapped);
}

function getAutoFinalMax(selectableCount) {
  if (selectableCount >= 200) return 110;
  if (selectableCount >= 120) return 85;
  if (selectableCount >= 60) return 65;
  return 55;
}

function computeAutoTargetMin(selectableCount, frameHeight) {
  var base = 35;
  if (frameHeight >= 1400) base = 45;
  if (frameHeight >= 2200) base = 55;
  var ratio = Math.round(selectableCount * 0.6);
  return Math.min(selectableCount, Math.max(base, ratio));
}

function finalizeAutoSelection(mapped, selectableMap, frameWidth, selectableCount) {
  var out = mapped.slice();
  out = out.filter(function(m) {
    var c = selectableMap[m.id];
    if (!c) return false;
    if (typeof m.confidence === "number" && m.confidence >= 0.75) return true;
    return isBasicDesignItem(c);
  });
  out = dropSeatCellItems(out);
  out = dedupeNestedAutoItems(out, selectableMap);
  out = dropRepeatedFieldLabels(out, selectableMap);
  out = keepOneSeatMapRepresentative(out, selectableMap);
  out = collapseRepeatedActionIconsMapped(out, selectableMap);
  out = sortAutoReadingOrder(out);
  var finalMax = getAutoFinalMax(selectableCount || out.length);
  if (out.length > finalMax) out = out.slice(0, finalMax);
  return out;
}

function refineAutoSelectedItems(mapped, selectableMap) {
  var refined = [];
  for (var i = 0; i < mapped.length; i++) {
    var m = mapped[i];
    var c = selectableMap[m.id];
    if (!c || !isBasicDesignItem(c)) continue;
    if (isLikelySampleDisplayText(m.text)) continue;
    if (c.ignoreReason === "duplicate_child_text") continue;
    refined.push(m);
  }
  return refined;
}

function selectCuratedAutoItems(selectable, frameWidth) {
  var picked = [];
  for (var i = 0; i < selectable.length; i++) {
    if (isBasicDesignItem(selectable[i])) picked.push(selectable[i]);
  }
  var pseudo = picked.map(function(c) {
    return candidateToMappedElement(c, 0, "curated");
  });
  var map = buildSelectableMap(selectable);
  pseudo = finalizeAutoSelection(pseudo, map, frameWidth, selectable.length);
  var idSet = {};
  for (var j = 0; j < pseudo.length; j++) idSet[pseudo[j].id] = true;
  return picked.filter(function(c) { return idSet[c.nodeId]; });
}

function selectDeterministicAutoItems(selectable, frameWidth) {
  return selectCuratedAutoItems(selectable, frameWidth);
}

function backfillAutoSelection(mapped, selectable, selectableMap, frameWidth, frameHeight) {
  var targetMin = computeAutoTargetMin(selectable.length, frameHeight || 0);
  if (mapped.length >= targetMin) return mapped;

  var used = {};
  for (var i = 0; i < mapped.length; i++) used[mapped[i].id] = true;

  var extras = prioritizeSelectableForAuto(selectable);
  var out = mapped.slice();
  for (var j = 0; j < extras.length && out.length < targetMin; j++) {
    var c = extras[j];
    if (!c || used[c.nodeId] || !isBasicDesignItem(c)) continue;
    out.push(candidateToMappedElement(c, out.length + 1, "backfill"));
    used[c.nodeId] = true;
  }
  return out;
}

function buildSelectableMap(selectable) {
  var map = {};
  for (var i = 0; i < selectable.length; i++) map[selectable[i].nodeId] = selectable[i];
  return map;
}

function candidateToMappedElement(c, number, reason) {
  return {
    id: c.nodeId,
    name: c.name,
    type: c.type,
    text: c.text || "",
    label: c.label || "",
    role: c.role || "",
    parentPath: c.path || "",
    number: String(number),
    x: c.x, y: c.y, width: c.width, height: c.height,
    centerX: c.centerX, centerY: c.centerY,
    itemType: c.roleHint || "",
    aiReason: reason || "",
    confidence: 0.75,
    enabled: true,
  };
}

function inferRoleHint(c) {
  var path = (c.path || "").toLowerCase();
  var name = (c.name || "").toLowerCase();
  var text = (c.text || "").trim();
  if (c.roleHint === "icon" || c.role === "icon") return "icon";
  if (/breadcrumb|パンくず/.test(path)) return "breadcrumb";
  if (/pagination/.test(path)) return "pagination";
  if (/tab|タブ/.test(path)) return "tab";
  if (/button|btn|primary|secondary/.test(path) || /button|btn/.test(name)) return "button";
  if (isButtonLabelText(text)) return "button";
  if (/textfield|input|combobox|select|search/.test(path)) {
    if (/label/.test(path) || /label/.test(name)) return "label";
    return "input";
  }
  if (/checkbox|check-box/.test(path) || /checkbox/.test(name)) return "checkbox";
  if (/radio/.test(path)) return "radio";
  if (/table-header|column-header/.test(path)) return "table_column_header";
  if (c.tableRoleHint === "row_header") return "table_row_header";
  if (c.tableRoleHint === "column_header") return "table_column_header";
  if (/title|heading|header/.test(path) && text.length <= 40) return "section_title";
  if (c.type === "TEXT" && text) return "label";
  return "unknown";
}

function enrichCandidates(candidates, frame) {
  var enriched = [];
  for (var i = 0; i < candidates.length; i++) {
    var c = candidates[i];
    var path = c.parentPath || "";
    var parts = path.split(" > ");
    var text = (c.text || c.label || "").trim();
    var e = {
      nodeId: c.id,
      id: c.id,
      text: text,
      name: c.name || "",
      type: c.type || "",
      path: path,
      parentPath: path,
      x: c.x, y: c.y, width: c.width, height: c.height,
      centerX: c.centerX, centerY: c.centerY,
      parentName: parts.length ? parts[parts.length - 1] : "",
      parentType: "",
      roleHint: c.role || "",
      role: c.role || "",
      label: c.label || "",
      toolbarIndex: c.toolbarIndex || "",
      layoutHint: "",
      groupHint: "",
      tableId: null,
      rowIndex: null,
      colIndex: null,
      tableRoleHint: "unknown",
      isLikelySeparator: isLikelySeparatorText(text),
      isLikelyValue: isLikelyValueText(text),
      isLikelyDate: isLikelyDateText(text),
      isLikelyMoney: isLikelyMoneyText(text),
      isLikelyNumeric: isNumericOnlyText(text),
      isLikelyTableHeader: false,
      isLikelyRowHeader: false,
      isLikelyColumnHeader: false,
      isLikelyTableCellValue: false,
      shouldNumberHint: true,
      ignoreReason: "",
      score: 50,
      bucket: "selectable",
    };
    if (e.isLikelySeparator) {
      e.shouldNumberHint = false;
      e.ignoreReason = "separator";
      e.score = 0;
    } else if (e.isLikelyValue && !e.isLikelySeparator) {
      e.score = 15;
    }
    e.roleHint = inferRoleHint(e);
    enriched.push(e);
  }
  detectTableLikeGroups(enriched, frame);
  detectBreadcrumbHints(enriched);
  markInputLabelVsValue(enriched);
  markDuplicateChildText(enriched);
  groupFormFieldPairs(enriched);
  groupIconTitlePairs(enriched);
  markActionElements(enriched);
  markSampleAndDescriptionText(enriched);
  markRadioTabOptions(enriched);
  markProductCardTitles(enriched);
  markFormFieldLabels(enriched);
  markBdCoverageBoost(enriched, frame.width);
  return enriched;
}

function markFormFieldLabels(candidates) {
  var inputs = candidates.filter(function(c) {
    if (!isInputContainerType(c.type)) return false;
    var path = (c.path || "").toLowerCase();
    if (/textfield|input|combobox|select|textarea/i.test(path)) return true;
    return c.height >= 24 && c.height <= 64 && c.width >= 48 && c.width <= 400;
  });

  for (var i = 0; i < candidates.length; i++) {
    var c = candidates[i];
    if (c.type !== "TEXT") continue;
    var text = (c.text || "").trim();
    if (!text || isLikelyValueText(text) || isLikelySampleDisplayText(text)) continue;
    if (c.ignoreReason === "input_value" || c.ignoreReason === "duplicate_child_text") continue;

    if (BD_REAL_ESTATE_LABEL_RE.test(text) || BD_CARD_SECTION_TITLE_RE.test(text)) {
      c.roleHint = BD_CARD_SECTION_TITLE_RE.test(text) ? "section_title" : "label";
      c.isBdPriority = true;
      c.shouldNumberHint = true;
      c.score = Math.max(c.score, 84);
      continue;
    }

    for (var j = 0; j < inputs.length; j++) {
      var inp = inputs[j];
      if (parentPathPrefix(c.path, 3) !== parentPathPrefix(inp.path, 3)) continue;
      var gap = inp.y - (c.y + c.height);
      var xAlign = Math.abs((c.x + c.width / 2) - (inp.x + inp.width / 2)) < 40 ||
        Math.abs(c.x - inp.x) < 20;
      if (gap >= -6 && gap <= 40 && xAlign && text.length >= 2 && text.length <= 36) {
        c.roleHint = "label";
        c.isBdPriority = true;
        c.shouldNumberHint = true;
        c.score = Math.max(c.score, 79);
        break;
      }
    }
  }
}

function detectBreadcrumbHints(candidates) {
  var texts = candidates.filter(function(c) {
    return c.type === "TEXT" && (c.text || "").trim();
  });
  var rows = clusterElementsByY(texts, 10);
  for (var r = 0; r < rows.length; r++) {
    var row = rows[r];
    var seps = 0;
    var items = 0;
    for (var i = 0; i < row.length; i++) {
      if (isLikelySeparatorText(row[i].text)) seps++;
      else if (!isLikelyValueText(row[i].text) || isLikelyDateText(row[i].text)) items++;
    }
    if (seps < 1 || items < 2) continue;
    for (var j = 0; j < row.length; j++) {
      var c = row[j];
      if (isLikelySeparatorText(c.text)) {
        c.shouldNumberHint = false;
        c.ignoreReason = "breadcrumb_separator";
        c.groupHint = "breadcrumb";
      } else if (isLikelyDateText(c.text)) {
        c.shouldNumberHint = false;
        c.isLikelyDate = true;
        c.ignoreReason = "breadcrumb_date";
        c.groupHint = "breadcrumb";
      } else {
        c.groupHint = "breadcrumb";
        c.roleHint = "breadcrumb";
        c.shouldNumberHint = true;
        c.score = Math.max(c.score, 70);
      }
    }
  }
}

function markInputLabelVsValue(candidates) {
  for (var i = 0; i < candidates.length; i++) {
    var c = candidates[i];
    if (c.type !== "TEXT") continue;
    var path = (c.path || "").toLowerCase();
    if (INPUT_VALUE_PATH_RE.test(path) && !INPUT_LABEL_PATH_RE.test(path)) {
      c.shouldNumberHint = false;
      c.isLikelyTableCellValue = false;
      c.ignoreReason = c.ignoreReason || "input_value";
      c.score = 10;
    }
    if (INPUT_LABEL_PATH_RE.test(path) || /label/.test((c.name || "").toLowerCase())) {
      c.shouldNumberHint = true;
      c.roleHint = "label";
      c.score = Math.max(c.score, 75);
    }
  }
}

function markDuplicateChildText(candidates) {
  var controls = candidates.filter(function(c) {
    if (c.type === "TEXT") return false;
    var cPath = (c.path || "").toLowerCase();
    if (c.roleHint === "button" || c.roleHint === "input") return true;
    if (/button|textfield|input|instance|component/i.test(c.type)) return true;
    if (c.type === "FRAME" && /button|btn/.test(cPath)) return true;
    return false;
  });
  for (var i = 0; i < candidates.length; i++) {
    var t = candidates[i];
    if (t.type !== "TEXT" || !t.text) continue;
    var path = (t.path || "").toLowerCase();
    if (!/button|textfield|input|btn/i.test(path) && !isButtonLabelText(t.text)) continue;
    for (var j = 0; j < controls.length; j++) {
      var ctrl = controls[j];
      if (t.nodeId === ctrl.nodeId) continue;
      if (path.indexOf((ctrl.name || "").toLowerCase()) !== -1 ||
          t.x >= ctrl.x - 4 && t.y >= ctrl.y - 4 &&
          t.x + t.width <= ctrl.x + ctrl.width + 4 &&
          t.y + t.height <= ctrl.y + ctrl.height + 4) {
        t.shouldNumberHint = false;
        t.ignoreReason = "duplicate_child_text";
        t.score = 5;
        ctrl.shouldNumberHint = true;
        ctrl.score = Math.max(ctrl.score, 80);
        break;
      }
    }
  }
}

function isInputContainerType(type) {
  return type === "FRAME" || type === "INSTANCE" || type === "COMPONENT";
}

function hasTextBetweenY(candidates, parentPath, yMin, yMax, excludeId) {
  for (var i = 0; i < candidates.length; i++) {
    var n = candidates[i];
    if (n.nodeId === excludeId) continue;
    if (n.type !== "TEXT") continue;
    if (n.parentPath !== parentPath) continue;
    if (n.y > yMin && n.y < yMax) return true;
  }
  return false;
}

function groupFormFieldPairs(enriched) {
  var labels = enriched.filter(function(c) {
    if (c.type !== "TEXT") return false;
    var text = (c.text || "").trim();
    if (!text || isLikelyValueText(text)) return false;
    if (c.ignoreReason === "duplicate_child_text" || c.ignoreReason === "input_value") return false;
    return true;
  });
  var inputs = enriched.filter(function(c) {
    return isInputContainerType(c.type) && c.shouldNumberHint !== false;
  });

  for (var i = 0; i < labels.length; i++) {
    var a = labels[i];
    var best = null;
    var bestGap = Infinity;
    for (var j = 0; j < inputs.length; j++) {
      var b = inputs[j];
      if (b.ignoreReason === "input_under_label") continue;
      if (b.width < a.width * 0.7) continue;

      var samePrefix = parentPathPrefix(a.parentPath, 2) === parentPathPrefix(b.parentPath, 2);
      var alignedBelow = Math.abs(a.x - b.x) < 20 &&
        b.y > a.y &&
        b.y - (a.y + a.height) < 48;
      if (!samePrefix && !alignedBelow) continue;

      if (hasTextBetweenY(enriched, a.parentPath, a.y, b.y, a.nodeId)) continue;

      var gap = b.y - (a.y + a.height);
      if (gap < bestGap) {
        bestGap = gap;
        best = b;
      }
    }
    if (best) {
      best.shouldNumberHint = false;
      best.ignoreReason = "input_under_label";
      a.roleHint = "label";
      a.score = Math.max(a.score, 78);
    }
  }
}

function groupIconTitlePairs(enriched) {
  var icons = enriched.filter(function(c) {
    if (c.ignoreReason === "title_beside_icon") return false;
    if (c.role === "icon" || c.roleHint === "icon") return true;
    return (c.type === "INSTANCE" || c.type === "COMPONENT") &&
      c.width <= 32 && c.height <= 32;
  });
  var titles = enriched.filter(function(c) {
    return c.type === "TEXT" && (c.text || "").trim() && c.shouldNumberHint !== false;
  });

  for (var i = 0; i < icons.length; i++) {
    var a = icons[i];
    var best = null;
    var bestDist = Infinity;
    for (var j = 0; j < titles.length; j++) {
      var b = titles[j];
      if (b.ignoreReason === "title_beside_icon") continue;
      if (parentPathPrefix(a.parentPath, 2) !== parentPathPrefix(b.parentPath, 2)) continue;

      var rowAlign = Math.abs(a.y + a.height / 2 - b.y - b.height / 2) < 14;
      var beside = b.x > a.x && b.x - (a.x + a.width) < 16;
      if (!rowAlign || !beside) continue;

      var dist = b.x - (a.x + a.width);
      if (dist < bestDist) {
        bestDist = dist;
        best = b;
      }
    }
    if (best) {
      best.shouldNumberHint = false;
      best.ignoreReason = "title_beside_icon";
      a.label = a.label || best.text;
      a.shouldNumberHint = true;
      a.score = Math.max(a.score, 82);
    }
  }
}

function detectTableLikeGroups(candidates, frame) {
  var tableEls = [];
  for (var i = 0; i < candidates.length; i++) {
    var c = candidates[i];
    if (isInTableRegion((c.path || "").toLowerCase())) tableEls.push(c);
  }
  if (!tableEls.length) return;

  var byRegion = {};
  for (var t = 0; t < tableEls.length; t++) {
    var el = tableEls[t];
    var region = extractTableRegionKey((el.path || "").toLowerCase()) || "table_cluster";
    el.tableId = region;
    if (!byRegion[region]) byRegion[region] = [];
    byRegion[region].push(el);
  }

  for (var region in byRegion) {
    var group = byRegion[region];
    var pseudo = group.map(function(c) {
      return { x: c.x, y: c.y, width: c.width, height: c.height, parentPath: c.path, type: c.type, text: c.text, role: c.role };
    });
    var cutoffs = buildTableHeaderCutoffs(pseudo);

    var xs = group.map(function(c) { return c.x + c.width / 2; }).sort(function(a, b) { return a - b; });
    var leftMedian = xs[Math.floor(xs.length * 0.28)] || xs[0];
    var leftLabels = 0;
    for (var li = 0; li < group.length; li++) {
      var g = group[li];
      if (g.type !== "TEXT") continue;
      if (g.x + g.width / 2 <= leftMedian + 8 && !isLikelyValueText(g.text)) leftLabels++;
    }
    var verticalHeaderTable = leftLabels >= 5;

    var rows = clusterElementsByY(group, 14);
    for (var ri = 0; ri < rows.length; ri++) {
      for (var ci = 0; ci < rows[ri].length; ci++) {
        rows[ri][ci].rowIndex = ri;
        rows[ri][ci].colIndex = ci;
      }
    }

    for (var gi = 0; gi < group.length; gi++) {
      var c = group[gi];
      var path = (c.path || "").toLowerCase();
      var cy = c.y + c.height / 2;

      if (TABLE_HEADER_PATH_RE.test(path)) {
        c.tableRoleHint = "column_header";
        c.isLikelyColumnHeader = true;
        c.shouldNumberHint = true;
        c.score = Math.max(c.score, 85);
        continue;
      }

      if (verticalHeaderTable && c.type === "TEXT" && c.x + c.width / 2 <= leftMedian + 12) {
        if (!isLikelyValueText(c.text) || c.text.length > 4) {
          c.tableRoleHint = "row_header";
          c.isLikelyRowHeader = true;
          c.shouldNumberHint = true;
          c.score = Math.max(c.score, 82);
          continue;
        }
      }

      if (cutoffs[region] != null && cy <= cutoffs[region] + 8) {
        if (c.type === "TEXT" && !isLikelyValueText(c.text)) {
          c.tableRoleHint = "column_header";
          c.isLikelyColumnHeader = true;
          c.shouldNumberHint = true;
          c.score = Math.max(c.score, 80);
        }
        continue;
      }

      if (isActionIconCandidate(c)) {
        c.tableRoleHint = "action";
        c.isLikelyTableCellValue = false;
        c.shouldNumberHint = true;
        c.score = Math.max(c.score, 88);
        continue;
      }

      if (isTableBodyValue({ parentPath: c.path, y: c.y, height: c.height }, cutoffs) ||
          (cutoffs[region] != null && cy > cutoffs[region] + 8)) {
        if (isLikelyValueText(c.text) || c.isLikelyNumeric ||
            (c.roleHint === "icon" && !isActionIconCandidate(c))) {
          c.tableRoleHint = "cell_value";
          c.isLikelyTableCellValue = true;
          c.shouldNumberHint = false;
          c.ignoreReason = c.ignoreReason || "table_cell_value";
          c.score = 10;
        }
      }
    }
  }
}

function isDecorativeCandidate(c) {
  if (c.type === "LINE") return true;
  var n = (c.name || "").toLowerCase();
  if (c.type === "RECTANGLE" && /border|divider|separator|line/.test(n)) return true;
  if (/border|divider|separator/.test((c.path || "").toLowerCase()) && c.type !== "TEXT") return true;
  return false;
}

function isInputFieldValueCandidate(c) {
  if (c.type !== "TEXT") return false;
  return INPUT_VALUE_PATH_RE.test((c.path || "").toLowerCase()) &&
    !INPUT_LABEL_PATH_RE.test((c.path || "").toLowerCase());
}

function preFilterCandidates(enriched) {
  var selectable = [];
  var contextOnly = [];
  var ignored = [];
  var cutoffs = buildTableHeaderCutoffs(enriched.map(function(c) {
    return { parentPath: c.path, y: c.y, height: c.height };
  }));
  var repeatCounts = buildRepeatTextKeys(enriched.map(function(c) {
    return { type: c.type, text: c.text, parentPath: c.path, y: c.y, height: c.height };
  }), cutoffs);

  for (var i = 0; i < enriched.length; i++) {
    var c = enriched[i];
    c.bucket = "selectable";

    if (c.isLikelySeparator || c.ignoreReason === "breadcrumb_separator") {
      c.bucket = "ignored";
      ignored.push(c);
      continue;
    }
    if (isDecorativeCandidate(c)) {
      c.bucket = "ignored";
      c.ignoreReason = "decorative";
      ignored.push(c);
      continue;
    }
    if (c.tableRoleHint === "cell_value" || c.isLikelyTableCellValue) {
      if (isActionIconCandidate(c)) {
        c.isLikelyTableCellValue = false;
        c.tableRoleHint = "action";
        c.shouldNumberHint = true;
      } else {
        c.bucket = "contextOnly";
        contextOnly.push(c);
        continue;
      }
    }
    if (isInputFieldValueCandidate(c) || c.ignoreReason === "input_value") {
      c.bucket = "contextOnly";
      contextOnly.push(c);
      continue;
    }
    if (c.isLikelyValue && !c.isBdPriority && c.tableRoleHint !== "row_header" &&
        c.tableRoleHint !== "column_header" &&
        !c.isLikelyRowHeader && !c.isLikelyColumnHeader && !c.isAction) {
      if (isRepeatedTableCellText({ type: c.type, text: c.text, parentPath: c.path }, repeatCounts, cutoffs) ||
          c.isLikelyDate || c.isLikelyMoney || c.isLikelyNumeric ||
          c.ignoreReason === "sample_display_value") {
        c.bucket = "contextOnly";
        contextOnly.push(c);
        continue;
      }
    }
    if (c.ignoreReason === "description_text") {
      c.bucket = "contextOnly";
      contextOnly.push(c);
      continue;
    }
    if (c.ignoreReason === "generic_component" && !c.isAction && !c.isBdPriority) {
      c.bucket = "contextOnly";
      contextOnly.push(c);
      continue;
    }
    if (c.ignoreReason === "duplicate_child_text") {
      c.bucket = "contextOnly";
      contextOnly.push(c);
      continue;
    }
    if (c.shouldNumberHint === false) {
      if (c.ignoreReason) {
        c.bucket = "ignored";
        ignored.push(c);
      } else {
        c.bucket = "contextOnly";
        contextOnly.push(c);
      }
      continue;
    }
    if (c.roleHint === "icon" && isInTableRegion((c.path || "").toLowerCase()) &&
        c.tableRoleHint !== "column_header" && !isTableHeaderElement(
          { parentPath: c.path, y: c.y, height: c.height }, cutoffs) &&
        !isActionIconCandidate(c)) {
      c.bucket = "contextOnly";
      contextOnly.push(c);
      continue;
    }
    if (!c.text && c.type === "TEXT") {
      c.bucket = "ignored";
      ignored.push(c);
      continue;
    }
    selectable.push(c);
  }

  return { selectable: selectable, contextOnly: contextOnly, ignored: ignored };
}

function escapePromptText(val) {
  return String(val || "")
    .replace(/\\/g, "\\\\")
    .replace(/"/g, '\\"')
    .replace(/\r?\n/g, " ")
    .slice(0, 100);
}

function formatCandidateLine(c, idx) {
  var line = (idx + 1) + ". nodeId=" + c.nodeId + " [" + c.type + '] text="' +
    escapePromptText(c.text || c.label || c.name) + '"';
  line += " roleHint=" + (c.roleHint || "");
  if (c.tableRoleHint && c.tableRoleHint !== "unknown") line += " tableRole=" + c.tableRoleHint;
  if (c.groupHint) line += " group=" + c.groupHint;
  if (c.role === "icon" || c.roleHint === "icon") line += " role=icon";
  if (c.toolbarIndex) line += " toolbarPos=" + c.toolbarIndex;
  if (c.isAction) line += " action=must_select";
  if (c.shouldNumberHint === false) line += " shouldNumberHint=false";
  if (c.ignoreReason) line += " preIgnore=" + c.ignoreReason;
  line += " @(" + Math.round(c.x) + "," + Math.round(c.y) + ")";
  return line;
}


async function callClaudeApiAuto(routerEndpoint, system, user) {
  return callRouterApiWithModel(routerEndpoint, system, user, ROUTER_AUTO_MODEL, AUTO_SELECT_MAX_TOKENS, ROUTER_SPEC_TIMEOUT_MS);
}

async function autoSelectElementsWithAI(opts) {
  var excludeIds = opts.excludeNodeIds || {};
  var selectable = (opts.selectable || []).filter(function(c) {
    return c && c.nodeId && !excludeIds[c.nodeId];
  });
  var contextOnly = opts.contextOnly || [];
  var ignored = opts.ignored || [];
  var routerEndpoint = opts.routerEndpoint || DEFAULT_ROUTER_ENDPOINT;
  var frameContext = opts.frameContext || {};
  var language = opts.language || "vi";
  var definedCount = opts.definedCount || 0;

  if (!selectable.length) {
    if (definedCount > 0) {
      return { elements: [], aiIgnored: [], selectableCount: 0 };
    }
    throw new Error("Khong co candidate selectable sau loc.");
  }

  var selList = prioritizeSelectableForAuto(selectable).slice(0, AUTO_SELECTABLE_LIMIT);
  var ctxCount = Math.min(contextOnly.length, AUTO_CONTEXT_LIMIT);

  var incrementalNote = definedCount > 0
    ? ("\n\nIMPORTANT: " + definedCount + " items are ALREADY numbered and excluded from this list. " +
      "Select ONLY the remaining NEW items below — do not re-number existing items.\n")
    : "";

  var user =
    "Frame context:\n" +
    "- name: \"" + (frameContext.name || "") + "\"\n" +
    "- size: " + (frameContext.width || 0) + "x" + (frameContext.height || 0) + "\n" +
    "- total enriched: " + (frameContext.total || 0) + "\n" +
    "- already numbered (excluded): " + definedCount + "\n" +
    "- selectable: " + selList.length + " (CHI duoc chon tu list nay)\n" +
    "- context-only: " + ctxCount + " (da loai khoi prompt — KHONG duoc chon)\n" +
    "- ignored: " + ignored.length + " (da loai)\n\n" +
    "=== SELECTABLE (choose nodeId from here only) ===\n" +
    selList.map(formatCandidateLine).join("\n") + incrementalNote + "\n\n" +
    "Task: Select UI items to number for Basic Design. Target count: " +
    computeAutoTargetMin(selList.length, frameContext.height || 0) + "-" +
    getAutoFinalMax(selectable.length) + " items for this screen. " +
    "Number by visual order top-to-bottom, left-to-right. " +
    "Include ALL sections: header, workflow steps, form field labels in cards (アクセス情報, 物件価格, 駅名…), " +
    "data cards, tables (headers only), sidebar, footer actions. " +
    "ONE number per logical BD item — not sample values (¥ prices, user names, seat codes A1-E10). " +
    "MUST include all action=must_select items (buttons, table action icons). " +
    "For repeated identical row icons or seat cells, pick one representative per type. " +
    "Return strict JSON with items[] only. Minimum confidence 0.75 to select.";

  var sys = language === "ja" ? AUTO_SELECT_SYSTEM + "\nJSONのみ。" : AUTO_SELECT_SYSTEM;
  postProgress("ai", "AI chon item can danh so (" + selList.length + " selectable)...");
  var jsonText = await callClaudeApiAuto(routerEndpoint, sys, user);
  var parsed = parseClaudeJson(jsonText);
  if (!parsed.items || !parsed.items.length) {
    parsed.items = [];
  }

  var selectableMap = {};
  for (var i = 0; i < selectable.length; i++) selectableMap[selectable[i].nodeId] = selectable[i];

  var mapped = [];
  var aiIgnored = parsed.ignored || [];
  for (var j = 0; j < parsed.items.length; j++) {
    var item = parsed.items[j];
    var nid = item.nodeId;
    if (!nid || !selectableMap[nid]) continue;
    if (typeof item.confidence === "number" && item.confidence < 0.75) continue;
    var orig = selectableMap[nid];
    mapped.push({
      id: orig.nodeId,
      name: item.label || orig.name,
      type: orig.type,
      text: orig.text || "",
      label: orig.label || "",
      role: orig.role || "",
      parentPath: orig.path || orig.parentPath || "",
      number: normalizeItemNumber(item.number) || String(mapped.length + 1),
      x: orig.x, y: orig.y, width: orig.width, height: orig.height,
      centerX: orig.centerX, centerY: orig.centerY,
      itemType: item.itemType || orig.roleHint || "",
      aiReason: item.reason || "",
      confidence: item.confidence,
      enabled: true,
    });
  }

  if (!mapped.length) {
    if (definedCount > 0) {
      return { elements: [], aiIgnored: aiIgnored, selectableCount: selList.length };
    }
    throw new Error("AI khong chon item nao phu hop (hoac confidence thap). Kiem tra proxy va thu lai.");
  }

  mapped = refineAutoSelectedItems(mapped, selectableMap);
  mapped = backfillAutoSelection(
    mapped, selectable, selectableMap, frameContext.width, frameContext.height
  );
  mapped = finalizeAutoSelection(mapped, selectableMap, frameContext.width, selectable.length);
  if (!mapped.length) {
    throw new Error("AI khong chon item nao sau khi loc. Thu lai hoac kiem tra frame.");
  }

  for (var n = 0; n < mapped.length; n++) mapped[n].number = String(n + 1);

  return { elements: mapped, aiIgnored: aiIgnored, selectableCount: selList.length };
}

function buildAutoPreviewRows(mapped, ignored, enriched) {
  var rows = [];
  for (var i = 0; i < mapped.length; i++) {
    var el = mapped[i];
    rows.push({
      enabled: true,
      number: el.number,
      nodeId: el.id,
      label: el.text || el.name,
      itemType: el.itemType || el.role || "",
      confidence: el.confidence,
      reason: el.aiReason || "",
      status: "selected",
    });
  }
  var ignMap = {};
  for (var j = 0; j < ignored.length; j++) {
    var ig = ignored[j];
    rows.push({
      enabled: false,
      number: "—",
      nodeId: ig.nodeId,
      label: ig.text || ig.name || "—",
      itemType: ig.roleHint || ig.type || "",
      confidence: null,
      reason: ig.ignoreReason || ig.bucket || "ignored",
      status: "ignored",
    });
    ignMap[ig.nodeId] = true;
  }
  rows.sort(function(a, b) {
    if (a.status !== b.status) return a.status === "selected" ? -1 : 1;
    if (a.status === "selected" && b.status === "selected") {
      return numberSortKey(a.number) - numberSortKey(b.number);
    }
    return 0;
  });
  return rows;
}

async function runAutoAiNumberingPipeline(frame, routerEndpoint, language, opts) {
  opts = opts || {};
  var definedRows = await resolveDefinedRowsForFrame(frame.id, opts.definedRows);
  var definedIds = buildDefinedIdSet(definedRows);
  var definedCount = definedRows.length;

  var drawCtx = getDrawContext(frame);
  var root = drawCtx.positionRoot;
  var collectOpts = getCollectOptions(root, { useScope: false });
  postProgress("scan", definedCount > 0
    ? ("Bo qua " + definedCount + " item da danh — quet phan con lai...")
    : (collectOpts
      ? ('Quet vung "' + collectOpts.scopeLabel + '"...')
      : "Quet frame..."));
  var rawAll = collectElements(root, "reading", collectOpts || undefined);
  rawAll = supplementButtonContainers(root, rawAll);
  annotateActionToolbarIcons(rawAll);
  if (!rawAll.length) throw new Error("Khong tim thay element trong frame.");

  var raw = definedCount
    ? rawAll.filter(function(el) { return el && el.id && !definedIds[el.id]; })
    : rawAll;

  if (!raw.length && definedCount > 0) {
    postProgress("filter", "Khong con item moi — giu " + definedCount + " item da danh so.");
    return {
      elements: [],
      selectedElements: [],
      method: "Bo qua AI — khong con item moi (" + definedCount + " item da danh so)",
      candidateCount: 0,
      rawElements: rawAll,
      structuralCount: 0,
      previewRows: [],
      enrichedCount: 0,
      ignoredCount: 0,
      skippedAi: true,
      definedCount: definedCount,
    };
  }

  postProgress("enrich", definedCount > 0
    ? ("Phan tich " + raw.length + " item moi (bo qua " + definedCount + " da danh)...")
    : "Phan tich cau truc (table, breadcrumb, field, action)...");
  var enriched = enrichCandidates(raw, root);
  var buckets = preFilterCandidates(enriched);

  postProgress("filter", "Loc " + buckets.selectable.length + " selectable / " +
    buckets.contextOnly.length + " context / " + buckets.ignored.length + " ignored" +
    (definedCount > 0 ? " (" + definedCount + " da danh so bo qua)" : ""));

  if (!buckets.selectable.length && definedCount > 0) {
    postProgress("ai", "Khong con item moi de goi AI.");
    return {
      elements: [],
      selectedElements: [],
      method: "Bo qua AI — khong con item moi (" + definedCount + " item da danh so)",
      candidateCount: raw.length,
      rawElements: rawAll,
      structuralCount: 0,
      previewRows: [],
      enrichedCount: enriched.length,
      ignoredCount: buckets.ignored.length,
      skippedAi: true,
      definedCount: definedCount,
    };
  }

  var aiResult = await autoSelectElementsWithAI({
    selectable: buckets.selectable,
    contextOnly: buckets.contextOnly,
    ignored: buckets.ignored,
    excludeNodeIds: definedIds,
    definedCount: definedCount,
    routerEndpoint: routerEndpoint,
    language: language,
    frameContext: {
      name: frame.name,
      width: root.width,
      height: root.height,
      total: enriched.length,
    },
  });

  var previewRows = buildAutoPreviewRows(aiResult.elements, buckets.ignored, enriched);
  var displayElements = [];
  for (var si = 0; si < aiResult.elements.length; si++) {
    var sel = aiResult.elements[si];
    sel.enabled = sel.enabled !== false;
    displayElements.push(sel);
  }
  for (var ii = 0; ii < buckets.ignored.length; ii++) {
    var ign = buckets.ignored[ii];
    displayElements.push({
      id: ign.nodeId,
      enabled: false,
      number: "—",
      text: ign.text || "",
      name: ign.name || "",
      type: ign.type || "TEXT",
      itemType: ign.roleHint || "ignored",
      aiReason: ign.ignoreReason || "ignored",
      parentPath: ign.path || ign.parentPath || "",
      role: ign.role || "",
    });
  }

  var methodLabel = definedCount > 0
    ? ("Auto AI incremental (giu " + definedCount + ", moi " + aiResult.elements.length + ")")
    : "Auto AI (hybrid + Claude Code)";

  return {
    elements: displayElements,
    selectedElements: aiResult.elements,
    method: methodLabel,
    candidateCount: raw.length,
    rawElements: rawAll,
    structuralCount: buckets.selectable.length,
    previewRows: previewRows,
    enrichedCount: enriched.length,
    ignoredCount: buckets.ignored.length,
    definedCount: definedCount,
    skippedAi: false,
  };
}

function buildAutoNumberedElements(frame, scope) {
  var drawCtx = getDrawContext(frame);
  var root = drawCtx.positionRoot;
  var raw;
  if (scope === "text") {
    raw = collectTextElementsForMatch(root);
  } else {
    raw = collectElements(root, "reading");
  }
  var structural = filterAutoStructuralTargets(raw);
  var filtered = structural.elements;
  var sorted = sortElementsReadingOrder(filtered);
  var elements = [];
  for (var j = 0; j < sorted.length; j++) {
    var el = sorted[j];
    elements.push({
      id: el.id,
      name: el.name,
      type: el.type,
      text: el.text || "",
      label: el.label || "",
      role: el.role || "",
      parentPath: el.parentPath || "",
      number: String(j + 1),
      x: el.x,
      y: el.y,
      width: el.width,
      height: el.height,
      centerX: el.centerX,
      centerY: el.centerY,
    });
  }
  var methodLabel = "Tu dong (cau truc UI: header/label, tren→duoi trai→phai)";
  if (scope === "text") methodLabel += " · chi text";
  return {
    elements: elements,
    method: methodLabel,
    candidateCount: raw.length,
    structuralCount: filtered.length,
  };
}

function isNumericOnlyText(text) {
  return /^[\d,.\-+\s%％]+$/.test(text || "");
}

function collectTextElementsForMatch(frame, collectedElements) {
  if (collectedElements && collectedElements.length) {
    return filterTextElementsForMatch(collectedElements);
  }
  return filterTextElementsForMatch(collectElements(frame));
}

function prioritizeCandidates(elements) {
  return elements.slice().sort(function(a, b) {
    var pathA = (a.parentPath || "").toLowerCase();
    var pathB = (b.parentPath || "").toLowerCase();
    var actionA = /action|アクション|操作|toolbar|icon-bar/i.test(pathA) ? 0 : 1;
    var actionB = /action|アクション|操作|toolbar|icon-bar/i.test(pathB) ? 0 : 1;
    if (actionA !== actionB) return actionA - actionB;
    if (a.role === "icon" && b.role !== "icon") return -1;
    if (b.role === "icon" && a.role !== "icon") return 1;
    var rowDiff = a.y - b.y;
    if (Math.abs(rowDiff) > 20) return rowDiff;
    return a.x - b.x;
  });
}

async function selectElementsWithAI(routerEndpoint, frameName, userPrompt, rawEls, language) {
  annotateDuplicateText(rawEls);
  annotateActionToolbarIcons(rawEls);
  var listText = rawEls.map(formatElForAI).join("\n");
  var user =
    'Frame: "' + frameName + '"\n' +
    "=== Mo ta nguoi dung (doc va hieu toan bo, khong co dinh format) ===\n" +
    userPrompt +
    "\n\n=== Danh sach node trong frame (CHI duoc chon nodeId co trong list) ===\n" +
    listText +
    "\n\nNhiem vu cua ban:\n" +
    "1. Tu phan tich mo ta: moi yeu cau danh so -> 1 phan tu JSON (co the nhieu dong, nhieu so 10/20/30...)\n" +
    "2. Chon nodeId khop text/label/name/icon/button theo y nguia tung dong mo ta\n" +
    "3. number: lay DUNG so user yeu cau — STRING trong JSON (vd. \"11.1.1\", \"11.1.2\"). KHONG rut gon 11.1.1 thanh 11.1\n" +
    "4. text= uu tien khop chinh xac; khong chon text dai hon/khac (vd クライアント名 vs クライアント名で検索)\n" +
    "5. Khi trung text (dup 1/2...): dung path, box, center, vi tri de chon dung cot/control\n" +
    "6. Icon/checkbox/delete: chon role=icon; dung toolbarPos=1/8,2/8... de chon icon trong cot アクション/action\n" +
    "7. Dong 11.1-11.8: BAT BUOC 8 icon rieng trong toolbar cot アクション (keo trai->phai), KHONG gop thanh 1 node\n" +
    "8. Popup/modal: moi dong 1.1, 1.2... la 1 node rieng (title, X, label, input, Cancel, Create)\n" +
    "9. Button: chon theo name/label/text gan nhat\n\n" +
    'Tra ve ONLY JSON:\n{"elements":[{"nodeId":"...","number":"11.1.1","label":"mo ta ngan","type":"TEXT"}]}';

  var sys = language === "ja" ? AI_SELECT_SYSTEM_JA : AI_SELECT_SYSTEM_VI;
  var jsonText = await callClaudeApi(routerEndpoint, sys, user);
  var parsed = parseClaudeJson(jsonText);
  if (!parsed.elements || !parsed.elements.length) {
    throw new Error("AI khong tim thay element phu hop voi mo ta.");
  }
  var mapped = mapAiElements(rawEls, parsed.elements);
  if (!mapped.length) {
    throw new Error("AI tra nodeId khong co trong frame. Thu mo ta ro hon hoac chon lai frame.");
  }
  mapped = applyPromptNumbersToMapped(userPrompt, mapped);
  return mapped;
}

function splitPromptByExistingElements(userPrompt, prevElements) {
  var lines = parseNumberedLinesFromPrompt(userPrompt);
  if (!lines.length) return { kept: [], newPrompt: userPrompt, hasNew: true };

  var prevByNumber = {};
  for (var i = 0; i < prevElements.length; i++) {
    var pe = prevElements[i];
    var num = pe.number && normalizeItemNumber(pe.number);
    if (num && num !== "—" && pe.id) prevByNumber[num] = pe;
  }

  var kept = [];
  var newLines = [];
  for (var j = 0; j < lines.length; j++) {
    var line = lines[j];
    if (prevByNumber[line.number]) {
      kept.push(prevByNumber[line.number]);
    } else {
      newLines.push(line.number + ". " + line.hint);
    }
  }
  return {
    kept: kept,
    newPrompt: newLines.join("\n"),
    hasNew: newLines.length > 0,
  };
}

async function resolveElementsFromPrompt(routerEndpoint, frameName, userPrompt, rawEls, language, frameWidth, textElsForMatch) {
  var matchPool = textElsForMatch && textElsForMatch.length ? textElsForMatch : rawEls;
  var local = localResolveElementsFromPrompt(userPrompt, matchPool, frameWidth);
  if (local && local.elements && local.elements.length) {
    var suffix = local.elements.length + "/" + local.total;
    if (local.miss > 0) suffix += " (thieu " + local.miss + ")";
    return { elements: local.elements, method: local.method + " (" + suffix + ")" };
  }

  postProgress("ai", "Claude Code (" + ROUTER_MODEL + ") dang doc mo ta va chon element...");
  var aiElements = await selectElementsWithAI(routerEndpoint, frameName, userPrompt, rawEls, language);
  return { elements: aiElements, method: "Claude Code AI" };
}

async function buildPreviewElements(frame, elements, markerOpts) {
  var ctx = getDrawContext(frame);
  var placed = await resolveElementsForDraw(ctx.root, ctx.coord, elements, markerOpts);
  return placed.map(function(el) {
    var cx = typeof el.centerX === "number" && !isNaN(el.centerX) ? Math.round(el.centerX) : null;
    var cy = typeof el.centerY === "number" && !isNaN(el.centerY) ? Math.round(el.centerY) : null;
    return {
      id: el.id,
      number: el.number,
      name: el.name,
      type: el.type,
      text: el.text || "",
      parentPath: el.parentPath || "",
      x: el.x,
      y: el.y,
      width: el.width,
      height: el.height,
      centerX: cx,
      centerY: cy,
      markerOn: el.markerOn || el.name,
    };
  });
}

// --- Basic Design spec draft (numbered items only) ---

async function callClaudeApiSpec(routerEndpoint, system, user) {
  return callRouterApi(
    routerEndpoint, system, user, SPEC_GENERATION_MAX_TOKENS, ROUTER_SPEC_TIMEOUT_MS
  );
}

function compactBbox(bbox) {
  if (!bbox) return undefined;
  return Math.round(bbox.x) + "," + Math.round(bbox.y) + "," +
    Math.round(bbox.width) + "x" + Math.round(bbox.height);
}

function trimPath(path) {
  if (!path) return undefined;
  var parts = path.split(" > ");
  return parts.length > 2 ? parts.slice(-2).join(" > ") : path;
}

function buildSpecUserPrompt(payload) {
  var itemPayload = payload.numberedItems.map(function(it) {
    return {
      no: it.no,
      elementText: it.text || it.label,
      elementType: it.itemType,
      layerName: it.parentName,
      parentPath: trimPath(it.path),
      bbox: compactBbox(it.bbox),
      nearbyTexts: (it.nearbyTexts || []).slice(0, 4),
      section: it.section || it.groupHint || "",
      detectedRole: it.detectedRole,
    };
  });
  var user =
    "Screen name: " + (payload.screenTitle || payload.frameName) + "\n" +
    "Frame name: " + payload.frameName + "\n\n";
  if (payload.businessContext) {
    user += formatBusinessContextForPrompt(payload.businessContext);
  }
  user +=
    "Numbered UI elements:\n" + JSON.stringify(itemPayload) + "\n\n" +
    "Generate Basic Design item definitions for ALL numbered elements above.\n" +
    "Output JSON only. No markdown. Follow the schema exactly.\n" +
    "If behavior is not visible from UI, infer conservatively and write 要確認 in comment.";
  return user;
}

async function generateBasicDesignSpecDocument(routerEndpoint, payload) {
  var items = payload.numberedItems.slice().sort(function(a, b) {
    return numberSortKey(a.no) - numberSortKey(b.no);
  });
  var batchSize = SPEC_AI_BATCH_SIZE;
  var totalBatches = Math.max(1, Math.ceil(items.length / batchSize));
  var allAiItems = [];

  for (var start = 0; start < items.length; start += batchSize) {
    var batchIndex = Math.floor(start / batchSize) + 1;
    var batchItems = items.slice(start, start + batchSize);
    var batchPayload = Object.assign({}, payload, { numberedItems: batchItems });
    if (totalBatches > 1) {
      postProgress(
        "spec",
        "Claude Code viet spec (" + batchIndex + "/" + totalBatches + ", " + batchItems.length + " item)..."
      );
    }
    var user = buildSpecUserPrompt(batchPayload);
    if (totalBatches > 1) {
      user +=
        "\n\nNote: Batch " + batchIndex + "/" + totalBatches + " for the same screen. " +
        "Generate specs ONLY for the numbered elements in this batch.\n";
    }
    var jsonText = await callClaudeApiSpec(routerEndpoint, SPEC_SYSTEM_PROMPT, user);
    var parsed = parseClaudeJson(jsonText);
    var got = (parsed && parsed.items && parsed.items.length) ? parsed.items.slice() : [];
    if (!got.length && parsed && parsed.sections) {
      for (var si = 0; si < parsed.sections.length; si++) {
        got = got.concat(parsed.sections[si].items || []);
      }
    }
    allAiItems = allAiItems.concat(got);
  }

  return buildSpecDocument(payload, {
    items: allAiItems,
    screenTitle: payload.screenTitle || payload.frameName,
  });
}

function inferScreenTitle(items, frameName) {
  for (var i = 0; i < items.length; i++) {
    var it = items[i];
    var t = (it.itemType || it.role || "").toLowerCase();
    if (t === "screen_title" || t === "section_title") {
      return (it.label || it.text || "").trim() || frameName;
    }
  }
  var sorted = items.slice().sort(function(a, b) { return (a.y || 0) - (b.y || 0); });
  for (var j = 0; j < sorted.length; j++) {
    var txt = (sorted[j].text || sorted[j].label || "").trim();
    if (txt && txt.length >= 2 && txt.length <= 60) return txt;
  }
  return frameName || "";
}

function bboxDistance(a, b) {
  var ax = (a.x || 0) + (a.width || 0) / 2;
  var ay = (a.y || 0) + (a.height || 0) / 2;
  var bx = (b.x || 0) + (b.width || 0) / 2;
  var by = (b.y || 0) + (b.height || 0) / 2;
  return Math.sqrt((ax - bx) * (ax - bx) + (ay - by) * (ay - by));
}

function attachNearbyTexts(items, contextPool) {
  var pool = contextPool || [];
  for (var i = 0; i < items.length; i++) {
    var item = items[i];
    var nearby = [];
    for (var j = 0; j < pool.length; j++) {
      var c = pool[j];
      if (c.nodeId === item.nodeId) continue;
      var t = (c.text || c.label || "").trim();
      if (!t || t.length > 80) continue;
      if (bboxDistance(item, c) <= NEARBY_TEXT_MAX_DIST) nearby.push(t);
    }
    nearby = nearby.filter(function(v, idx, arr) { return arr.indexOf(v) === idx; });
    item.nearbyTexts = nearby.slice(0, NEARBY_TEXT_LIMIT);
  }
}

function attachContextNeighbors(items) {
  var sorted = items.slice().sort(function(a, b) {
    var row = (a.y || 0) - (b.y || 0);
    if (Math.abs(row) > READING_ORDER_ROW_PX) return row;
    return (a.x || 0) - (b.x || 0);
  });
  for (var i = 0; i < sorted.length; i++) {
    var before = [];
    var after = [];
    for (var b = Math.max(0, i - 2); b < i; b++) {
      var t1 = (sorted[b].label || sorted[b].text || "").trim();
      if (t1) before.push(t1);
    }
    for (var a = i + 1; a < Math.min(sorted.length, i + 3); a++) {
      var t2 = (sorted[a].label || sorted[a].text || "").trim();
      if (t2) after.push(t2);
    }
    sorted[i].contextBefore = before;
    sorted[i].contextAfter = after;
  }
  var byId = {};
  for (var k = 0; k < sorted.length; k++) byId[sorted[k].nodeId] = sorted[k];
  for (var m = 0; m < items.length; m++) {
    var enriched = byId[items[m].nodeId];
    if (enriched) {
      items[m].contextBefore = enriched.contextBefore || [];
      items[m].contextAfter = enriched.contextAfter || [];
    }
  }
}

function isFigmaCompoundLayerPath(path) {
  return /(?:background|overlay|border|shadow|blur|paragraph)\+/i.test(path || "");
}

function isLikelyAddIconCandidate(candidate) {
  var label = ((candidate.text || "") + " " + (candidate.name || "")).trim().toLowerCase();
  var path = (candidate.path || "").toLowerCase();
  var itemType = (candidate.itemType || candidate.type || "").toLowerCase();

  if (/行追加|追加行|行を追加|add\s*row|row\s*add/.test(label)) return true;
  if (/\bplus\b/.test(label)) return true;
  if (/^\+$|^\+\s*$/.test(label)) return true;
  if (/追加|プラス/.test(label) && (itemType === "icon" || itemType === "button")) return true;

  if (isFigmaCompoundLayerPath(path)) return false;

  var leaf = path.split(" > ").pop() || "";
  if (/^(add|plus|icon-add|add-icon|行追加)/i.test(leaf)) return true;
  if (/\b(add|plus)\b/.test(path) || /\b(add|plus)\b/.test(leaf)) return true;
  return false;
}

function detectElementRole(candidate) {
  var labelText = ((candidate.text || "") + " " + (candidate.name || "")).toLowerCase();
  var text = (labelText + " " + (candidate.path || "")).toLowerCase();

  if (labelText.indexOf("保存") >= 0) return "save_button";
  if (labelText.indexOf("キャンセル") >= 0) return "cancel_button";
  if (labelText.indexOf("削除") >= 0 || labelText.indexOf("trash") >= 0 || labelText.indexOf("delete") >= 0) return "delete_icon";
  if (isLikelyAddIconCandidate(candidate)) return "add_icon";
  if (text.indexOf("ipアドレス") >= 0 || text.indexOf("ip address") >= 0) return "ip_address_input";
  if (text.indexOf("名称") >= 0) return "name_input";
  if (/\bno\.?\b/.test(text) || text === "no" || text.indexOf("連番") >= 0) return "table_no";
  if (text.indexOf("パンくず") >= 0 || text.indexOf("breadcrumb") >= 0) return "breadcrumb";
  if (text.indexOf("toggle") >= 0 || text.indexOf("switch") >= 0) return "toggle";
  if ((text.indexOf("有効") >= 0 && text.indexOf("無効") >= 0) || text.indexOf("on/off") >= 0) return "toggle";
  var itemType = (candidate.type || candidate.itemType || "").toLowerCase();
  if (itemType === "breadcrumb") return "breadcrumb";
  if (itemType === "screen_title" || itemType === "section_title") return "title";
  if (itemType === "table_column_header") return "table_header";
  if (itemType === "button") return "button";
  if (itemType === "input") return "input";
  if (itemType === "icon") return "icon";
  return itemType || "unknown";
}

function normalizeNumberedItemForSpec(el, index) {
  var path = el.parentPath || el.path || "";
  var parts = path.split(" > ");
  var label = (el.label || el.text || el.name || "").trim();
  var itemType = el.itemType || el.role || el.type || "unknown";
  var detectedRole = detectElementRole({
    text: (el.text || "") + " " + label,
    name: el.name || parts[parts.length - 1] || "",
    path: path,
    type: itemType,
    itemType: itemType,
  });
  return {
    no: el.number != null ? el.number : String(index + 1),
    nodeId: el.id || el.nodeId || "",
    label: label,
    text: (el.text || "").trim(),
    itemType: itemType,
    detectedRole: detectedRole,
    path: path,
    parentName: parts.length ? parts[parts.length - 1] : "",
    groupHint: el.groupHint || "",
    section: el.groupHint || (parts.length > 1 ? parts[parts.length - 2] : ""),
    tableRoleHint: el.tableRoleHint || "",
    bbox: { x: el.x, y: el.y, width: el.width, height: el.height },
    x: el.x, y: el.y,
    width: el.width, height: el.height,
    contextBefore: el.contextBefore || [],
    contextAfter: el.contextAfter || [],
    nearbyTexts: el.nearbyTexts || [],
    confidence: typeof el.confidence === "number" ? el.confidence : null,
    reason: el.aiReason || el.reason || "",
  };
}

function buildSpecAiPayload(frameName, screenTitle, items, language) {
  var normalized = items.map(normalizeNumberedItemForSpec);
  attachContextNeighbors(normalized);
  return {
    frameName: frameName,
    screenTitle: screenTitle || frameName,
    language: language === "ja" ? "ja-vn" : "ja-vn",
    numberedItems: normalized,
  };
}

function mapItemTypeToExcelType(itemType, path, detectedRole) {
  var role = (detectedRole || "").toLowerCase();
  if (role === "toggle") return "Toggle";
  if (role === "save_button" || role === "cancel_button" || role === "button") return "Button";
  if (role === "delete_icon" || role === "add_icon" || role === "icon") return "Icon Button";
  if (role === "ip_address_input" || role === "name_input" || role === "input") return "Input";
  if (role === "table_header" || role === "table_no") return "Table Header";
  if (role === "breadcrumb") return "Breadcrumb";
  if (role === "title") return "Title";
  var t = (itemType || "").toLowerCase();
  var p = (path || "").toLowerCase();
  if (t === "input" || /textfield|textbox/.test(p)) return "Input";
  if (t === "select" || /combobox|dropdown/.test(p)) return "Dropdown";
  if (t === "checkbox") return "Checkbox";
  if (t === "radio") return "Radio";
  if (t === "button") return "Button";
  if (t === "icon") return "Icon Button";
  if (t === "table_column_header" || t === "table_row_header") return "Table Header";
  if (t === "breadcrumb") return "Breadcrumb";
  if (t === "screen_title" || t === "section_title") return "Title";
  if (t === "label") return "Label";
  return "Label";
}

function assignSectionKey(item, frameHeight) {
  var t = (item.itemType || "").toLowerCase();
  var gh = (item.groupHint || "").toLowerCase();
  var path = (item.path || "").toLowerCase();
  var y = item.y || 0;
  var h = frameHeight || 800;
  if (gh === "breadcrumb" || t === "breadcrumb" || t === "screen_title" || t === "section_title") {
    return "header";
  }
  if (t === "table_column_header" || t === "table_row_header" || /table|一覧|list|grid/.test(path)) {
    return "table";
  }
  if (/button|icon/.test(t)) {
    if (y > h * 0.42) return "table";
    return "operation";
  }
  if (/input|select|checkbox|radio/.test(t) || (t === "label" && y < h * 0.45)) {
    return "search";
  }
  if (y < h * 0.2) return "header";
  if (y > h * 0.55) return "table";
  return "other";
}

function buildFallbackItemSpec(item) {
  var label = (item.label || item.text || "").trim() || "項目";
  var itemType = (item.itemType || "unknown").toLowerCase();
  var path = (item.path || "").toLowerCase();
  var role = item.detectedRole || detectElementRole({
    text: (item.text || "") + " " + label,
    name: item.parentName || "",
    path: item.path || "",
    type: itemType,
    itemType: itemType,
  });
  var dash = "-";
  var spec = {
    no: item.no,
    nodeId: item.nodeId || "",
    itemNameJP: label,
    itemNameVN: label,
    type: mapItemTypeToExcelType(itemType, path, role),
    status: "New",
    required: dash,
    maxlength: dash,
    defaultValue: dash,
    table: dash,
    field: dash,
    descriptionJP: "",
    descriptionVN: "",
    comment: "",
    figmaNodePath: item.path || "",
    confidence: 0.6,
  };

  if (role === "save_button") {
    var fbSave = SPEC_FALLBACK.save_button;
    spec.itemNameJP = label.indexOf("保存") >= 0 ? label : fbSave.itemNameJP;
    spec.itemNameVN = fbSave.itemNameVN;
    spec.type = fbSave.type;
    spec.descriptionJP = fbSave.descriptionJP;
    spec.descriptionVN = fbSave.descriptionVN;
    spec.comment = fbSave.comment;
    return spec;
  }
  if (role === "cancel_button") {
    var fbCancel = SPEC_FALLBACK.cancel_button;
    spec.itemNameJP = label.indexOf("キャンセル") >= 0 ? label : fbCancel.itemNameJP;
    spec.itemNameVN = fbCancel.itemNameVN;
    spec.type = fbCancel.type;
    spec.descriptionJP = fbCancel.descriptionJP;
    spec.descriptionVN = fbCancel.descriptionVN;
    spec.comment = fbCancel.comment;
    return spec;
  }
  if (role === "toggle") {
    var fbToggle = SPEC_FALLBACK.toggle;
    spec.itemNameJP = /ip/i.test(label) ? fbToggle.itemNameJP_ip : (label + fbToggle.itemNameJPSuffix);
    spec.itemNameVN = /ip/i.test(label) ? fbToggle.itemNameVN_ip : (fbToggle.itemNameVNPrefix + label);
    spec.type = fbToggle.type;
    spec.defaultValue = fbToggle.defaultValue;
    spec.descriptionJP = fbToggle.descriptionJP;
    spec.descriptionVN = fbToggle.descriptionVN;
    spec.comment = fbToggle.comment;
    return spec;
  }
  if (role === "delete_icon") {
    var fbDelete = SPEC_FALLBACK.delete_icon;
    spec.itemNameJP = fbDelete.itemNameJP;
    spec.itemNameVN = fbDelete.itemNameVN;
    spec.type = fbDelete.type;
    spec.descriptionJP = fbDelete.descriptionJP;
    spec.descriptionVN = fbDelete.descriptionVN;
    spec.comment = fbDelete.comment;
    return spec;
  }
  if (role === "add_icon") {
    var fbAdd = SPEC_FALLBACK.add_icon;
    spec.itemNameJP = fbAdd.itemNameJP;
    spec.itemNameVN = fbAdd.itemNameVN;
    spec.type = fbAdd.type;
    spec.descriptionJP = fbAdd.descriptionJP;
    spec.descriptionVN = fbAdd.descriptionVN;
    spec.comment = fbAdd.comment;
    return spec;
  }
  if (role === "ip_address_input") {
    var fbIp = SPEC_FALLBACK.ip_address_input;
    spec.itemNameJP = fbIp.itemNameJP;
    spec.itemNameVN = fbIp.itemNameVN;
    spec.type = fbIp.type;
    spec.required = fbIp.required;
    spec.maxlength = fbIp.maxlength;
    var ipDefault = (item.text || item.label || "").trim();
    if (/^\d{1,3}(\.\d{1,3}){3}/.test(ipDefault)) spec.defaultValue = ipDefault;
    spec.descriptionJP = fbIp.descriptionJP;
    spec.descriptionVN = fbIp.descriptionVN;
    spec.comment = fbIp.comment;
    return spec;
  }
  if (role === "name_input") {
    var fbName = SPEC_FALLBACK.name_input;
    spec.itemNameJP = fbName.itemNameJP;
    spec.itemNameVN = fbName.itemNameVN;
    spec.type = fbName.type;
    spec.descriptionJP = fbName.descriptionJP;
    spec.descriptionVN = fbName.descriptionVN;
    spec.comment = fbName.comment;
    return spec;
  }
  if (role === "table_no") {
    var fbTableNo = SPEC_FALLBACK.table_no;
    spec.itemNameJP = fbTableNo.itemNameJP;
    spec.itemNameVN = fbTableNo.itemNameVN;
    spec.type = fbTableNo.type;
    spec.descriptionJP = fbTableNo.descriptionJP;
    spec.descriptionVN = fbTableNo.descriptionVN;
    return spec;
  }
  if (role === "breadcrumb") {
    var fbCrumb = SPEC_FALLBACK.breadcrumb;
    spec.type = fbCrumb.type;
    spec.descriptionJP = fbCrumb.descriptionJP;
    spec.descriptionVN = fbCrumb.descriptionVN;
    spec.comment = fbCrumb.comment;
    return spec;
  }
  if (role === "title") {
    var fbTitle = SPEC_FALLBACK.title;
    spec.type = fbTitle.type;
    spec.defaultValue = label;
    spec.descriptionJP = fbTitle.descriptionJP;
    spec.descriptionVN = fbTitle.descriptionVN;
    return spec;
  }
  if (role === "table_header" || itemType === "table_column_header") {
    var fbCol = SPEC_FALLBACK.table_column_header;
    spec.type = fbCol.type;
    spec.descriptionJP = fbCol.descriptionJPPrefix + label + fbCol.descriptionJPSuffix;
    spec.descriptionVN = fbCol.descriptionVNPrefix + label + fbCol.descriptionVNSuffix;
    return spec;
  }
  if (itemType === "table_row_header") {
    var fbRow = SPEC_FALLBACK.table_row_header;
    spec.type = fbRow.type;
    spec.descriptionJP = fbRow.descriptionJPPrefix + label + fbRow.descriptionJPSuffix;
    spec.descriptionVN = fbRow.descriptionVNPrefix + label + fbRow.descriptionVNSuffix;
    return spec;
  }
  if (itemType === "input" || role === "input") {
    var fbInput = SPEC_FALLBACK.input;
    spec.type = fbInput.type;
    spec.descriptionJP = label + fbInput.descriptionJPSuffix;
    spec.descriptionVN = fbInput.descriptionVNPrefix + label + fbInput.descriptionVNSuffix;
    spec.comment = fbInput.comment;
    return spec;
  }
  if (itemType === "select") {
    var fbSelect = SPEC_FALLBACK.select;
    spec.type = fbSelect.type;
    spec.descriptionJP = label + fbSelect.descriptionJPSuffix;
    spec.descriptionVN = fbSelect.descriptionVNPrefix + label + fbSelect.descriptionVNSuffix;
    spec.comment = fbSelect.comment;
    return spec;
  }
  if (itemType === "checkbox") {
    var fbCheckbox = SPEC_FALLBACK.checkbox;
    spec.type = fbCheckbox.type;
    spec.required = fbCheckbox.required;
    spec.descriptionJP = label + fbCheckbox.descriptionJPSuffix;
    spec.descriptionVN = fbCheckbox.descriptionVNPrefix + label + fbCheckbox.descriptionVNSuffix;
    return spec;
  }
  if (itemType === "radio") {
    var fbRadio = SPEC_FALLBACK.radio;
    spec.type = fbRadio.type;
    spec.descriptionJP = label + fbRadio.descriptionJPSuffix;
    spec.descriptionVN = fbRadio.descriptionVNPrefix + label + fbRadio.descriptionVNSuffix;
    return spec;
  }
  if (itemType === "button" || role === "button") {
    var fbButton = SPEC_FALLBACK.button;
    spec.type = fbButton.type;
    spec.descriptionJP = fbButton.descriptionJPPrefix + label + fbButton.descriptionJPSuffix;
    spec.descriptionVN = fbButton.descriptionVNPrefix + label + fbButton.descriptionVNSuffix;
    spec.comment = fbButton.comment;
    return spec;
  }
  if (itemType === "icon" || role === "icon") {
    if (/delete|trash|remove|削除/.test(path)) {
      return buildFallbackItemSpec(Object.assign({}, item, { detectedRole: "delete_icon" }));
    }
    if (isLikelyAddIconCandidate({ text: item.text, name: item.parentName, path: item.path, itemType: itemType, type: itemType })) {
      return buildFallbackItemSpec(Object.assign({}, item, { detectedRole: "add_icon" }));
    }
    var fbIcon = SPEC_FALLBACK.icon_generic;
    spec.type = fbIcon.type;
    spec.descriptionJP = fbIcon.descriptionJP;
    spec.descriptionVN = fbIcon.descriptionVN;
    spec.comment = fbIcon.comment;
    return spec;
  }
  var fbDefault = SPEC_FALLBACK.default;
  spec.descriptionJP = label + fbDefault.descriptionJPSuffix;
  spec.descriptionVN = fbDefault.descriptionVNPrefix + label + fbDefault.descriptionVNSuffix;
  spec.comment = fbDefault.comment;
  return spec;
}

function mergeAiItemSpec(item, ai) {
  var row = buildFallbackItemSpec(item);
  if (!ai) return row;
  row.itemNameJP = ai.itemNameJP || ai.elementName || row.itemNameJP;
  row.itemNameVN = ai.itemNameVN || row.itemNameVN;
  row.type = ai.type || row.type;
  row.status = ai.status != null ? ai.status : row.status;
  row.required = ai.required != null ? ai.required : row.required;
  row.maxlength = ai.maxlength != null ? ai.maxlength : row.maxlength;
  row.defaultValue = ai.default != null ? ai.default : (ai.defaultValue != null ? ai.defaultValue : row.defaultValue);
  row.table = ai.table != null ? ai.table : row.table;
  row.field = ai.field != null ? ai.field : row.field;
  row.descriptionJP = ai.descriptionJP || ai.description || row.descriptionJP;
  row.descriptionVN = ai.descriptionVN || row.descriptionVN;
  row.comment = ai.comment != null ? ai.comment : row.comment;
  row.figmaNodePath = ai.figmaNodePath || item.path || row.figmaNodePath;
  if (typeof ai.confidence === "number") row.confidence = ai.confidence;
  return row;
}

function groupItemsIntoSections(payloadItems, frameHeight) {
  var buckets = { header: [], search: [], operation: [], table: [], other: [] };
  for (var i = 0; i < payloadItems.length; i++) {
    var item = payloadItems[i];
    var key = assignSectionKey(item, frameHeight);
    if (!buckets[key]) buckets[key] = [];
    buckets[key].push(item);
  }
  var order = ["header", "search", "operation", "table", "other"];
  var sections = [];
  for (var o = 0; o < order.length; o++) {
    var k = order[o];
    var list = buckets[k];
    if (!list || !list.length) continue;
    list.sort(function(a, b) {
      var row = (a.y || 0) - (b.y || 0);
      if (Math.abs(row) > READING_ORDER_ROW_PX) return row;
      return (a.x || 0) - (b.x || 0);
    });
    var meta = SECTION_META[k];
    var items = [];
    for (var j = 0; j < list.length; j++) {
      items.push(mergeAiItemSpec(list[j], null));
    }
    sections.push({
      sectionNo: meta.sectionNo,
      sectionNameJP: meta.sectionNameJP,
      sectionNameVN: meta.sectionNameVN,
      items: items,
    });
  }
  return sections;
}

function indexAiSpecItems(parsed) {
  var byNo = {};
  if (!parsed) return byNo;
  var flatItems = parsed.items || [];
  for (var f = 0; f < flatItems.length; f++) {
    var fit = flatItems[f];
    if (fit.no != null) byNo[String(fit.no)] = fit;
  }
  var sections = parsed.sections || [];
  for (var s = 0; s < sections.length; s++) {
    var items = sections[s].items || [];
    for (var i = 0; i < items.length; i++) {
      var it = items[i];
      if (it.no != null) byNo[String(it.no)] = it;
    }
  }
  (parsed.specs || []).forEach(function(legacy) {
    if (legacy.no != null) byNo[String(legacy.no)] = legacy;
  });
  return byNo;
}

function buildSpecDocument(payload, parsed) {
  var frameHeight = 0;
  for (var i = 0; i < payload.numberedItems.length; i++) {
    var bottom = (payload.numberedItems[i].y || 0) + (payload.numberedItems[i].height || 0);
    if (bottom > frameHeight) frameHeight = bottom;
  }
  if (!frameHeight) frameHeight = 800;

  var aiByNo = indexAiSpecItems(parsed || {});
  var aiSections = (parsed && parsed.sections) ? parsed.sections : null;
  var aiFlatItems = (parsed && parsed.items && parsed.items.length) ? parsed.items : null;
  var screenTitle = (parsed && parsed.screenTitle) || payload.screenTitle || payload.frameName;

  if (aiFlatItems && aiFlatItems.length && !aiSections) {
    var flatMerged = [];
    var sortedPayload = payload.numberedItems.slice().sort(function(a, b) {
      return numberSortKey(a.no) - numberSortKey(b.no);
    });
    for (var fi = 0; fi < sortedPayload.length; fi++) {
      var fpItem = sortedPayload[fi];
      flatMerged.push(mergeAiItemSpec(fpItem, aiByNo[String(fpItem.no)] || null));
    }
    return {
      screenTitle: screenTitle,
      sections: [{
        sectionNo: 1,
        sectionNameJP: "画面項目",
        sectionNameVN: "Mục màn hình",
        items: flatMerged,
      }],
      frameName: payload.frameName,
    };
  }

  if (aiSections && aiSections.length) {
    var used = {};
    var sections = [];
    for (var si = 0; si < aiSections.length; si++) {
      var sec = aiSections[si];
      var mergedItems = [];
      var srcItems = sec.items || [];
      for (var ii = 0; ii < srcItems.length; ii++) {
        var aiItem = srcItems[ii];
        var payloadItem = null;
        for (var pi = 0; pi < payload.numberedItems.length; pi++) {
          if (String(payload.numberedItems[pi].no) === String(aiItem.no)) {
            payloadItem = payload.numberedItems[pi];
            used[String(aiItem.no)] = true;
            break;
          }
        }
        if (payloadItem) mergedItems.push(mergeAiItemSpec(payloadItem, aiItem));
      }
      if (mergedItems.length) {
        sections.push({
          sectionNo: sec.sectionNo != null ? sec.sectionNo : si + 1,
          sectionNameJP: sec.sectionNameJP || SECTION_META.other.sectionNameJP,
          sectionNameVN: sec.sectionNameVN || SECTION_META.other.sectionNameVN,
          items: mergedItems,
        });
      }
    }
    for (var mi = 0; mi < payload.numberedItems.length; mi++) {
      var pit = payload.numberedItems[mi];
      if (used[String(pit.no)]) continue;
      var fb = mergeAiItemSpec(pit, aiByNo[String(pit.no)] || null);
      var sk = assignSectionKey(pit, frameHeight);
      var sm = SECTION_META[sk] || SECTION_META.other;
      var foundSec = null;
      for (var fs = 0; fs < sections.length; fs++) {
        if (sections[fs].sectionNameJP === sm.sectionNameJP) { foundSec = sections[fs]; break; }
      }
      if (!foundSec) {
        foundSec = { sectionNo: sm.sectionNo, sectionNameJP: sm.sectionNameJP, sectionNameVN: sm.sectionNameVN, items: [] };
        sections.push(foundSec);
      }
      foundSec.items.push(fb);
    }
    sections.sort(function(a, b) { return (a.sectionNo || 0) - (b.sectionNo || 0); });
    return { screenTitle: screenTitle, sections: sections, frameName: payload.frameName };
  }

  var localSections = groupItemsIntoSections(payload.numberedItems, frameHeight);
  for (var ls = 0; ls < localSections.length; ls++) {
    var secItems = localSections[ls].items;
    for (var li = 0; li < secItems.length; li++) {
      var pItem = null;
      for (var px = 0; px < payload.numberedItems.length; px++) {
        if (String(payload.numberedItems[px].no) === String(secItems[li].no)) {
          pItem = payload.numberedItems[px];
          break;
        }
      }
      if (pItem) secItems[li] = mergeAiItemSpec(pItem, aiByNo[String(pItem.no)] || null);
    }
  }
  return { screenTitle: screenTitle, sections: localSections, frameName: payload.frameName };
}

function flattenSpecDocument(doc) {
  var rows = [];
  var sections = doc.sections || [];
  for (var s = 0; s < sections.length; s++) {
    var items = sections[s].items || [];
    for (var i = 0; i < items.length; i++) {
      var it = items[i];
      rows.push({
        no: it.no,
        itemNameJP: it.itemNameJP,
        itemNameVN: it.itemNameVN,
        type: it.type,
        status: it.status,
        required: it.required,
        maxlength: it.maxlength,
        defaultValue: it.defaultValue,
        table: it.table,
        field: it.field,
        descriptionJP: it.descriptionJP,
        descriptionVN: it.descriptionVN,
        comment: it.comment || "",
        figmaNodePath: it.figmaNodePath,
        path: it.figmaNodePath,
        confidence: it.confidence,
        sectionNameJP: sections[s].sectionNameJP,
        sectionNameVN: sections[s].sectionNameVN,
      });
    }
  }
  rows.sort(function(a, b) { return numberSortKey(a.no) - numberSortKey(b.no); });
  return rows;
}

function generateLocalSpecDocument(payload) {
  return buildSpecDocument(payload, null);
}

// Export frame PNG (includes __overlay__ markers inside frame)
async function exportFrameWithMarkersPng(frame) {
  var markerCount = getOverlayMarkerCount(frame);
  if (!markerCount) {
    throw new Error("Chua co badge so tren frame. Hay ve so len canvas truoc khi export Excel.");
  }
  var ctx = getDrawContext(frame);
  var exportNode = ctx.root;
  if (!exportNode || !("exportAsync" in exportNode)) {
    throw new Error("Khong export duoc frame (node khong ho tro exportAsync).");
  }
  var scales = [2, 1];
  var lastErr = null;
  for (var i = 0; i < scales.length; i++) {
    try {
      var bytes = await exportNode.exportAsync({
        format: "PNG",
        constraint: { type: "SCALE", value: scales[i] },
      });
      if (bytes.length > FRAME_EXPORT_MAX_BYTES && scales[i] > 1) {
        lastErr = new Error("Anh export qua lon (" + Math.round(bytes.length / 1024) + " KB). Thu scale 1.");
        continue;
      }
      return {
        base64: figma.base64Encode(bytes),
        width: Math.round(exportNode.width * scales[i]),
        height: Math.round(exportNode.height * scales[i]),
        scale: scales[i],
        byteLength: bytes.length,
      };
    } catch (ex) {
      lastErr = ex;
    }
  }
  throw lastErr || new Error("Export anh frame that bai.");
}

async function runGenerateSpec(msg) {
  var routerEndpoint = normalizeRouterEndpoint(msg.routerEndpoint);
  var items = (msg.items || []).filter(function(el) {
    return el && el.enabled !== false && el.number && el.number !== "—";
  });
  if (!items.length) {
    throw new Error("Chua co item da danh so. Quet preview, chon item, roi ve badge hoac giu danh sach da chon.");
  }

  var frame = await resolveExportableFrameById(msg.frameId);
  if (!frame) throw new Error("Frame khong tim thay.");

  var drawCtx = getDrawContext(frame);
  var contextPool = collectElements(drawCtx.positionRoot, "reading").map(function(c) {
    return {
      nodeId: c.id,
      text: c.text || "",
      label: c.label || "",
      x: c.x, y: c.y, width: c.width, height: c.height,
    };
  });

  var payloadItems = items.map(normalizeNumberedItemForSpec);
  attachNearbyTexts(payloadItems, contextPool);
  attachContextNeighbors(payloadItems);

  var payload = {
    frameName: frame.name,
    screenTitle: inferScreenTitle(payloadItems, frame.name),
    language: "ja-vn",
    numberedItems: payloadItems,
    businessContext: normalizeBusinessContext(msg.businessContext),
  };

  if (msg.frameId && payload.businessContext) {
    await saveBusinessContext(msg.frameId, payload.businessContext);
  }

  var specDocument;
  var method = "local_fallback";

  if (msg.useFallbackOnly) {
    postProgress("spec", "Tao spec draft local (fallback)...");
    specDocument = generateLocalSpecDocument(payload);
    method = "local_fallback";
  } else {
    postProgress("spec", "Claude Code (" + ROUTER_MODEL + ") viet Basic Design spec (JP/VN)...");
    specDocument = await generateBasicDesignSpecDocument(routerEndpoint, payload);
    method = "claude_code_ai";
  }

  var specRows = flattenSpecDocument(specDocument);

  return {
    specDocument: specDocument,
    specRows: specRows,
    frameName: frame.name,
    screenTitle: specDocument.screenTitle,
    method: method,
    warning: "",
    itemCount: items.length,
  };
}

function isVisible(node) {
  return node.visible !== false && node.opacity > 0;
}

function isInterestingType(node) {
  var types = ["FRAME","COMPONENT","INSTANCE","GROUP","TEXT","RECTANGLE","ELLIPSE","VECTOR","BOOLEAN_OPERATION","STAR","LINE","POLYGON"];
  return types.indexOf(node.type) !== -1;
}

function isOverlayNode(node) {
  return !!(node && node.name && node.name.indexOf("__overlay__") === 0);
}

async function ensurePageLoaded() {
  if (ensurePageLoaded._done) return;
  try {
    await figma.loadAllPagesAsync();
    ensurePageLoaded._done = true;
  } catch (e) {
    // older API / single page
  }
}

function tryGetNodeByIdSync(nodeId) {
  if (!nodeId) return null;
  try {
    return figma.getNodeById(nodeId);
  } catch (e) {
    return null;
  }
}

function resolveSelectedFrameNodeSync() {
  var sel = figma.currentPage.selection;
  if (!sel.length) return null;

  var node = sel[0];
  if (node.type === "SECTION") {
    var sec = resolveFramesFromSection(node);
    if (!sec.frames.length) return null;
    var fromSec = tryGetNodeByIdSync(sec.frames[0].id);
    return isExportableFrame(fromSec) ? fromSec : null;
  }

  if (isExportableFrame(node)) return node;

  var p = node.parent;
  while (p && p.type !== "PAGE") {
    if (isExportableFrame(p)) return p;
    if (p.type === "SECTION") {
      var sec2 = resolveFramesFromSection(p);
      if (sec2.frames.length) {
        var fromSec2 = tryGetNodeByIdSync(sec2.frames[0].id);
        if (isExportableFrame(fromSec2)) return fromSec2;
      }
    }
    p = p.parent;
  }
  return null;
}

async function resolveFrameNodeQuick(frameId) {
  if (!frameId) return null;
  var syncNode = tryGetNodeByIdSync(frameId);
  if (isExportableFrame(syncNode)) return syncNode;
  try {
    var node = await figma.getNodeByIdAsync(frameId);
    if (isExportableFrame(node)) return node;
  } catch (e) {}
  return resolveExportableFrameById(frameId);
}

function getPageAncestor(node) {
  var p = node;
  while (p) {
    if (p.type === "PAGE") return p;
    p = p.parent;
  }
  return null;
}

async function activatePageForNode(node) {
  var page = getPageAncestor(node);
  if (page && figma.currentPage && figma.currentPage.id !== page.id) {
    await figma.setCurrentPageAsync(page);
  }
}

function buildFigmaFrameUrl(nodeId) {
  var fileKey = figma.fileKey;
  if (!fileKey || !nodeId) return "-";
  return "https://www.figma.com/design/" + fileKey + "?node-id=" + String(nodeId).replace(/:/g, "-");
}

function frameToSelectionInfo(node) {
  var inSection = false;
  var p = node.parent;
  while (p && p.type !== "PAGE") {
    if (p.type === "SECTION") inSection = true;
    p = p.parent;
  }
  return {
    id: node.id,
    name: node.name,
    width: Math.round(node.width),
    height: Math.round(node.height),
    inSection: inSection,
    frameUrl: buildFigmaFrameUrl(node.id),
  };
}

function isScreenSizedFrame(node) {
  return node && node.width >= 320 && node.height >= 200;
}

function findDirectScreenFramesInContainer(container) {
  var screens = [];
  if (!container || !container.children) return screens;
  for (var i = 0; i < container.children.length; i++) {
    var ch = container.children[i];
    if ((ch.type === "FRAME" || ch.type === "COMPONENT" || ch.type === "INSTANCE") &&
        isScreenSizedFrame(ch)) {
      screens.push(ch);
    }
  }
  return screens;
}

function findScreenFramesDeep(container, maxDepth) {
  var screens = [];
  function walk(n, depth) {
    if (!n || depth > maxDepth) return;
    if ((n.type === "FRAME" || n.type === "COMPONENT" || n.type === "INSTANCE") &&
        isScreenSizedFrame(n)) {
      screens.push(n);
      return;
    }
    if (n.children) {
      for (var i = 0; i < n.children.length; i++) walk(n.children[i], depth + 1);
    }
  }
  walk(container, 0);
  return screens;
}

function pickFrameNearViewport(frames) {
  if (!frames.length) return null;
  if (frames.length === 1) return frames[0];
  var center = figma.viewport.center;
  for (var i = 0; i < frames.length; i++) {
    var box = frames[i].absoluteBoundingBox;
    if (box && center.x >= box.x && center.x <= box.x + box.width &&
        center.y >= box.y && center.y <= box.y + box.height) {
      return frames[i];
    }
  }
  return frames[0];
}

function resolveFramesFromSection(sectionNode) {
  var screens = findDirectScreenFramesInContainer(sectionNode);
  if (!screens.length) screens = findScreenFramesDeep(sectionNode, 2);
  var hint = "";
  if (!screens.length) {
    hint = 'Section "' + sectionNode.name + '" khong co Frame man hinh. Chon truc tiep Frame (vd. D1-Home) trong Layers.';
    return { frames: [], hint: hint };
  }
  var picked = pickFrameNearViewport(screens);
  if (screens.length === 1) {
    hint = 'Da lay man hinh trong Section "' + sectionNode.name + '".';
  } else {
    hint = 'Ban chon Section "' + sectionNode.name + '". Plugin chon man hinh gan viewport: "' +
      picked.name + '". Muon man khac: click truc tiep Frame do (khong chon Section).';
  }
  return { frames: [frameToSelectionInfo(picked)], hint: hint };
}

function resolveSelectionFromSel(sel) {
  var frames = [];
  var hint = "";
  var seen = {};

  function addFrameInfo(info) {
    if (!info || seen[info.id]) return;
    seen[info.id] = true;
    frames.push(info);
  }

  for (var i = 0; i < sel.length; i++) {
    var n = sel[i];
    if (n.type === "FRAME" || n.type === "COMPONENT" || n.type === "INSTANCE") {
      addFrameInfo(frameToSelectionInfo(n));
    } else if (n.type === "SECTION") {
      var sec = resolveFramesFromSection(n);
      if (sec.frames.length) addFrameInfo(sec.frames[0]);
      if (sec.hint) hint = sec.hint;
    }
  }

  if (!frames.length && sel.length > 0) {
    var node = sel[0];
    while (node && node.type !== "PAGE") {
      if (node.type === "FRAME" || node.type === "COMPONENT" || node.type === "INSTANCE") {
        addFrameInfo(frameToSelectionInfo(node));
        break;
      }
      if (node.type === "SECTION") {
        var sec2 = resolveFramesFromSection(node);
        if (sec2.frames.length) addFrameInfo(sec2.frames[0]);
        if (sec2.hint) hint = sec2.hint;
        break;
      }
      node = node.parent;
    }
  }

  return { frames: frames, hint: hint };
}

async function findNodeByIdInDocumentAsync(targetId) {
  try {
    var direct = await figma.getNodeByIdAsync(targetId);
    if (direct) return direct;
  } catch (e) {}

  await ensurePageLoaded();
  try {
    var loaded = await figma.getNodeByIdAsync(targetId);
    if (loaded) return loaded;
  } catch (e2) {}

  function walk(n) {
    if (n.id === targetId) return n;
    if (n.children) {
      for (var i = 0; i < n.children.length; i++) {
        var found = walk(n.children[i]);
        if (found) return found;
      }
    }
    return null;
  }

  for (var p = 0; p < figma.root.children.length; p++) {
    var page = figma.root.children[p];
    if (page.type !== "PAGE") continue;
    var foundOnPage = walk(page);
    if (foundOnPage) return foundOnPage;
  }
  return null;
}

async function resolveExportableFrameById(frameId) {
  var node = await findNodeByIdInDocumentAsync(frameId);
  if (!node || !isExportableFrame(node)) return null;
  await activatePageForNode(node);
  return node;
}

function getContentFrameChildren(root) {
  var list = [];
  if (!("children" in root) || !root.children) return list;
  for (var i = 0; i < root.children.length; i++) {
    var ch = root.children[i];
    if (isOverlayNode(ch)) continue;
    if (ch.type === "FRAME" || ch.type === "COMPONENT" || ch.type === "INSTANCE") {
      list.push(ch);
    }
  }
  return list;
}

function isModalLikeFrame(root) {
  if (!root) return false;
  var w = root.width;
  var h = root.height;
  var name = (root.name || "").toLowerCase();
  if (/popup|modal|dialog|sharing|share|共有|ダイアログ|ポップアップ|pop-up|pop up/i.test(name)) return true;
  var kids = getContentFrameChildren(root);
  // Popup/modal: nho, co 2+ frame con (header+body / body+footer)
  if (w >= 260 && w <= 800 && h >= 160 && h <= 680 && kids.length >= 2 && kids.length <= 8) {
    return true;
  }
  return false;
}

function getCoordinateFrame(root) {
  // Modal/popup: overlay + toa do theo frame goc (gom ca footer, header)
  if (isModalLikeFrame(root)) return root;

  var contentKids = getContentFrameChildren(root);
  if (!contentKids.length) return root;

  var best = contentKids[0];
  var bestArea = best.width * best.height;
  for (var j = 1; j < contentKids.length; j++) {
    var area = contentKids[j].width * contentKids[j].height;
    if (area > bestArea) {
      best = contentKids[j];
      bestArea = area;
    }
  }
  // Frame UI con (vd. Frame 1000014278) — tranh dat overlay sibling tren frame auto-layout
  if (best.width >= 50 && best.height >= 50) return best;
  return root;
}

function bringToFront(node) {
  var parent = node.parent;
  if (!parent || !("children" in parent)) return;
  var idx = parent.children.indexOf(node);
  if (idx >= 0 && idx !== parent.children.length - 1) {
    parent.insertChild(parent.children.length - 1, node);
  }
}

function getDrawContext(root) {
  // Overlay + toa do LUON theo frame user chon (root).
  // Tranh loi offset khi frame lon / table / sidebar → so bi day sang phai.
  return {
    root: root,
    coord: root,
    positionRoot: root,
    offsetX: 0,
    offsetY: 0,
  };
}

function applyAbsolutePosition(child, parent) {
  if ("layoutMode" in parent && parent.layoutMode && parent.layoutMode !== "NONE") {
    if ("layoutPositioning" in child) child.layoutPositioning = "ABSOLUTE";
  }
}

function isDescendantOf(node, frame) {
  var p = node;
  while (p) {
    if (p.id === frame.id) return true;
    p = p.parent;
  }
  return false;
}

function positionInFrame(node, frame) {
  if (!node || !frame) return null;

  // Uu tien toa do tuong doi (on dinh trong Instance / Section / modal)
  if (isDescendantOf(node, frame)) {
    var rx = node.x;
    var ry = node.y;
    var cur = node.parent;
    while (cur && cur.id !== frame.id) {
      rx += cur.x;
      ry += cur.y;
      cur = cur.parent;
    }
    if (cur && cur.id === frame.id) {
      return { x: rx, y: ry, width: node.width, height: node.height };
    }
  }

  var frameBox = frame.absoluteBoundingBox;
  var nodeBox = node.absoluteBoundingBox;
  if (frameBox && nodeBox && nodeBox.width > 0 && nodeBox.height > 0) {
    return {
      x: nodeBox.x - frameBox.x,
      y: nodeBox.y - frameBox.y,
      width: nodeBox.width,
      height: nodeBox.height,
    };
  }
  var nodeTr = node.absoluteTransform;
  var frameTr = frame.absoluteTransform;
  if (nodeTr && frameTr) {
    var scaleX = frameTr[0][0] || 1;
    var scaleY = frameTr[1][1] || 1;
    return {
      x: (nodeTr[0][2] - frameTr[0][2]) / scaleX,
      y: (nodeTr[1][2] - frameTr[1][2]) / scaleY,
      width: (node.width || 0),
      height: (node.height || 0),
    };
  }
  return null;
}

function findNodeInFrame(frame, nodeId) {
  if (frame.id === nodeId) return frame;
  var found = null;
  function walk(n) {
    if (found) return;
    if (n.id === nodeId) {
      found = n;
      return;
    }
    if ("children" in n && n.children) {
      for (var i = 0; i < n.children.length; i++) walk(n.children[i]);
    }
  }
  if ("children" in frame && frame.children) {
    for (var c = 0; c < frame.children.length; c++) walk(frame.children[c]);
  }
  return found;
}

function hasValidStoredCoords(el) {
  return typeof el.centerX === "number" && !isNaN(el.centerX) &&
    typeof el.centerY === "number" && !isNaN(el.centerY);
}

function parseMarkerRadius(sizeVal) {
  var n = parseInt(sizeVal, 10);
  if (isNaN(n)) n = 12;
  return Math.max(8, Math.min(22, n));
}

function normalizeMarkerPosition(val) {
  var v = (val || "auto").toLowerCase();
  if (v === "left" || v === "right" || v === "top" || v === "bottom") return v;
  return "auto";
}

function markerOptsFromMsg(msg) {
  return {
    position: normalizeMarkerPosition(msg.markerPosition),
    radius: parseMarkerRadius(msg.markerSize != null ? msg.markerSize : 12),
  };
}

function markerRadiusForFrame(frameWidth, overrideRadius) {
  if (overrideRadius) return overrideRadius;
  return Math.max(10, Math.min(16, (frameWidth || 800) * 0.012));
}

function detectAutoPosition(node, frame, pos, path) {
  if (isTableHeaderContext(path, pos, frame)) return "top";
  if (isButtonLikeNode(node, pos)) return "top";
  if (isCloseIconNode(node, pos)) return "top";
  if (node.type !== "TEXT" && pos.width <= 56 && pos.height <= 56) return "top";
  if (pos.width >= 120 && /textfield|input|search|combobox|select/i.test(path)) return "top";
  if (node.type === "TEXT" && pos.x <= frame.width * 0.42) return "left";
  if (pos.width >= 120 && nodeInHeaderBand(pos, frame)) return "top";
  return "left";
}

function computeMarkerLayout(targetRect, radius, positionHint, autoPos) {
  var gap = 8;
  var tr = targetRect;
  var pos = positionHint === "auto" ? autoPos : positionHint;
  var anchorX, anchorY, badgeX, badgeY, lineStyle;

  function pack(ax, ay, bx, by, ls) {
    return {
      badgeCenterX: bx,
      badgeCenterY: by,
      anchorX: ax,
      anchorY: ay,
      centerX: bx,
      centerY: by,
      targetRect: tr,
      lineStyle: ls,
      drawBox: false,
    };
  }

  if (pos === "right") {
    anchorX = tr.x + tr.width;
    anchorY = tr.y + tr.height / 2;
    badgeX = anchorX + radius + gap;
    badgeY = anchorY;
    return pack(anchorX, anchorY, badgeX, badgeY, "horizontal");
  }
  if (pos === "top") {
    anchorX = tr.x + tr.width / 2;
    anchorY = tr.y;
    badgeX = anchorX;
    badgeY = Math.max(radius + 4, tr.y - radius - gap);
    return pack(anchorX, anchorY, badgeX, badgeY, "vertical");
  }
  if (pos === "bottom") {
    anchorX = tr.x + tr.width / 2;
    anchorY = tr.y + tr.height;
    badgeX = anchorX;
    badgeY = anchorY + radius + gap;
    return pack(anchorX, anchorY, badgeX, badgeY, "vertical");
  }
  // left (default — row label table)
  anchorX = tr.x;
  anchorY = tr.y + tr.height / 2;
  badgeX = Math.max(radius + 4, tr.x - radius - gap);
  badgeY = anchorY;
  return pack(anchorX, anchorY, badgeX, badgeY, "horizontal");
}

function buildAnnotationSpec(node, frame, pos, markerOpts) {
  markerOpts = markerOpts || { position: "auto", radius: 12 };
  var path = getParentPath(node, frame).toLowerCase();
  var radius = markerRadiusForFrame(frame.width, markerOpts.radius);
  var targetRect = {
    x: pos.x,
    y: pos.y,
    width: Math.max(pos.width, 4),
    height: Math.max(pos.height, 4),
  };
  var autoPos = detectAutoPosition(node, frame, pos, path);
  return computeMarkerLayout(targetRect, radius, markerOpts.position, autoPos);
}

var BD_STROKE_RED = { type: "SOLID", color: { r: 1, g: 0, b: 0 } };
var BD_FILL_RED = { type: "SOLID", color: { r: 0.86, g: 0.08, b: 0.12 } };

function markerBadgeCenter(spec) {
  return {
    centerX: spec.badgeCenterX != null ? spec.badgeCenterX : spec.centerX,
    centerY: spec.badgeCenterY != null ? spec.badgeCenterY : spec.centerY,
  };
}

function isTableHeaderContext(path, pos, frame) {
  if (/table-header|thead|header-cell|column-header|table\/head/i.test(path)) return true;
  return nodeInHeaderBand(pos, frame) && pos.width < frame.width * 0.25;
}

function nodeInHeaderBand(pos, frame) {
  return pos.y < frame.height * 0.38;
}

function markerCoordsFromElement(el, frameWidth, markerOpts) {
  var th = el.height || 24;
  var tw = el.width || 40;
  var ty = typeof el.y === "number" ? el.y : (el.centerY - th / 2);
  var tx = typeof el.x === "number" ? el.x : (el.centerX - tw / 2);
  var pos = { x: tx, y: ty, width: tw, height: th };
  var fakeFrame = { width: frameWidth || 800, height: 1000 };
  var fakeNode = { type: el.type || "TEXT", name: el.name || "", role: el.role || "" };
  return buildAnnotationSpec(fakeNode, fakeFrame, pos, markerOpts);
}

function isButtonLikeNode(node, pos) {
  if (!node || !pos) return false;
  if (pos.height >= 28 && pos.width >= 52) {
    var name = (node.name || "").toLowerCase();
    if (/button|btn|primary|secondary|cancel|submit|共有|キャンセル|作成|export|エクスポート/i.test(name)) return true;
    if (node.type === "INSTANCE" || node.type === "COMPONENT") return true;
  }
  if (node.type === "TEXT") {
    var t = getTextContent(node);
    if (/^(キャンセル|cancel|作成|共有|share|ok|submit|エクスポート|export)$/i.test(t)) return true;
  }
  return false;
}

function isCloseIconNode(node, pos) {
  var name = (node.name || "").toLowerCase();
  if (/close|closed|x-icon|icon.?x|dismiss/i.test(name)) return true;
  if (pos && pos.width <= 48 && pos.height <= 48 && /x|close|閉/i.test(name)) return true;
  return false;
}

function isPlausibleMarker(mp, el, frame) {
  var c = markerBadgeCenter(mp);
  if (typeof c.centerX !== "number" || isNaN(c.centerX)) return false;
  if (c.centerX < 4 && c.centerY < 4 && hasValidStoredCoords(el) &&
      (el.centerY > 25 || el.centerX > 25)) {
    return false;
  }
  var fw = frame.width || 10000;
  var fh = frame.height || 10000;
  if (c.centerX < -40 || c.centerY < -40) return false;
  if (c.centerX > fw + 40 || c.centerY > fh + 40) return false;
  if (typeof el.x === "number" && el.x < fw * 0.55 && c.centerX > fw * 0.72) return false;
  if (typeof el.centerX === "number" && el.centerX < fw * 0.55 && c.centerX > fw * 0.72) return false;
  return true;
}

function shouldExpandTextToParent(node, frame) {
  var path = getParentPath(node, frame).toLowerCase();
  if (path.indexOf("table-header") !== -1 || path.indexOf("table-cell") !== -1) return false;
  if (path.indexOf("table/column") !== -1 || path.indexOf("pagination") !== -1) return false;
  return path.indexOf("textfield") !== -1 || path.indexOf("input") !== -1 ||
    path.indexOf("<textfield>") !== -1 || path.indexOf("button") !== -1;
}

function markerExpandCapArea(frame) {
  var fw = frame.width || 800;
  var fh = frame.height || 600;
  return fw * fh * 0.35;
}

function isMarkerControlContainer(node) {
  if (!node) return false;
  var name = (node.name || "").toLowerCase();
  return /button|btn|tab|link|input|options|textfield|select|combobox|textarea/i.test(name);
}

function getMarkerNode(node, frame) {
  if (node.type !== "TEXT") return node;
  if (!shouldExpandTextToParent(node, frame)) return node;

  var capArea = markerExpandCapArea(frame);
  var best = node;
  var bestArea = node.width * node.height;
  var parent = node.parent;
  var depth = 0;

  while (parent && parent.id !== frame.id && depth < 6) {
    var isContainer = parent.type === "INSTANCE" || parent.type === "FRAME" ||
      parent.type === "COMPONENT" || parent.type === "GROUP";
    if (!isContainer || parent.width < 40 || parent.height < 20) {
      parent = parent.parent;
      depth++;
      continue;
    }

    var area = parent.width * parent.height;
    if (area > capArea) break;

    if (isMarkerControlContainer(parent)) {
      return parent;
    }

    if (area > bestArea * 2) {
      best = parent;
      bestArea = area;
    }

    parent = parent.parent;
    depth++;
  }
  return best;
}

function markerPosition(markerNode, textNode, frame, markerOpts) {
  var textPos = positionInFrame(textNode, frame);
  if (!textPos) return null;
  var usePos = textPos;
  if (markerNode.id !== textNode.id) {
    var boxPos = positionInFrame(markerNode, frame);
    if (boxPos) usePos = boxPos;
  }
  return buildAnnotationSpec(markerNode, frame, usePos, markerOpts);
}

function getTextContent(node) {
  if (node.type !== "TEXT" || !node.characters) return "";
  return node.characters.replace(/\s+/g, " ").trim();
}

function normalizeIconLabel(name) {
  var n = (name || "").trim();
  if (!n) return "";
  var parts = n.split("/");
  if (parts.length > 1 && /icon|btn|button|component/i.test(parts[0])) {
    return parts[parts.length - 1].trim();
  }
  return n;
}

function isIconLikeNode(node, frame, parentPathForNode) {
  if (!node || !isVisible(node)) return false;
  var w = node.width;
  var h = node.height;
  if (w < 8 || h < 8) return false;
  var okType = node.type === "INSTANCE" || node.type === "COMPONENT" ||
    node.type === "FRAME" || node.type === "GROUP" ||
    node.type === "VECTOR" || node.type === "BOOLEAN_OPERATION" ||
    node.type === "ELLIPSE" || node.type === "RECTANGLE";
  if (!okType) return false;

  var name = node.name || "";
  if (isIconLikeName(name)) {
    if (w <= 96 && h <= 96) return true;
    if (w <= 120 && h <= 48) return true;
  }

  // Icon cot アクション: INSTANCE nho trong path action/table (ten layer co the la emoji/khong co "icon")
  if (frame && w <= 52 && h <= 52) {
    var path = parentPathForNode != null ? parentPathForNode : getParentPath(node, frame);
    if (ACTION_PATH_RE.test(path)) return true;
  }
  return false;
}

function getElementLabel(node) {
  if (node.type === "TEXT") return getTextContent(node);
  return normalizeIconLabel(node.name);
}

function markerPositionForNode(node, frame, markerOpts) {
  var pos = positionInFrame(node, frame);
  if (!pos) return null;

  if (node.type === "TEXT") {
    var markerNode = getMarkerNode(node, frame);
    var mp = markerPosition(markerNode, node, frame, markerOpts);
    if (mp) return mp;
  }
  return buildAnnotationSpec(node, frame, pos, markerOpts);
}

function normalizeParentPathForElement(parentPathForNode) {
  return parentPathForNode ? parentPathForNode : "(root)";
}

function parentPathForChild(parentPathForNode, node) {
  var name = node.name || node.type;
  if (!parentPathForNode || parentPathForNode === "(root)") return name;
  return parentPathForNode + " > " + name;
}

function pushElement(elements, frame, node, pos, extra, parentPathForNode) {
  if (!pos || pos.width <= 0 || pos.height <= 0) return;
  var frameBox = frame.absoluteBoundingBox;
  var frameW = frameBox ? frameBox.width : frame.width;
  var frameH = frameBox ? frameBox.height : frame.height;
  var el = {
    id: node.id,
    name: node.name,
    type: node.type,
    parentPath: parentPathForNode != null
      ? normalizeParentPathForElement(parentPathForNode)
      : getParentPath(node, frame),
    x: pos.x,
    y: pos.y,
    width: pos.width,
    height: pos.height,
    centerX: pos.x + pos.width / 2,
    centerY: pos.y + pos.height / 2,
    xPct: Math.round(((pos.x + pos.width / 2) / frameW) * 100),
    yPct: Math.round(((pos.y + pos.height / 2) / frameH) * 100),
  };
  if (extra) {
    for (var key in extra) el[key] = extra[key];
  }
  elements.push(el);
}

function resolveCollectionScope(screenFrame) {
  var sel = figma.currentPage.selection;
  if (!sel.length) return null;
  var node = sel[0];
  if (!node || node.id === screenFrame.id) return null;
  if (!isDescendantOf(node, screenFrame)) return null;

  var candidate = node;
  var containerTypes = ["FRAME", "GROUP", "COMPONENT", "INSTANCE"];
  if (containerTypes.indexOf(node.type) === -1 && node.parent && isDescendantOf(node.parent, screenFrame)) {
    candidate = node.parent;
  }
  if (containerTypes.indexOf(candidate.type) === -1 || candidate.id === screenFrame.id) return null;

  var area = (candidate.width || 0) * (candidate.height || 0);
  var frameArea = (screenFrame.width || 0) * (screenFrame.height || 0);
  if (area <= 0 || frameArea <= 0 || area >= frameArea * 0.92) return null;

  return { node: candidate, label: candidate.name || candidate.type };
}

function getCollectOptions(screenFrame, options) {
  options = options || {};
  if (options.useScope === false) return null;
  var scope = resolveCollectionScope(screenFrame);
  if (!scope) return null;
  return {
    scanRoot: scope.node,
    coordFrame: screenFrame,
    scopeLabel: scope.label,
  };
}

function dedupCollectedElements(elements) {
  var deduped = [];
  var grid = {};
  for (var d = 0; d < elements.length; d++) {
    var el = elements[d];
    var gx = Math.floor(el.x / 48);
    var gy = Math.floor(el.y / 48);
    var merged = false;
    for (var dx = -1; dx <= 1 && !merged; dx++) {
      for (var dy = -1; dy <= 1 && !merged; dy++) {
        var bucket = grid[(gx + dx) + "," + (gy + dy)];
        if (!bucket) continue;
        for (var bi = 0; bi < bucket.length; bi++) {
          var ex = bucket[bi];
          var ox = Math.max(0, Math.min(el.x + el.width, ex.x + ex.width) - Math.max(el.x, ex.x));
          var oy = Math.max(0, Math.min(el.y + el.height, ex.y + ex.height) - Math.max(el.y, ex.y));
          var overlap = (ox * oy) / Math.min(el.width * el.height, ex.width * ex.height);
          if (overlap > 0.7) {
            if (el.role === "icon" && ex.role !== "icon") bucket[bi] = el;
            else if (el.type === "TEXT" && ex.type !== "TEXT") bucket[bi] = el;
            merged = true;
            break;
          }
        }
      }
    }
    if (!merged) {
      deduped.push(el);
      var key = gx + "," + gy;
      if (!grid[key]) grid[key] = [];
      grid[key].push(el);
    }
  }
  return deduped;
}

function filterTextElementsForMatch(elements) {
  var out = [];
  for (var i = 0; i < elements.length; i++) {
    var el = elements[i];
    if (el.type !== "TEXT" || !el.text || isNumericOnlyText(el.text)) continue;
    out.push(el);
  }
  out.sort(function(a, b) {
    var rowDiff = a.y - b.y;
    if (Math.abs(rowDiff) > 2) return rowDiff;
    return a.x - b.x;
  });
  return out;
}

function collectElements(frame, sortMode, options) {
  options = options || {};
  var coordFrame = options.coordFrame || frame;
  var scanRoot = options.scanRoot || frame;
  var elements = [];
  var textIds = {};
  var collectedIds = {};
  var softCap = (sortMode === "reading" ? AUTO_NUMBER_LIMIT : CANDIDATE_LIMIT) * 3;

  function markCollected(id) {
    collectedIds[id] = true;
    textIds[id] = true;
  }

  function relPos(relX, relY, node) {
    return { x: relX, y: relY, width: node.width, height: node.height };
  }

  function walkUnified(node, depth, relX, relY, parentPathForNode) {
    if (!isVisible(node) || isOverlayNode(node) || depth > 16) return;
    if (elements.length >= softCap) return;

    var pos = relPos(relX, relY, node);
    var childParentPath = parentPathForChild(parentPathForNode, node);
    var blockInstanceDone = false;

    if (node.type === "TEXT" && depth <= 10) {
      var content = getTextContent(node);
      if (content.length > 0 && pos.width >= 4 && pos.height >= 4) {
        pushElement(elements, coordFrame, node, pos, { text: content }, parentPathForNode);
        markCollected(node.id);
      }
      return;
    }

    if (depth <= 4) {
      var hasName = node.name && node.name.charAt(0) !== ".";
      var bigEnough = node.width >= 8 && node.height >= 8;
      var isTopLevel = depth === 1;
      if (bigEnough && isInterestingType(node) && hasName && node.type !== "TEXT") {
        if (isTopLevel || node.type === "INSTANCE" || node.type === "COMPONENT") {
          if (!textIds[node.id]) {
            pushElement(elements, coordFrame, node, pos, null, parentPathForNode);
          }
          if (node.type === "INSTANCE" || node.type === "COMPONENT") {
            if (node.children) {
              for (var ic = 0; ic < node.children.length; ic++) {
                var ich = node.children[ic];
                walkUnified(ich, depth + 1, relX + ich.x, relY + ich.y, childParentPath);
              }
            }
            blockInstanceDone = true;
          }
        } else if (node.children) {
          for (var jb = 0; jb < node.children.length; jb++) {
            var jch = node.children[jb];
            walkUnified(jch, depth + 1, relX + jch.x, relY + jch.y, childParentPath);
          }
          blockInstanceDone = true;
        }
      } else if (node.children && bigEnough) {
        for (var kb = 0; kb < node.children.length; kb++) {
          var kch = node.children[kb];
          walkUnified(kch, depth + 1, relX + kch.x, relY + kch.y, childParentPath);
        }
        blockInstanceDone = true;
      }
    }

    if (depth <= 14 && isIconLikeNode(node, coordFrame, parentPathForNode) && !collectedIds[node.id]) {
      if (pos.width >= 10 && pos.height >= 10) {
        pushElement(elements, coordFrame, node, pos, {
          text: "",
          label: getElementLabel(node),
          role: "icon",
        }, parentPathForNode);
        markCollected(node.id);
      }
    }

    if (depth <= 12 && node.children && node.children.length >= 3) {
      var smallKids = [];
      for (var sk = 0; sk < node.children.length; sk++) {
        var ch = node.children[sk];
        if (!isVisible(ch) || isOverlayNode(ch)) continue;
        if (isIconLikeNode(ch, coordFrame, childParentPath) ||
            ((ch.type === "INSTANCE" || ch.type === "COMPONENT" || ch.type === "FRAME") &&
              ch.width >= 8 && ch.width <= 48 && ch.height >= 8 && ch.height <= 48)) {
          smallKids.push({ node: ch, relX: relX + ch.x, relY: relY + ch.y });
        }
      }
      if (smallKids.length >= 3) {
        smallKids.sort(function(a, b) { return a.relX - b.relX; });
        for (var si = 0; si < smallKids.length; si++) {
          var iconEntry = smallKids[si];
          var iconNode = iconEntry.node;
          if (collectedIds[iconNode.id]) continue;
          var spos = relPos(iconEntry.relX, iconEntry.relY, iconNode);
          if (spos.width >= 8 && spos.height >= 8) {
            pushElement(elements, coordFrame, iconNode, spos, {
              text: "",
              label: getElementLabel(iconNode),
              role: "icon",
            }, childParentPath);
            markCollected(iconNode.id);
          }
        }
      }
    }

    if (depth <= 14 &&
        (node.type === "INSTANCE" || node.type === "COMPONENT" || node.type === "FRAME") &&
        !collectedIds[node.id] && node.width >= 8 && node.width <= 52 &&
        node.height >= 8 && node.height <= 52) {
      if (ACTION_PATH_RE.test(parentPathForNode || "") || isIconLikeName(node.name)) {
        if (pos.width >= 8 && pos.height >= 8) {
          pushElement(elements, coordFrame, node, pos, {
            text: "",
            label: getElementLabel(node),
            role: "icon",
          }, parentPathForNode);
          markCollected(node.id);
        }
      }
    }

    if (blockInstanceDone) return;

    if (node.children) {
      for (var i = 0; i < node.children.length; i++) {
        var child = node.children[i];
        walkUnified(child, depth + 1, relX + child.x, relY + child.y, childParentPath);
      }
    }
  }

  var baseX = 0;
  var baseY = 0;
  var basePath = "(root)";
  if (scanRoot.id !== coordFrame.id) {
    var scopePos = positionInFrame(scanRoot, coordFrame);
    if (!scopePos) return [];
    baseX = scopePos.x;
    baseY = scopePos.y;
    basePath = getParentPath(scanRoot, coordFrame);
  }

  if (scanRoot.children) {
    for (var r = 0; r < scanRoot.children.length; r++) {
      var rootChild = scanRoot.children[r];
      walkUnified(rootChild, 1, baseX + rootChild.x, baseY + rootChild.y, basePath);
    }
  }

  elements.sort(function(a, b) {
    var rowDiff = a.y - b.y;
    if (Math.abs(rowDiff) > 20) return rowDiff;
    return a.x - b.x;
  });

  var deduped = dedupCollectedElements(elements);

  if (sortMode === "reading") {
    return sortElementsReadingOrder(deduped).slice(0, AUTO_NUMBER_LIMIT);
  }
  return prioritizeCandidates(deduped).slice(0, CANDIDATE_LIMIT);
}

function overlayLayerName(rootFrame) {
  return "__overlay__" + rootFrame.id;
}

function markerGroupName(num) {
  return "marker-" + formatMarkerNumber(num);
}

function getExistingMarkerNumbers(overlay) {
  var set = {};
  if (!overlay || !("children" in overlay) || !overlay.children) return set;
  for (var i = 0; i < overlay.children.length; i++) {
    var ch = overlay.children[i];
    if (ch.name && ch.name.indexOf("marker-") === 0) {
      var raw = ch.name.slice(7);
      set[raw] = true;
      var norm = normalizeItemNumber(raw);
      if (norm) set[norm] = true;
    }
  }
  return set;
}

function getMaxExistingNumber(overlay) {
  if (!overlay || !overlay.children) return 0;
  var max = 0;
  for (var i = 0; i < overlay.children.length; i++) {
    var ch = overlay.children[i];
    if (ch.name && ch.name.indexOf("marker-") === 0) {
      var n = parseInt(ch.name.slice(7), 10);
      if (!isNaN(n) && n > max) max = n;
    }
  }
  return max;
}

function getFrameMaxMarkerNumber(rootFrame) {
  return getMaxExistingNumber(findOverlay(rootFrame));
}

function getExistingMarkerNodeIds(overlay) {
  var ids = {};
  if (!overlay || !overlay.children) return ids;
  for (var i = 0; i < overlay.children.length; i++) {
    var ch = overlay.children[i];
    if (ch.name && ch.name.indexOf("marker-") === 0) {
      try {
        var nid = ch.getPluginData("nodeId");
        if (nid) ids[nid] = true;
      } catch (e) {}
    }
  }
  return ids;
}

function countOverlayMarkers(overlay) {
  if (!overlay || !overlay.children) return 0;
  var n = 0;
  for (var i = 0; i < overlay.children.length; i++) {
    if (overlay.children[i].name && overlay.children[i].name.indexOf("marker-") === 0) n++;
  }
  return n;
}

function removeMarkerByNumber(overlay, num) {
  if (!overlay || !overlay.children) return;
  var name = markerGroupName(num);
  for (var i = overlay.children.length - 1; i >= 0; i--) {
    if (overlay.children[i].name === name) overlay.children[i].remove();
  }
}

function storageKeyPlaced(frameId) {
  return "bd-placed-" + frameId;
}

function storageKeySpec(frameId) {
  return "bd-spec-" + frameId;
}

function storageKeyTableRows(frameId) {
  return "bd-table-rows-" + frameId;
}

function storageKeyDefinedItems(frameId) {
  return "bd-defined-items-" + frameId;
}

function buildDefinedIdSet(rows) {
  var set = {};
  for (var i = 0; i < (rows || []).length; i++) {
    var r = rows[i];
    if (r && r.enabled !== false && r.id) set[r.id] = true;
  }
  return set;
}

function normalizeDefinedRows(rows) {
  return sortTableRowsByNo((rows || []).filter(function(r) {
    return r && r.enabled !== false && r.id && r.no;
  }));
}

async function saveDefinedItemsRegistry(frameId, rows) {
  var defined = normalizeDefinedRows(rows);
  await figma.clientStorage.setAsync(storageKeyDefinedItems(frameId), {
    version: 1,
    frameId: frameId,
    savedAt: Date.now(),
    items: defined,
    nodeIds: defined.map(function(r) { return r.id; }),
  });
}

async function loadDefinedItemsRegistry(frameId) {
  var data = await figma.clientStorage.getAsync(storageKeyDefinedItems(frameId));
  if (data && Array.isArray(data.items) && data.items.length) return data.items;
  return null;
}

async function resolveDefinedRowsForFrame(frameId, incomingRows) {
  var defined = normalizeDefinedRows(incomingRows || []);
  if (defined.length) return defined;
  var fromRegistry = await loadDefinedItemsRegistry(frameId);
  if (fromRegistry && fromRegistry.length) return normalizeDefinedRows(fromRegistry);
  var fromTable = await loadTableRows(frameId);
  return normalizeDefinedRows(fromTable);
}

/** @typedef {{ id: string, no: number, element: string, type?: string, x?: number, y?: number, source: string, enabled?: boolean }} TableRow */

function parseTableRowNo(value) {
  var n = parseInt(String(value).replace(/[^\d]/g, ""), 10);
  return isNaN(n) || n < 1 ? 1 : n;
}

function sortTableRowsByNo(rows) {
  return (rows || []).slice().sort(function(a, b) {
    return parseTableRowNo(a.no) - parseTableRowNo(b.no);
  });
}

function getIncrementalStartNumber(rootFrame, preservedRows) {
  var max = getFrameMaxMarkerNumber(rootFrame);
  var rows = preservedRows || [];
  for (var i = 0; i < rows.length; i++) {
    if (rows[i].enabled === false) continue;
    var n = parseTableRowNo(rows[i].no);
    if (n > max) max = n;
  }
  return max;
}

function newTableRowId() {
  return "manual-" + Date.now() + "-" + Math.random().toString(36).slice(2, 7);
}

function elementToTableRow(el, source) {
  var src = source || el.source || "AUTO";
  return {
    id: el.id || newTableRowId(),
    no: parseTableRowNo(el.no != null ? el.no : el.number),
    element: (el.element || el.text || el.label || el.name || "").trim(),
    type: el.type || el.itemType || el.role || undefined,
    x: typeof el.x === "number" ? el.x : undefined,
    y: typeof el.y === "number" ? el.y : undefined,
    centerX: typeof el.centerX === "number" ? el.centerX : undefined,
    centerY: typeof el.centerY === "number" ? el.centerY : undefined,
    source: src === "MANUAL" || src === "LOCKED" ? src : "AUTO",
    enabled: el.enabled !== false,
    confidence: el.confidence,
    aiReason: el.aiReason,
    parentPath: el.parentPath,
    markerOn: el.markerOn,
    name: el.name,
    role: el.role,
    width: el.width,
    height: el.height,
    label: el.label,
  };
}

/** Renderer input: only row.no and row.element are required for drawing labels. */
function tableRowToDrawElement(row) {
  return {
    id: row.id,
    number: row.no,
    no: row.no,
    text: row.element,
    label: row.element,
    name: row.name || row.element,
    type: row.type || "",
    itemType: row.type || "",
    x: row.x,
    y: row.y,
    width: row.width,
    height: row.height,
    centerX: row.centerX,
    centerY: row.centerY,
    parentPath: row.parentPath || "",
    markerOn: row.markerOn || row.element,
    enabled: row.enabled !== false,
    source: row.source || "AUTO",
    confidence: row.confidence,
    aiReason: row.aiReason,
    role: row.role,
  };
}

function tableRowsToDrawElements(rows) {
  return sortTableRowsByNo(rows || []).map(tableRowToDrawElement);
}

function mergePreservedWithAutoPreview(frame, preservedRows, autoElements) {
  var kept = sortTableRowsByNo((preservedRows || []).filter(function(r) {
    return r && r.enabled !== false && r.id && r.no;
  }));
  var keptIds = {};
  for (var i = 0; i < kept.length; i++) keptIds[kept[i].id] = true;

  var keptEls = tableRowsToDrawElements(kept);
  var newEls = [];
  for (var j = 0; j < (autoElements || []).length; j++) {
    var el = autoElements[j];
    if (!el || el.enabled === false) continue;
    if (!el.id || keptIds[el.id]) continue;
    newEls.push(el);
  }

  newEls = sortElementsReadingOrder(newEls);
  var startNo = getIncrementalStartNumber(frame, kept);
  var inc = 0;
  for (var k = 0; k < newEls.length; k++) {
    var ne = newEls[k];
    if (!ne.number || ne.number === "—") continue;
    inc++;
    ne.number = String(startNo + inc);
  }

  var newRows = newEls.map(function(el) { return elementToTableRow(el, "AUTO"); });
  return {
    elements: keptEls.concat(newEls),
    tableRows: sortTableRowsByNo(kept.concat(newRows)),
    keptCount: kept.length,
    newCount: newEls.length,
  };
}

async function loadTableRows(frameId) {
  var data = await figma.clientStorage.getAsync(storageKeyTableRows(frameId));
  return Array.isArray(data) ? data : [];
}

async function saveTableRows(frameId, rows) {
  var sorted = sortTableRowsByNo(rows || []);
  await figma.clientStorage.setAsync(storageKeyTableRows(frameId), sorted);
  await saveDefinedItemsRegistry(frameId, sorted);
}

function storageKeyBusinessContext(frameId) {
  return "bd-biz-context-" + frameId;
}

function normalizeBusinessContext(ctx) {
  if (!ctx || typeof ctx !== "object") return null;
  var out = {
    screenPurpose: String(ctx.screenPurpose || "").trim(),
    businessOverview: String(ctx.businessOverview || "").trim(),
    mainFlow: String(ctx.mainFlow || "").trim(),
    specialRules: String(ctx.specialRules || "").trim(),
  };
  if (!out.screenPurpose && !out.businessOverview && !out.mainFlow && !out.specialRules) return null;
  return out;
}

async function loadBusinessContext(frameId) {
  var data = await figma.clientStorage.getAsync(storageKeyBusinessContext(frameId));
  return normalizeBusinessContext(data);
}

async function saveBusinessContext(frameId, ctx) {
  var normalized = normalizeBusinessContext(ctx);
  if (normalized) {
    await figma.clientStorage.setAsync(storageKeyBusinessContext(frameId), normalized);
  } else {
    await figma.clientStorage.deleteAsync(storageKeyBusinessContext(frameId));
  }
}

function formatBusinessContextForPrompt(ctx) {
  if (!ctx) return "";
  return (
    "--- Business context (confirmed by user — MUST follow when writing specs) ---\n" +
    "Screen Purpose:\n" + (ctx.screenPurpose || "-") + "\n\n" +
    "Business Overview:\n" + (ctx.businessOverview || "-") + "\n\n" +
    "Main Flow:\n" + (ctx.mainFlow || "-") + "\n\n" +
    "Special Rules:\n" + (ctx.specialRules || "-") + "\n\n"
  );
}

async function loadPlacedMarkers(frameId) {
  var data = await figma.clientStorage.getAsync(storageKeyPlaced(frameId));
  return Array.isArray(data) ? data : [];
}

async function savePlacedMarkers(frameId, items) {
  await figma.clientStorage.setAsync(storageKeyPlaced(frameId), items);
}

async function loadSavedSpecDocument(frameId) {
  var data = await figma.clientStorage.getAsync(storageKeySpec(frameId));
  return data && data.sections ? data : null;
}

async function saveSpecDocument(frameId, doc) {
  if (doc && doc.sections) {
    await figma.clientStorage.setAsync(storageKeySpec(frameId), doc);
  }
}

async function clearFrameStorage(frameId) {
  await figma.clientStorage.setAsync(storageKeyPlaced(frameId), []);
  await figma.clientStorage.deleteAsync(storageKeySpec(frameId));
  await figma.clientStorage.deleteAsync(storageKeyTableRows(frameId));
  await figma.clientStorage.deleteAsync(storageKeyDefinedItems(frameId));
  await figma.clientStorage.deleteAsync(storageKeyBusinessContext(frameId));
}

function listMarkersOnCanvas(frame) {
  var overlay = findOverlay(frame);
  if (!overlay || !overlay.children) return [];
  var markers = [];
  for (var i = 0; i < overlay.children.length; i++) {
    var ch = overlay.children[i];
    if (!ch.name || ch.name.indexOf("marker-") !== 0) continue;
    var rawNum = ch.name.slice(7);
    var num = normalizeItemNumber(rawNum) || rawNum;
    var cx = null;
    var cy = null;
    if (ch.children) {
      for (var j = 0; j < ch.children.length; j++) {
        var sub = ch.children[j];
        if (sub.name === "marker-bg" || sub.name === "marker-text-" + rawNum) {
          cx = Math.round(ch.x + sub.x + sub.width / 2);
          cy = Math.round(ch.y + sub.y + sub.height / 2);
          if (sub.name.indexOf("marker-bg") === 0) break;
        }
      }
    }
    markers.push({ number: num, enabled: true, centerX: cx, centerY: cy });
  }
  markers.sort(function(a, b) { return numberSortKey(a.number) - numberSortKey(b.number); });
  return markers;
}

function enrichMarkerFromPosition(frame, marker, rawElements) {
  if (marker.id && marker.text && marker.text !== "—") return marker;
  var raw = rawElements;
  if (!raw) {
    var root = getDrawContext(frame).positionRoot;
    raw = collectElements(root, "reading");
  }
  var best = null;
  var bestDist = Infinity;
  var mx = marker.centerX != null ? marker.centerX : marker.x;
  var my = marker.centerY != null ? marker.centerY : marker.y;
  if (mx == null || my == null) return marker;
  for (var i = 0; i < raw.length; i++) {
    var el = raw[i];
    var d = bboxDistance({ x: mx, y: my, width: 0, height: 0 }, el);
    if (d < bestDist && d <= 100) {
      bestDist = d;
      best = el;
    }
  }
  if (best) {
    marker.id = best.id;
    marker.name = best.name;
    marker.type = best.type;
    marker.text = best.text || best.label || best.name || "—";
    marker.label = best.label || "";
    marker.parentPath = best.parentPath || "";
    marker.itemType = best.role || best.type || "";
    marker.x = best.x;
    marker.y = best.y;
    marker.width = best.width;
    marker.height = best.height;
    marker.markerOn = best.name;
  }
  return marker;
}

async function mergeCanvasMarkersWithStored(frame) {
  var onCanvas = listMarkersOnCanvas(frame);
  var stored = await loadPlacedMarkers(frame.id);
  var onCanvasByNum = {};
  for (var c = 0; c < onCanvas.length; c++) {
    onCanvasByNum[String(onCanvas[c].number)] = onCanvas[c];
  }

  var merged = [];
  var seen = {};
  var rawElements = null;
  function getRawElements() {
    if (!rawElements) {
      rawElements = collectElements(getDrawContext(frame).positionRoot, "reading");
    }
    return rawElements;
  }

  for (var s = 0; s < stored.length; s++) {
    var st = stored[s];
    var key = String(st.number);
    seen[key] = true;
    var onC = onCanvasByNum[key];
    var item = {
      id: st.id || (onC ? "canvas-" + key : st.id),
      number: st.number,
      name: st.name || "",
      type: st.type || "",
      text: st.text || st.label || st.name || "—",
      label: st.label || "",
      itemType: st.itemType || st.role || "",
      role: st.role || "",
      parentPath: st.parentPath || "",
      markerOn: st.markerOn || st.name || "—",
      centerX: onC ? onC.centerX : st.centerX,
      centerY: onC ? onC.centerY : st.centerY,
      x: st.x, y: st.y, width: st.width, height: st.height,
      confidence: st.confidence,
      enabled: !!onC,
    };
    if (!item.id || item.text === "—") enrichMarkerFromPosition(frame, item, getRawElements());
    merged.push(item);
  }

  for (var o = 0; o < onCanvas.length; o++) {
    var oc = onCanvas[o];
    var oKey = String(oc.number);
    if (seen[oKey]) continue;
    var fresh = {
      id: "canvas-" + oKey,
      number: oc.number,
      text: "—",
      name: "",
      type: "",
      parentPath: "",
      markerOn: "—",
      centerX: oc.centerX,
      centerY: oc.centerY,
      enabled: true,
    };
    enrichMarkerFromPosition(frame, fresh, getRawElements());
    merged.push(fresh);
  }

  merged.sort(function(a, b) { return numberSortKey(a.number) - numberSortKey(b.number); });
  return merged;
}

async function persistPlacedMarkersAfterDraw(frame, newItems, options) {
  options = options || {};
  if (options.replace) {
    var replaced = (newItems || []).slice().sort(function(x, y) {
      return numberSortKey(x.number) - numberSortKey(y.number);
    });
    await savePlacedMarkers(frame.id, replaced);
    return replaced;
  }
  var existing = await loadPlacedMarkers(frame.id);
  var byNum = {};
  for (var e = 0; e < existing.length; e++) {
    byNum[String(existing[e].number)] = existing[e];
  }
  for (var n = 0; n < newItems.length; n++) {
    var it = newItems[n];
    byNum[String(it.number)] = Object.assign({}, byNum[String(it.number)] || {}, it, { enabled: true });
  }
  var all = await mergeCanvasMarkersWithStored(frame);
  var mergedByNum = {};
  for (var a = 0; a < all.length; a++) mergedByNum[String(all[a].number)] = all[a];
  for (var key in byNum) {
    if (mergedByNum[key]) {
      mergedByNum[key] = Object.assign({}, mergedByNum[key], byNum[key], { enabled: true });
    }
  }
  var out = [];
  for (var k in mergedByNum) out.push(mergedByNum[k]);
  out.sort(function(x, y) { return numberSortKey(x.number) - numberSortKey(y.number); });
  await savePlacedMarkers(frame.id, out);
  return out;
}

async function updateStoredMarkerEnabled(frameId, element, enabled) {
  var stored = await loadPlacedMarkers(frameId);
  var found = false;
  for (var i = 0; i < stored.length; i++) {
    if (String(stored[i].number) === String(element.number)) {
      stored[i].enabled = enabled;
      stored[i] = Object.assign({}, stored[i], element, { enabled: enabled });
      found = true;
      break;
    }
  }
  if (!found) {
    stored.push(Object.assign({}, element, { enabled: enabled }));
  }
  stored.sort(function(a, b) { return numberSortKey(a.number) - numberSortKey(b.number); });
  await savePlacedMarkers(frameId, stored);
  return stored;
}

function normalizeOverlayPlacement(overlay, ctx) {
  var parent = ctx.root;
  var expectedName = overlayLayerName(parent);
  if (overlay.parent !== parent) {
    placeOverlayFrame(overlay, parent, 0, 0, parent.width, parent.height);
  } else {
    applyAbsolutePosition(overlay, parent);
    overlay.resize(parent.width, parent.height);
    overlay.x = 0;
    overlay.y = 0;
    bringToFront(overlay);
  }
  if (overlay.name !== expectedName) overlay.name = expectedName;
}

function getOrCreateOverlay(ctx) {
  var existing = findOverlay(ctx.root);
  if (existing) {
    normalizeOverlayPlacement(existing, ctx);
    return existing;
  }
  var overlay = figma.createFrame();
  overlay.name = overlayLayerName(ctx.root);
  overlay.fills = [];
  overlay.clipsContent = false;
  placeOverlayFrame(overlay, ctx.root, 0, 0, ctx.root.width, ctx.root.height);
  return overlay;
}

function findOverlay(rootFrame) {
  if (!rootFrame) return null;
  var name = overlayLayerName(rootFrame);
  if (rootFrame.findOne) {
    var found = rootFrame.findOne(function(n) {
      return n.name === name;
    });
    if (found) return found;
    // Fallback: overlay giu id frame cu sau khi duplicate / doi cau truc file
    found = rootFrame.findOne(function(n) {
      return n.name && n.name.indexOf("__overlay__") === 0;
    });
    if (found) return found;
  }
  var ctx = getDrawContext(rootFrame);
  if (ctx.coord.id !== rootFrame.id && ctx.coord.findOne) {
    var onCoord = ctx.coord.findOne(function(n) {
      return n.name === name;
    });
    if (onCoord) return onCoord;
    return ctx.coord.findOne(function(n) {
      return n.name && n.name.indexOf("__overlay__") === 0;
    });
  }
  return null;
}

function getOverlayMarkerCount(rootFrame) {
  var overlay = findOverlay(rootFrame);
  return overlay ? countOverlayMarkers(overlay) : 0;
}

function removeOverlayLayers(rootFrame) {
  if (!rootFrame) return 0;
  var overlay = findOverlay(rootFrame);
  var markerCount = overlay ? countOverlayMarkers(overlay) : 0;
  var name = overlayLayerName(rootFrame);
  var ctx = getDrawContext(rootFrame);
  var parents = [rootFrame];
  if (ctx.coord.id !== rootFrame.id) parents.push(ctx.coord);

  for (var p = 0; p < parents.length; p++) {
    var parent = parents[p];
    if (!("children" in parent) || !parent.children) continue;
    for (var i = parent.children.length - 1; i >= 0; i--) {
      if (parent.children[i].name === name) parent.children[i].remove();
    }
  }
  return markerCount;
}

async function findNodeForElement(targetFrame, nodeId) {
  if (!nodeId || nodeId.indexOf("manual-") === 0) return null;
  var node = null;
  try {
    node = await figma.getNodeByIdAsync(nodeId);
  } catch (e) {
    node = null;
  }
  if (node && !isDescendantOf(node, targetFrame)) node = null;
  if (!node) node = findNodeInFrame(targetFrame, nodeId);
  return node;
}

async function resolveElementsForDraw(rootFrame, coordFrame, elements, markerOpts) {
  markerOpts = markerOpts || { position: "auto", radius: 12 };
  var positionRoot = rootFrame;
  var rawForMatch = collectTextElementsForMatch(positionRoot);
  if (!rawForMatch.length) rawForMatch = collectElements(positionRoot, "reading");
  var textIndex = buildTextMatchIndex(rawForMatch);
  var usedMatchIds = {};
  var lastTextMatchY = -9999;
  for (var u = 0; u < elements.length; u++) {
    var uid = elements[u].id;
    if (uid && String(uid).indexOf("manual-") !== 0) usedMatchIds[uid] = true;
  }

  var resolved = [];
  for (var i = 0; i < elements.length; i++) {
    var el = elements[i];
    var coords = null;
    var markerOn = el.markerOn || el.name;
    var manualRow = isManualDrawElement(el);

    var node = manualRow ? null : await findNodeForElement(rootFrame, el.id);
    if (!node) {
      var labelText = (el.text || el.label || el.name || "").trim();
      if (labelText) {
        var rawMatch = findRawElementByLabel(labelText, rawForMatch, positionRoot.width, {
          used: usedMatchIds,
          byText: textIndex,
          lastPickY: lastTextMatchY,
        });
        if (rawMatch) {
          usedMatchIds[rawMatch.id] = true;
          lastTextMatchY = rawMatch.y;
          el = Object.assign({}, el, {
            id: rawMatch.id,
            name: rawMatch.name,
            type: rawMatch.type,
            text: rawMatch.text || el.text || labelText,
            label: rawMatch.label || el.label || "",
            parentPath: rawMatch.parentPath || el.parentPath || "",
            x: rawMatch.x,
            y: rawMatch.y,
            width: rawMatch.width,
            height: rawMatch.height,
            centerX: rawMatch.centerX,
            centerY: rawMatch.centerY,
            markerOn: rawMatch.name,
          });
          node = await findNodeForElement(rootFrame, rawMatch.id);
        }
      }
    }

    if (node) {
      var mp = markerPositionForNode(node, positionRoot, markerOpts);
      if (isPlausibleMarker(mp, el, positionRoot)) {
        var bc = markerBadgeCenter(mp);
        coords = {
          centerX: bc.centerX,
          centerY: bc.centerY,
          anchorX: mp.anchorX,
          anchorY: mp.anchorY,
          targetRect: mp.targetRect,
          lineStyle: mp.lineStyle || "horizontal",
          drawBox: false,
        };
        markerOn = node.name;
      }
    }

    if (!coords && hasValidStoredCoords(el) && !(manualRow && (el.text || el.label))) {
      var storedSpec = markerCoordsFromElement(el, positionRoot.width, markerOpts);
      if (isPlausibleMarker(storedSpec, el, positionRoot)) {
        var bc2 = markerBadgeCenter(storedSpec);
        coords = {
          centerX: bc2.centerX,
          centerY: bc2.centerY,
          anchorX: storedSpec.anchorX,
          anchorY: storedSpec.anchorY,
          targetRect: storedSpec.targetRect,
          lineStyle: storedSpec.lineStyle || "horizontal",
          drawBox: false,
        };
      }
    }

    if (!coords) {
      var col = i % 3;
      var row = Math.floor(i / 3);
      coords = {
        centerX: Math.min(positionRoot.width - 24, 28 + col * 72),
        centerY: Math.min(positionRoot.height - 24, 80 + row * 56),
        anchorX: Math.min(positionRoot.width - 24, 28 + col * 72),
        anchorY: Math.min(positionRoot.height - 24, 80 + row * 56),
        lineStyle: "horizontal",
        drawBox: false,
      };
    }

    resolved.push({
      id: el.id,
      name: el.name,
      type: el.type,
      text: el.text || "",
      parentPath: el.parentPath || "",
      number: el.number,
      x: el.x,
      y: el.y,
      width: el.width,
      height: el.height,
      centerX: coords.centerX,
      centerY: coords.centerY,
      anchorX: coords.anchorX,
      anchorY: coords.anchorY,
      targetRect: coords.targetRect || null,
      lineStyle: coords.lineStyle || "horizontal",
      drawBox: false,
      markerOn: markerOn,
    });
  }
  return resolved;
}

function placeOverlayFrame(overlay, parent, x, y, w, h) {
  if (overlay.parent !== parent) parent.appendChild(overlay);
  applyAbsolutePosition(overlay, parent);
  overlay.resize(w, h);
  overlay.x = x;
  overlay.y = y;
  bringToFront(overlay);
}

function createBdMarkerGroup(overlay, num, el, radius, fontName, fontSize) {
  var bx = el.centerX;
  var by = el.centerY;
  var tr = el.targetRect || {
    x: (typeof el.x === "number" ? el.x : bx - 20),
    y: (typeof el.y === "number" ? el.y : by - 10),
    width: el.width || 40,
    height: el.height || 24,
  };
  var ax = typeof el.anchorX === "number" ? el.anchorX : tr.x;
  var ay = typeof el.anchorY === "number" ? el.anchorY : tr.y + tr.height / 2;
  var dotR = 2.5;
  var pad = 3;
  var minX = Math.min(bx - radius, ax - dotR) - pad;
  var minY = Math.min(by - radius, ay - dotR) - pad;
  var maxX = Math.max(bx + radius, ax + dotR) + pad;
  var maxY = Math.max(by + radius, ay + dotR) + pad;

  var group = figma.createFrame();
  group.name = "marker-" + formatMarkerNumber(num);
  group.resize(Math.max(1, maxX - minX), Math.max(1, maxY - minY));
  group.x = minX;
  group.y = minY;
  group.fills = [];
  group.clipsContent = false;

  var line = figma.createLine();
  line.name = "marker-line";
  line.strokes = [BD_STROKE_RED];
  line.strokeWeight = 1.5;
  if (el.lineStyle === "horizontal") {
    var fromX = ax <= bx ? bx - radius : bx + radius;
    line.x = Math.min(fromX, ax) - minX;
    line.y = by - minY;
    line.resize(Math.max(0, Math.abs(ax - fromX)), 0);
  } else {
    var fromY = ay <= by ? by - radius : by + radius;
    line.x = bx - minX;
    line.y = Math.min(fromY, ay) - minY;
    line.resize(0, Math.max(0, Math.abs(ay - fromY)));
  }
  group.appendChild(line);

  var dot = figma.createEllipse();
  dot.name = "marker-dot";
  dot.resize(dotR * 2, dotR * 2);
  dot.x = ax - minX - dotR;
  dot.y = ay - minY - dotR;
  dot.fills = [BD_FILL_RED];
  dot.strokes = [];
  group.appendChild(dot);

  var rbx = bx - minX;
  var rby = by - minY;
  var markerSize = radius * 2;
  var circle = figma.createEllipse();
  circle.name = "marker-bg";
  circle.resize(markerSize, markerSize);
  circle.x = rbx - radius;
  circle.y = rby - radius;
  circle.fills = [BD_FILL_RED];
  group.appendChild(circle);

  var numLabel = formatMarkerNumber(num);
  var labelSize = numLabel.length >= 6 ? Math.max(7, Math.round(fontSize * 0.48)) :
    numLabel.length >= 5 ? Math.max(7, Math.round(fontSize * 0.55)) :
    numLabel.length >= 4 ? Math.max(8, Math.round(fontSize * 0.6)) :
    numLabel.length >= 3 ? Math.max(9, Math.round(fontSize * 0.72)) : fontSize;
  var text = figma.createText();
  text.fontName = fontName;
  text.fontSize = labelSize;
  text.characters = numLabel;
  text.fills = [{ type: "SOLID", color: { r: 1, g: 1, b: 1 } }];
  text.textAlignHorizontal = "CENTER";
  text.textAlignVertical = "CENTER";
  text.resize(markerSize, markerSize);
  text.x = rbx - radius;
  text.y = rby - radius;
  text.name = "marker-text-" + numLabel;
  group.appendChild(text);

  overlay.appendChild(group);
  applyAbsolutePosition(group, overlay);
  if (el && el.id) {
    try { group.setPluginData("nodeId", el.id); } catch (e) {}
  }
}

async function drawOverlay(rootFrame, elements, options) {
  options = options || {};
  var appendMode = options.append !== false;
  var incrementalMode = options.incremental === true;
  var markerOpts = options.markerOpts || { position: "auto", radius: 12 };

  var ctx = getDrawContext(rootFrame);
  var resolved = await resolveElementsForDraw(ctx.root, ctx.coord, elements, markerOpts);

  if (!appendMode) {
    removeOverlayLayers(ctx.root);
  }

  var overlay = getOrCreateOverlay(ctx);
  var existingNumbers = getExistingMarkerNumbers(overlay);

  var existingNodeIds = {};
  if (incrementalMode) {
    existingNodeIds = getExistingMarkerNodeIds(overlay);
  }

  var RADIUS = markerRadiusForFrame(ctx.coord.width, markerOpts.radius);
  var FONT_SIZE = Math.max(7, Math.round(RADIUS * 0.72));
  var fontName = { family: "Inter", style: "Bold" };
  try {
    await figma.loadFontAsync(fontName);
  } catch (fontErr) {
    fontName = { family: "Roboto", style: "Bold" };
    await figma.loadFontAsync(fontName);
  }

  var added = [];
  var skipped = 0;
  for (var i = 0; i < resolved.length; i++) {
    var el = resolved[i];

    if (incrementalMode) {
      // Skip elements already placed on this frame's overlay
      if (el.id && existingNodeIds[el.id]) {
        skipped++;
        continue;
      }
      // el.number already has the correct offset applied at preview time
      var numKey = formatMarkerNumber(el.number || (i + 1));
      if (existingNumbers[numKey]) {
        skipped++;
        continue;
      }
      createBdMarkerGroup(overlay, el.number || (i + 1), el, RADIUS, fontName, FONT_SIZE);
      existingNumbers[numKey] = true;
      added.push(el);
    } else {
      var numKey2 = formatMarkerNumber(el.number || (i + 1));
      if (existingNumbers[numKey2]) {
        skipped++;
        continue;
      }
      createBdMarkerGroup(overlay, el.number || (i + 1), el, RADIUS, fontName, FONT_SIZE);
      existingNumbers[numKey2] = true;
      added.push(el);
    }
  }

  bringToFront(overlay);
  return {
    added: added,
    skipped: skipped,
    totalOnCanvas: countOverlayMarkers(overlay),
    allResolved: resolved,
  };
}

function isExportableFrame(node) {
  return node && (node.type === "FRAME" || node.type === "COMPONENT" || node.type === "INSTANCE");
}

figma.ui.onmessage = async function(msg) {

  if (msg.type === "router-ai-response") {
    var waiter = _routerCallWaiters[msg.id];
    if (!waiter) return;
    delete _routerCallWaiters[msg.id];
    if (msg.error) waiter.reject(new Error(msg.error));
    else waiter.resolve(msg.text || "");
    return;
  }

  if (msg.type === "save-api-key") {
    await figma.clientStorage.setAsync("bd-router-endpoint", normalizeRouterEndpoint(msg.endpoint));
    return;
  }

  if (msg.type === "load-api-key") {
    var endpoint = await figma.clientStorage.getAsync("bd-router-endpoint");
    figma.ui.postMessage({
      type: "api-key-loaded",
      endpoint: endpoint || DEFAULT_ROUTER_ENDPOINT,
      model: ROUTER_MODEL,
    });
    return;
  }

  if (msg.type === "get-selection") {
    try {
      var selResult = resolveSelectionFromSel(figma.currentPage.selection);
      var markerCount = 0;
      var canvasMarkers = [];
      var savedSpecDocument = null;
      var savedTableRows = [];
      var savedBusinessContext = null;

      var selFrame = resolveSelectedFrameNodeSync();
      if (!selFrame && selResult.frames.length) {
        selFrame = await resolveFrameNodeQuick(selResult.frames[0].id);
      }

      if (selFrame) {
        savedTableRows = await loadTableRows(selFrame.id);
        savedBusinessContext = await loadBusinessContext(selFrame.id);
        canvasMarkers = await mergeCanvasMarkersWithStored(selFrame);
        markerCount = getOverlayMarkerCount(selFrame);
        if (!markerCount && canvasMarkers.length) {
          markerCount = canvasMarkers.filter(function(m) { return m.enabled !== false; }).length;
        }
        if (!savedTableRows.length && canvasMarkers.length) {
          savedTableRows = sortTableRowsByNo(canvasMarkers.map(function(el) {
            return elementToTableRow(el, el.source || "AUTO");
          }));
          await saveTableRows(selFrame.id, savedTableRows);
        }
        if (canvasMarkers.length > 0 || markerCount > 0) {
          savedSpecDocument = await loadSavedSpecDocument(selFrame.id);
        }
      }

      figma.ui.postMessage({
        type: "selection",
        frames: selResult.frames,
        hint: selResult.hint || "",
        markerCount: markerCount,
        canvasMarkers: canvasMarkers,
        savedSpecDocument: savedSpecDocument,
        savedTableRows: savedTableRows,
        savedBusinessContext: savedBusinessContext,
      });
    } catch (err) {
      figma.ui.postMessage({
        type: "error",
        message: (err && err.message) || String(err),
      });
    }
    return;
  }

  if (msg.type === "run-preview") {
    try {
      var routerEndpoint = normalizeRouterEndpoint(msg.routerEndpoint);
      var previewMode = (msg.mode || "prompt").toLowerCase();
      var userPrompt = (msg.userPrompt || "").trim();

      var frame = await resolveExportableFrameById(msg.frameId);
      if (!frame) throw new Error("Frame khong tim thay (co the nam trong Section — chon lai Frame man hinh va Lam moi).");
      if (!isExportableFrame(frame)) throw new Error("Chi ho tro Frame / Component / Instance.");

      var drawCtx = getDrawContext(frame);
      var markerOpts = markerOptsFromMsg(msg);
      var resolved;
      var rawElements = [];
      var collectOpts = getCollectOptions(drawCtx.positionRoot, {
        useScope: previewMode !== "auto",
      });

      var preservedIncoming = (msg.preservedRows || []).filter(function(r) {
        return r && r.enabled !== false && r.id && r.no;
      });

      if (previewMode === "auto") {
        resolved = await runAutoAiNumberingPipeline(frame, routerEndpoint, msg.language, {
          definedRows: preservedIncoming,
        });
        rawElements = resolved.rawElements || collectElements(drawCtx.positionRoot, "reading", collectOpts || undefined);
        if ((!resolved.selectedElements || !resolved.selectedElements.length) && !preservedIncoming.length) {
          throw new Error("AI khong chon item nao de danh so.");
        }
      } else {
        if (!userPrompt) throw new Error("Hay nhap mo ta yeu cau danh so.");

        postProgress("scan", collectOpts
          ? ('Quet vung "' + collectOpts.scopeLabel + '"...')
          : "Quet frame...");
        rawElements = collectElements(drawCtx.positionRoot, null, collectOpts || undefined);
        if (!rawElements.length) throw new Error("Khong tim thay element trong frame.");
        var textForMatch = collectTextElementsForMatch(drawCtx.positionRoot, rawElements);
        if (!textForMatch.length) throw new Error("Khong tim thay text trong frame.");

        var prevEls = msg.previousElements || [];
        var split = splitPromptByExistingElements(userPrompt, prevEls);

        if (!split.hasNew && split.kept.length > 0) {
          // Toan bo item da duoc nhan dien truoc do — bo qua AI call
          postProgress("match", "Giu lai " + split.kept.length + " item da nhan dien (khong can goi AI).");
          resolved = { elements: split.kept, method: "Cache (giu lai tu lan truoc)" };
        } else if (split.hasNew && split.kept.length > 0) {
          // Chi co mot so item moi — chi goi AI cho phan moi
          postProgress("match", "Giu " + split.kept.length + " item cu, tim " + split.newPrompt.split("\n").length + " item moi...");
          var newResolved = await resolveElementsFromPrompt(
            routerEndpoint, frame.name, split.newPrompt, rawElements, msg.language,
            drawCtx.positionRoot.width, textForMatch
          );
          resolved = {
            elements: split.kept.concat(newResolved.elements || []),
            method: newResolved.method + " (+" + split.kept.length + " item giu lai)",
          };
        } else {
          // Khong co item cu hoac prompt khong co danh so — goi AI cho toan bo
          postProgress("match", "Tim theo mo ta (" + textForMatch.length + " text labels)...");
          resolved = await resolveElementsFromPrompt(
            routerEndpoint, frame.name, userPrompt, rawElements, msg.language,
            drawCtx.positionRoot.width, textForMatch
          );
        }
        if (!resolved.elements.length) throw new Error("Khong co element phu hop. Kiem tra lai text trong prompt.");
      }

      postProgress("position", "Tinh vi tri tu Figma...");
      var selectedForPreview = resolved.selectedElements ||
        resolved.elements.filter(function(el) { return el.enabled !== false; });
      var preview = await buildPreviewElements(frame, selectedForPreview, markerOpts);
      var previewById = {};
      for (var pi = 0; pi < preview.length; pi++) previewById[preview[pi].id] = preview[pi];

      var elementsOut = previewMode === "auto" ? (resolved.selectedElements || []) : preview;
      if (previewMode === "auto") {
        elementsOut = (resolved.selectedElements || []).map(function(el) {
          var p = previewById[el.id];
          if (!p) return el;
          return {
            id: el.id,
            number: el.number,
            name: el.name,
            type: el.type,
            text: el.text || "",
            parentPath: el.parentPath || "",
            x: el.x,
            y: el.y,
            width: el.width,
            height: el.height,
            centerX: p.centerX,
            centerY: p.centerY,
            markerOn: p.markerOn,
            enabled: el.enabled,
            itemType: el.itemType,
            confidence: el.confidence,
            aiReason: el.aiReason,
            role: el.role,
            label: el.label,
          };
        });
      }

      // Giu so da danh + bo sung item moi (Auto AI quet lai)
      var mergeResult = mergePreservedWithAutoPreview(frame, preservedIncoming, elementsOut);
      elementsOut = mergeResult.elements;
      var mergedTableRows = mergeResult.tableRows;
      if (mergeResult.keptCount > 0) {
        resolved.method = (resolved.method || "Auto AI") +
          " (giu " + mergeResult.keptCount + " so, +" + mergeResult.newCount + " moi)";
      }

      var numberedForSpec = elementsOut.filter(function(el) {
        return el.enabled !== false && el.number && el.number !== "—";
      });

      figma.ui.postMessage({
        type: "preview-ready",
        frameId: msg.frameId,
        frameName: frame.name,
        coordFrameName: drawCtx.coord.name,
        matchMethod: resolved.method,
        candidateCount: resolved.candidateCount != null ? resolved.candidateCount : rawElements.length,
        elements: elementsOut,
        tableRows: mergedTableRows,
        numberedItems: numberedForSpec,
        markerPosition: markerOpts.position,
        markerSize: markerOpts.radius,
        mode: previewMode,
        structuralCount: resolved.structuralCount,
        previewRows: resolved.previewRows || null,
      });
    } catch (err) {
      var errMsg = err.message || String(err);
      figma.notify(errMsg, { error: true });
      figma.ui.postMessage({ type: "error", message: errMsg });
    }
  }

  if (msg.type === "save-table-rows") {
    try {
      if (!msg.frameId) throw new Error("Chua chon Frame.");
      var rowsToSave = sortTableRowsByNo(msg.tableRows || []);
      await saveTableRows(msg.frameId, rowsToSave);
      figma.ui.postMessage({
        type: "table-rows-saved",
        frameId: msg.frameId,
        count: rowsToSave.length,
        tableRows: rowsToSave,
      });
      figma.notify("Da luu " + rowsToSave.length + " dong bang.");
    } catch (saveRowsErr) {
      var saveRowsMsg = saveRowsErr.message || String(saveRowsErr);
      figma.notify(saveRowsMsg, { error: true });
      figma.ui.postMessage({ type: "error", message: saveRowsMsg });
    }
    return;
  }

  if (msg.type === "run-confirm") {
    try {
      var frame2 = await resolveExportableFrameById(msg.frameId);
      if (!frame2) throw new Error("Frame khong tim thay (co the nam trong Section — chon lai Frame man hinh va Lam moi).");
      var finalElements = msg.tableRows && msg.tableRows.length
        ? tableRowsToDrawElements(msg.tableRows).filter(function(el) { return el.enabled !== false; })
        : (msg.elements || []).filter(function(el) {
          return el.enabled !== false;
        });
      if (!finalElements.length) throw new Error("Khong co element de ve (chon it nhat 1 item trong preview).");

      postProgress("draw", "Cap nhat " + finalElements.length + " so theo bang...");
      var drawMarkerOpts = markerOptsFromMsg(msg);
      // Sync mode: xoa marker cu va ve lai toan bo theo bang (sua/xoa/so lai deu duoc cap nhat)
      var drawResult = await drawOverlay(frame2, finalElements, {
        append: false,
        incremental: false,
        markerOpts: drawMarkerOpts,
      });
      var placed = drawResult.added;
      if (!placed.length) {
        throw new Error("Khong ve duoc so nao. Kiem tra preview co element khop khong.");
      }

      var placedById = {};
      for (var pi = 0; pi < placed.length; pi++) placedById[placed[pi].id] = placed[pi];

      var finalById = {};
      var finalByNum = {};
      for (var fi = 0; fi < finalElements.length; fi++) {
        finalById[finalElements[fi].id] = finalElements[fi];
        finalByNum[String(finalElements[fi].number)] = finalElements[fi];
      }
      var resultEls = [];
      for (var ri = 0; ri < finalElements.length; ri++) {
        var orig = finalElements[ri];
        var el = placedById[orig.id];
        if (!el) continue;
        resultEls.push({
          id: el.id,
          number: orig.number,
          name: el.name,
          type: el.type,
          text: orig.text || el.text || "",
          label: orig.label || "",
          itemType: orig.itemType || orig.role || el.type || "",
          role: orig.role || "",
          aiName: el.text || el.name,
          parentPath: el.parentPath || orig.parentPath || "",
          x: el.x, y: el.y, width: el.width, height: el.height,
          confidence: orig.confidence,
          aiReason: orig.aiReason,
          centerX: typeof el.centerX === "number" && !isNaN(el.centerX) ? Math.round(el.centerX) : null,
          centerY: typeof el.centerY === "number" && !isNaN(el.centerY) ? Math.round(el.centerY) : null,
          markerOn: el.markerOn || el.name,
          enabled: true,
        });
      }

      var summaryText = "Da cap nhat " + resultEls.length + " so theo bang (tong " +
        drawResult.totalOnCanvas + " so tren canvas).";

      var allPlaced = await persistPlacedMarkersAfterDraw(frame2, resultEls, { replace: true });

      if (msg.tableRows && msg.tableRows.length) {
        await saveTableRows(msg.frameId, msg.tableRows);
      }

      figma.ui.postMessage({
        type: "run-complete",
        frameName: frame2.name,
        screenName: frame2.name,
        resultEls: resultEls,
        numberedItems: allPlaced,
        canvasMarkers: allPlaced,
        matchMethod: msg.matchMethod || "",
        selectedElements: resultEls,
        summary: summaryText + " — Buoc tiep: 「AI spec draft」 de tao spec.",
        summaryType: "ok",
        addedCount: placed.length,
        skippedCount: drawResult.skipped,
        totalOnCanvas: drawResult.totalOnCanvas,
      });
      figma.notify(summaryText);
    } catch (err) {
      var errMsg2 = err.message || String(err);
      figma.notify(errMsg2, { error: true });
      figma.ui.postMessage({ type: "error", message: errMsg2 });
    }
  }

  if (msg.type === "generate-spec") {
    try {
      var specResult = await runGenerateSpec(msg);
      await saveSpecDocument(msg.frameId, specResult.specDocument);
      figma.ui.postMessage({
        type: "generate-spec-result",
        specDocument: specResult.specDocument,
        specRows: specResult.specRows,
        frameName: specResult.frameName,
        screenTitle: specResult.screenTitle,
        method: specResult.method,
        warning: specResult.warning || "",
        itemCount: specResult.itemCount,
      });
      figma.notify("Da tao " + specResult.specRows.length + " dong spec draft.");
    } catch (specGenErr) {
      var specGenMsg = specGenErr.message || String(specGenErr);
      figma.notify(specGenMsg, { error: true });
      figma.ui.postMessage({ type: "generate-spec-error", message: specGenMsg });
    }
    return;
  }

  if (msg.type === "export-excel-notify") {
    var notifyMsg = msg.message || "";
    if (notifyMsg) figma.notify(notifyMsg, msg.error ? { error: true } : undefined);
    return;
  }

  if (msg.type === "export-frame-png") {
    try {
      if (!msg.frameId) throw new Error("Chua chon Frame.");
      var frameExp = await resolveExportableFrameById(msg.frameId);
      if (!frameExp) throw new Error("Frame khong tim thay.");
      postProgress("export", "Export anh frame co badge...");
      var pngResult = await exportFrameWithMarkersPng(frameExp);
      figma.ui.postMessage({
        type: "export-frame-png-result",
        imageBase64: pngResult.base64,
        width: pngResult.width,
        height: pngResult.height,
        scale: pngResult.scale,
        frameName: frameExp.name,
        frameUrl: buildFigmaFrameUrl(frameExp.id),
      });
    } catch (pngErr) {
      var pngMsg = pngErr.message || String(pngErr);
      figma.notify(pngMsg, { error: true });
      figma.ui.postMessage({ type: "export-frame-png-error", message: pngMsg });
    }
    return;
  }

  if (msg.type === "remove-overlay") {
    try {
      if (!msg.frameId) throw new Error("Chua chon Frame. Chon Frame man hinh roi bam Xoa marker.");
      var frameForRemove = await resolveExportableFrameById(msg.frameId);
      if (!frameForRemove) {
        throw new Error("Frame khong tim thay. Bam Lam moi selection.");
      }
      var removed = removeOverlayLayers(frameForRemove);
      await clearFrameStorage(frameForRemove.id);
      var note = removed > 0
        ? "Da xoa " + removed + " marker tren \"" + frameForRemove.name + "\"."
        : "Khong co marker tren frame \"" + frameForRemove.name + "\".";
      figma.notify(note);
      figma.ui.postMessage({
        type: "overlay-removed",
        markerCount: 0,
        removed: removed,
        message: note,
        canvasMarkers: [],
      });
    } catch (remErr) {
      var remMsg = remErr.message || String(remErr);
      figma.notify(remMsg, { error: true });
      figma.ui.postMessage({ type: "error", message: remMsg });
    }
  }

  if (msg.type === "toggle-marker-canvas") {
    try {
      if (!msg.frameId) throw new Error("Chua chon Frame.");
      var frame = await resolveExportableFrameById(msg.frameId);
      if (!frame) throw new Error("Frame khong tim thay.");

      var ctx = getDrawContext(frame);
      var overlay = findOverlay(frame);

      if (msg.enabled === false) {
        if (overlay) removeMarkerByNumber(overlay, msg.element.number);
        await updateStoredMarkerEnabled(msg.frameId, msg.element, false);
        figma.notify("Da xoa so " + msg.element.number + " tren canvas.");
      } else {
        var drawMarkerOpts = {
          position: msg.markerPosition || "auto",
          radius: msg.markerSize || 12,
        };
        await drawOverlay(frame, [msg.element], {
          append: true,
          markerOpts: drawMarkerOpts,
        });
        await updateStoredMarkerEnabled(msg.frameId, msg.element, true);
        figma.notify("Da ve lai so " + msg.element.number + ".");
      }

      var markerCount = getOverlayMarkerCount(frame);
      var canvasMarkers = markerCount > 0
        ? await mergeCanvasMarkersWithStored(frame)
        : await loadPlacedMarkers(frame.id);
      figma.ui.postMessage({
        type: "marker-count-update",
        markerCount: markerCount,
        canvasMarkers: canvasMarkers,
      });
    } catch (err) {
      var errMsg = err.message || String(err);
      figma.notify(errMsg, { error: true });
      figma.ui.postMessage({ type: "error", message: errMsg });
    }
    return;
  }

  if (msg.type === "close") { figma.closePlugin(); }
};
